  if (path === "/assets/hb-favicon-v33.png") return assetResponse(HB_FAVICON_B64, HB_APP_ICON_MIME);
  if (path === "/assets/hb-app-icon-512.png") return assetResponse(HB_APP_ICON_512_B64, HB_APP_ICON_MIME);
  if (path === "/assets/hb-app-icon-192.png") return assetResponse(HB_APP_ICON_192_B64, HB_APP_ICON_MIME);
  if (path === "/assets/hb-favicon.png") return assetResponse(HB_FAVICON_B64, HB_APP_ICON_MIME);
  if (path === "/apple-touch-icon.png") return assetResponse(HB_APP_ICON_512_B64, HB_APP_ICON_MIME);
  if (path === "/site.webmanifest") return siteManifest();
  if (path === "/site-v33.webmanifest") return siteManifest();
  if (path === "/assets/admin-icon.png") return assetResponse(HB_APP_ICON_512_B64, HB_APP_ICON_MIME);
  if (path === "/assets/centriqpay-banner-dark.webp") return assetResponse(CENTRIQ_BANNER_DARK_B64, CENTRIQ_MIME);
  if (path === "/assets/centriqpay-banner-light.webp") return assetResponse(CENTRIQ_BANNER_LIGHT_B64, CENTRIQ_MIME);
  if (path === "/assets/centriqpay-icon.webp") return assetResponse(CENTRIQ_ICON_B64, CENTRIQ_MIME);
  if (path === "/assets/centriqpay-logo.webp") return assetResponse(CENTRIQ_LOGO_B64, CENTRIQ_MIME);
  if (path === "/assets/mockup-home.webp") return assetResponse(MOCKUP_HOME_B64, MOCKUP_MIME);
  if (path === "/assets/mockup-pos.webp") return assetResponse(MOCKUP_POS_B64, MOCKUP_MIME);
  if (path === "/assets/mockup-security.webp") return assetResponse(MOCKUP_SECURITY_B64, MOCKUP_MIME);
  if (path === "/assets/mockup-merchant.webp") return assetResponse(MOCKUP_MERCHANT_B64, MOCKUP_MIME);
  if (path === "/assets/merchant-body.webp") return assetResponse(MERCHANT_BODY_B64, MOCKUP_MIME);
  if (path === "/assets/pos-body.webp") return assetResponse(POS_BODY_B64, MOCKUP_MIME);
  if (path === "/assets/security-body.webp") return assetResponse(SECURITY_BODY_B64, MOCKUP_MIME);
  if (path === "/assets/security-body-v20.webp") return assetResponse(SECURITY_BODY_B64, MOCKUP_MIME);
  if (path === "/assets/security-body-v21.webp") return assetResponse(SECURITY_BODY_B64, MOCKUP_MIME);
  if (path === "/assets/security-top-v38.webp") return assetResponse(SECURITY_TOP_V38_B64, MOCKUP_MIME);
  if (path === "/assets/v75-merchant-visual.webp") return assetResponse(V75_MERCHANT_VISUAL_B64, MOCKUP_MIME);
  if (path === "/assets/centriqpay-logo-mark.webp") return assetResponse(CENTRIQPAY_LOGO_MARK_B64, MOCKUP_MIME);
  if (path === "/assets/v75-pos-visual.webp") return assetResponse(V75_POS_VISUAL_B64, MOCKUP_MIME);
  if (path === "/assets/v75-security-visual.webp") return assetResponse(V75_SECURITY_VISUAL_B64, MOCKUP_MIME);
  if (path === "/assets/v75-lts-recorders.webp") return assetResponse(V75_LTS_RECORDERS_B64, MOCKUP_MIME);
  if (path === "/assets/v75-lts-cameras.webp") return assetResponse(V75_LTS_CAMERAS_B64, MOCKUP_MIME);
  if (path === "/assets/mobile-merchant-graphic.webp") return assetResponse(MOBILE_MERCHANT_GRAPHIC_B64, MOCKUP_MIME);
  if (path === "/assets/mobile-pos-graphic.webp") return assetResponse(MOBILE_POS_GRAPHIC_B64, MOCKUP_MIME);
  if (path === "/assets/mobile-security-graphic.webp") return assetResponse(MOBILE_SECURITY_GRAPHIC_B64, MOCKUP_MIME);
