  if (path === "/assets/v72-home-hero-visual.webp") return assetResponse(V72_HERO_VISUAL_B64, MOCKUP_MIME);
  if (path === "/assets/v72-card-merchant.webp") return assetResponse(V72_CARD_MERCHANT_B64, MOCKUP_MIME);
  if (path === "/assets/v72-card-pos.webp") return assetResponse(V72_CARD_POS_B64, MOCKUP_MIME);
  if (path === "/assets/v72-card-security.webp") return assetResponse(V72_CARD_SECURITY_B64, MOCKUP_MIME);
  if (path === "/assets/v72-industries.webp") return assetResponse(V72_INDUSTRIES_B64, MOCKUP_MIME);
  if (path === "/assets/merchant-banner-v56.webp") return assetResponse(MERCHANT_BANNER_V56_B64, MOCKUP_MIME);
  if (path === "/assets/pos-banner-v56.webp") return assetResponse(POS_BANNER_V56_B64, MOCKUP_MIME);
  if (path === "/assets/security-banner-v56.webp") return assetResponse(SECURITY_BANNER_V56_B64, MOCKUP_MIME);
  if (path === "/admin.webmanifest") return adminManifest();
  if (path === "/admin-v33.webmanifest") return adminManifest();
  if (path === "/admin-sw.js") return adminServiceWorker();
  if (path === "/favicon.ico") return assetResponse(HB_FAVICON_B64, HB_APP_ICON_MIME);
  const ltsImageMatch = path.match(/^\/assets\/lts-product-image\/([^\/]+)$/);
  if (method === "GET" && ltsImageMatch) return ltsProductImageProxy(request, env, decodeURIComponent(ltsImageMatch[1]));
  if (method === "GET" && path === "/admin/lts/sync") return adminLtsSyncOne(request, env);
  if (method === "GET" && path === "/admin/lts/sync-all") return adminLtsSyncAll(request, env);

  const dueCalPublicMatch = path.match(/^\/calendar\/hb-due-dates-([a-f0-9]+)\.ics$/i); if (method === "GET" && dueCalPublicMatch) return adminDueDatesIcs(request, env, dueCalPublicMatch[1]);
  if (method === "GET" && path === "/account") return customerAccountPage(request, env);
  if (method === "GET" && path === "/account/orders") return customerOrderHistoryPage(request, env);
  if (method === "GET" && path === "/account/profile") return customerAccountPage(request, env);
  if (method === "GET" && path === "/account/change-password") return customerChangePasswordPage(request, env);
