  if (method === "POST" && path === "/account/login") return customerLoginPost(request, env);
  if (method === "GET" && path === "/account/logout") return customerLogout(request, env);
  if (method === "GET" && path === "/account/register") return customerRegisterPage(request, env);
  if (method === "POST" && path === "/account/register") return customerRegisterPost(request, env);
  if (method === "GET" && path === "/account/verify") return customerVerifyEmail(request, env);
  if (method === "GET" && path === "/account/forgot") return customerForgotPage(request, env);
  if (method === "POST" && path === "/account/forgot") return customerForgotPost(request, env);
  if (method === "GET" && path === "/account/reset") return customerResetPage(request, env);
  if (method === "POST" && path === "/account/reset") return customerResetPost(request, env);

  const payInvoiceMatch = path.match(/^\/pay\/invoice\/([^\/]+)\/([^\/]+)$/);
  if (method === "GET" && payInvoiceMatch) return publicInvoicePayPage(request, env, decodeURIComponent(payInvoiceMatch[1]), decodeURIComponent(payInvoiceMatch[2]));
  if (method === "POST" && payInvoiceMatch) return publicInvoicePaymentPost(request, env, decodeURIComponent(payInvoiceMatch[1]), decodeURIComponent(payInvoiceMatch[2]));
  const payOrderMatch = path.match(/^\/pay\/order\/([^\/]+)\/([^\/]+)$/);
  if (method === "GET" && payOrderMatch) return publicInvoicePayPage(request, env, decodeURIComponent(payOrderMatch[1]), decodeURIComponent(payOrderMatch[2]));
  if (method === "POST" && payOrderMatch) return publicInvoicePaymentPost(request, env, decodeURIComponent(payOrderMatch[1]), decodeURIComponent(payOrderMatch[2]));
  if (method === "GET" && path === "/") return pageHome(env);
  if (method === "GET" && path === "/services") return pageServices(env);
  if (method === "GET" && path === "/merchant-services") return pagePayment(env);
  if (method === "GET" && path === "/merchant-services/apply") return merchantApplicationOptionsPage(env);
  if (method === "GET" && path === "/merchant-services/apply/pos-merchant") { const c = await requireVerifiedCustomer(request, env); if (!c) return redirect(accountLoginUrl(request)); return merchantApplicationFormRoute(request, env, "pos_merchant", "", c); }
