function normalizePath(path) {
  if (path.length > 1 && path.endsWith("/")) path = path.slice(0, -1);
  return path;
}

function applePayDomainAssociationResponse(method = "GET") {
  const headers = {
    "content-type": "text/plain; charset=utf-8",
    "cache-control": "no-store, max-age=0",
    "x-content-type-options": "nosniff"
  };
  return new Response(method === "HEAD" ? null : APPLE_PAY_DOMAIN_ASSOCIATION_TEXT, { status: 200, headers });
}

function assetResponse(b64, mime) {
  const bytes = Uint8Array.from(atob(b64), c => c.charCodeAt(0));
  return new Response(bytes, { headers: { "content-type": mime, "cache-control": "public, max-age=86400" } });
}

function homepageBackgroundThemeCss() {
  const css = `
:root{
  --hb-navy:#06284d;
  --hb-deep-navy:#061b35;
  --hb-orange:#ff6a00;
  --hb-green:#138a3d;
  --hb-page-bg-1:#fbfdff;
  --hb-page-bg-2:#f7fafc;
  --hb-page-bg-3:#eef8f3;
}
body,.hb-homepage-background{
  background:
    radial-gradient(circle at 12% 8%,rgba(255,106,0,.13),transparent 25%),
    radial-gradient(circle at 88% 18%,rgba(19,138,61,.14),transparent 28%),
    linear-gradient(135deg,#fbfdff 0%,#f7fafc 44%,#eef8f3 100%);
  background-attachment:fixed;
}
.hb-homepage-background-overlay:before{
  content:"";
  position:fixed;
  inset:0;
  pointer-events:none;
  z-index:-1;
  background:linear-gradient(120deg,rgba(6,40,77,.035),rgba(255,106,0,.025),rgba(19,138,61,.035));
}`;
  return new Response(css, { headers: { "content-type":"text/css; charset=utf-8", "content-disposition":"attachment; filename=hb-homepage-background-theme.css", "cache-control":"public, max-age=86400" } });
}

function logoResponse() {
  return assetResponse(LOGO_B64, LOGO_MIME);
}

