function responsiveDeviceScript(){
  return `<script>(function(){
    function classify(){
      var w=Math.min(window.innerWidth||0, screen && screen.width ? screen.width : window.innerWidth || 0) || 1200;
      var ua=(navigator.userAgent||'').toLowerCase();
      var isTouch=('ontouchstart' in window)||navigator.maxTouchPoints>0;
      var phone=w<=760 || /iphone|android.*mobile|windows phone/.test(ua);
      var tablet=!phone && (w<=1180 || /ipad|tablet|android(?!.*mobile)/.test(ua) || (isTouch && w<=1366));
      var root=document.documentElement;
      root.classList.toggle('hb-device-phone', !!phone);
      root.classList.toggle('hb-device-tablet', !!tablet);
      root.classList.toggle('hb-device-desktop', !phone && !tablet);
      root.dataset.hbDevice = phone ? 'phone' : tablet ? 'tablet' : 'desktop';
    }
    classify();
    var t;
    window.addEventListener('resize',function(){clearTimeout(t);t=setTimeout(classify,120);},{passive:true});
    window.addEventListener('orientationchange',function(){setTimeout(classify,180);},{passive:true});
  })();</script>`;
}

function installButtonHtml() {
  return `<div id="hbInstallWidget" class="hb-install-widget" hidden>
  <button id="hbInstallButton" class="hb-install-button" type="button" aria-label="Install HB Commerce app">
    <span>＋</span><strong>Install App</strong>
  </button>
</div>
<style>
.hb-install-widget[hidden]{display:none!important}
.hb-install-widget{position:fixed;right:18px;bottom:18px;z-index:2147483000}
.hb-install-button{display:flex;align-items:center;gap:8px;border:0;border-radius:999px;background:linear-gradient(135deg,#ff6a00,#ff8c21);color:#fff;padding:12px 16px;min-height:48px;font:900 14px/1 system-ui,-apple-system,Segoe UI,Arial,sans-serif;box-shadow:0 16px 42px rgba(255,106,0,.38),0 8px 20px rgba(6,27,53,.18);cursor:pointer;transition:.18s ease}
.hb-install-button span{display:grid;place-items:center;width:23px;height:23px;border-radius:50%;background:rgba(255,255,255,.22);font-size:19px;line-height:1}
.hb-install-button:hover{transform:translateY(-2px);box-shadow:0 20px 52px rgba(255,106,0,.45),0 10px 24px rgba(6,27,53,.22)}
@media(max-width:520px){.hb-install-widget{right:14px;bottom:14px}.hb-install-button strong{font-size:13px}.hb-install-button{padding:11px 14px}}
@media print{.hb-install-widget{display:none!important}}
</style>
<script>
(function(){
  if (window.__hbInstallButtonLoaded) return;
  window.__hbInstallButtonLoaded = true;

  var deferredPrompt = null;
  var widget = null;
  var button = null;

  function isStandalone(){
    return window.matchMedia('(display-mode: standalone)').matches || window.navigator.standalone === true;
  }

  function hideWidget(){
    widget = widget || document.getElementById('hbInstallWidget');
    if (widget) widget.hidden = true;
  }

  function showWidget(){
    if (isStandalone()) return;
    widget = widget || document.getElementById('hbInstallWidget');
    if (widget) widget.hidden = false;
  }

  window.addEventListener('beforeinstallprompt', function(e){
    e.preventDefault();
    deferredPrompt = e;
    showWidget();
  });

  window.addEventListener('appinstalled', function(){
    hideWidget();
    deferredPrompt = null;
  });

  document.addEventListener('DOMContentLoaded', function(){
    widget = document.getElementById('hbInstallWidget');
    button = document.getElementById('hbInstallButton');

    // Important: do NOT show fallback messages. Only show the button when the browser
    // gives the actual install prompt event. If Chrome shows "Open in app" in the
    // address bar, the app is already installed and this button stays hidden.
    hideWidget();

    if (button) {
      button.addEventListener('click', async function(){
        if (!deferredPrompt) {
          hideWidget();
          return;
        }
        var promptEvent = deferredPrompt;
        deferredPrompt = null;
        try { await promptEvent.prompt(); } catch(e) {}
        hideWidget();
      });
    }
  });
})();
</script>`;
}


function eufyCartHeaderScript() {
  return `<script>(function(){
    if(window.__hbEufyCartHeaderLoaded)return;window.__hbEufyCartHeaderLoaded=true;
    const KEY='hb_eufy_quote_cart';
    function get(){try{return JSON.parse(localStorage.getItem(KEY)||'[]')}catch(e){return[]}}
    function count(){return get().reduce((a,x)=>a+(parseInt(x.qty)||0),0)}
    function update(){document.querySelectorAll('#eufyCartCount,.eufy-cart-floating-count').forEach(el=>{el.textContent=count()})}
    window.hbEufyCartUpdate=update;
    window.addEventListener('storage',e=>{if(e.key===KEY)update()});
    document.addEventListener('DOMContentLoaded',update);
    update();
  })();</script>`;
}

function htmlPage(title, body, status = 200, headers = {}) {
  return new Response(`<!doctype html><html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>${escapeHtml(title)}</title><link rel="icon" href="/assets/hb-favicon-v33.png"><link rel="apple-touch-icon" href="/assets/hb-app-icon-v33-512.png"><link rel="manifest" href="/site-v33.webmanifest"><meta name="theme-color" content="#061b35"><style>${CSS}</style></head><body>${body}${responsiveDeviceScript()}${installButtonHtml()}${eufyCartHeaderScript()}</body></html>`, {
    status,
    headers: { "content-type": "text/html; charset=utf-8", ...headers }
  });
}


function customerAccountNavScript() {
  return `<script>
(function(){
  function esc(s){return String(s||'').replace(/[&<>"']/g,function(c){return {'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c];});}
  function initials(s){s=String(s||'').trim();if(!s)return 'AC';var p=s.split(/\\s+/).filter(Boolean);return ((p[0]||'A')[0]+(p[1]||p[0]||'C')[0]).toUpperCase();}
  var account=document.querySelector('.hb-v72-nav-links .nav-account');
  if(!account || account.__hbAccountMenuReady)return;
  account.__hbAccountMenuReady=true;
  fetch('/api/customer-status',{credentials:'same-origin',cache:'no-store'}).then(function(r){return r.json();}).then(function(status){
    if(!status || !status.logged_in)return;
    var name=status.display_name||status.business_name||status.email||'My Account';
    var email=status.email||'';
    var nav=account.parentNode;
    var wrap=document.createElement('div');
    wrap.className='customer-account-dropdown';
    nav.insertBefore(wrap, account);
    wrap.appendChild(account);
    account.classList.add('logged-in');
    account.setAttribute('href','/account');
    account.setAttribute('title','My Account');
    account.setAttribute('aria-label','My Account');
    account.innerHTML='<svg class="customer-user-icon" viewBox="0 0 24 24" aria-hidden="true"><path d="M12 12.1a4.35 4.35 0 1 0 0-8.7 4.35 4.35 0 0 0 0 8.7Z"/><path d="M4.75 20.15c.6-3.85 3.35-6 7.25-6s6.65 2.15 7.25 6c.08.5-.32.95-.83.95H5.58c-.51 0-.91-.45-.83-.95Z"/></svg><span class="customer-account-initials">'+esc(initials(name))+'</span>';
    var menu=document.createElement('div');
    menu.className='customer-account-menu';
    menu.innerHTML='<div class="customer-menu-head"><strong>'+esc(name)+'</strong><small>'+esc(email)+'</small></div><a href="/account">My Account / Profile</a><a href="/account/change-password">Change Password</a><a href="/account/logout" class="logout">Log Out</a>';
    wrap.appendChild(menu);
    account.addEventListener('click',function(e){
      e.preventDefault();
      wrap.classList.toggle('open');
    });
    document.addEventListener('click',function(e){
      if(!wrap.contains(e.target))wrap.classList.remove('open');
    });
    document.addEventListener('keydown',function(e){
      if(e.key==='Escape')wrap.classList.remove('open');
    });
  }).catch(function(){});
})();
</script>`;
}

