function v19FullHeroSliderScript() {
  return `(function(){
    const wrap=document.querySelector('.v19-full-hero-slider');
    const slides=[...document.querySelectorAll('.v19-hero-slide')];
    const dots=[...document.querySelectorAll('.v19-dot')];
    const prev=document.querySelector('.v56-prev');
    const next=document.querySelector('.v56-next');
    if(!slides.length)return;
    let i=0,timer=null;
    function show(n){
      i=(n+slides.length)%slides.length;
      slides.forEach((s,k)=>s.classList.toggle('active',k===i));
      dots.forEach((d,k)=>d.classList.toggle('active',k===i));
      if(wrap)wrap.setAttribute('data-active',String(i));
    }
    function stop(){if(timer){clearInterval(timer);timer=null;}}
    function play(){stop();timer=setInterval(()=>show(i+1),3900);}
    dots.forEach((d,k)=>d.addEventListener('click',function(e){e.preventDefault();stop();show(k);play();}));
    if(prev)prev.addEventListener('click',function(e){e.preventDefault();stop();show(i-1);play();});
    if(next)next.addEventListener('click',function(e){e.preventDefault();stop();show(i+1);play();});
    if(wrap){wrap.addEventListener('mouseenter',stop);wrap.addEventListener('mouseleave',play);}
    show(0);play();
  })();`;
}

