async function loadMerchantApplicationDraft(env, type, customer) {
  if (!customer) return null;
  const rows = await env.DB.prepare("SELECT id,data_json,updated_at FROM documents WHERE type='MerchantApplication' AND business=? AND status='Draft' ORDER BY updated_at DESC LIMIT 50").bind(type).all();
  for (const row of (rows.results || [])) {
    try {
      const app = JSON.parse(row.data_json || "{}");
      const data = app.app_data || {};
      if (data.customer_account_id === customer.id || data.customer_account_email === customer.email || app.email === customer.email) {
        return { ...data, _draft_id: row.id, _draft_number: app.number || "", _draft_updated_at: row.updated_at || app.updated_at || "" };
      }
    } catch {}
  }
  return null;
}

async function merchantApplicationFormRoute(request, env, type, message = "", customer = null) {
  const url = new URL(request.url);
  let values = await loadMerchantApplicationDraft(env, type, customer) || {};
  let note = message;
  if (url.searchParams.get("draft") === "saved") {
    note += `<div class="notice success"><strong>Draft saved.</strong> You can continue this application now or come back later while logged in.</div>`;
  } else if (values._draft_id) {
    note += `<div class="notice"><strong>Saved draft loaded.</strong> Last saved: ${escapeHtml(formatDateTime(values._draft_updated_at || ""))}</div>`;
  }
  return merchantApplicationFormPage(request, env, type, note, customer, values);
}

