function eufyProductById(id, products = null) {
  const list = products || eufyProducts();
  return list.find(p => p.id === id) || null;
}

function eufySlug(value) {
  return String(value || "").toLowerCase().replace(/[^a-z0-9]+/g, "-").replace(/^-+|-+$/g, "").slice(0, 80) || randomHex(4);
}

function normalizeEufyProduct(p = {}) {
  const regular = Math.max(0, Number(p.regular_price || p.price || 0));
  const discount = Math.max(0, Number(p.discount || 0));
  const sale = Math.max(0, regular - discount);
  let bullets = p.bullets;
  if (typeof bullets === "string") bullets = bullets.split(/\r?\n/).map(s => s.trim()).filter(Boolean);
  if (!Array.isArray(bullets)) bullets = [];
  const name = String(p.name || "New eufy Item").trim();
  return {
    id: String(p.id || eufySlug(name)).trim() || eufySlug(name),
    name,
    price: regular,
    regular_price: regular,
    sale_price: sale,
    discount,
    coupon: String(p.coupon || "").trim(),
    coupon_label: discount > 0 ? `Save ${money(discount)}` : "",
    coupon_required: discount > 0,
    desc: String(p.desc || p.description || "").trim(),
    image: String(p.image || p.image_url || "").trim() || "https://cdn.shopify.com/s/files/1/0504/7094/4954/files/1500_1500_2x-5_3840x.png?v=1760087772",
    video: String(p.video || p.video_url || "").trim(),
    category: String(p.category || "PoE NVR Security System").trim(),
    bullets,
    active: p.active === false ? false : true
  };
}

async function eufyProductsForEnv(env, includeInactive = false) {
  let list = null;
  let hasSavedList = false;
  try {
    const raw = await getSetting(env, "eufy_products_json", "");
    if (raw) {
      const parsed = JSON.parse(raw);
      if (Array.isArray(parsed)) {
        list = parsed;
        hasSavedList = true;
      }
    }
  } catch (err) {
    console.error("eufy product settings load failed", err);
  }
  if (!hasSavedList) list = eufyProducts();
  const normalized = (Array.isArray(list) ? list : []).map(normalizeEufyProduct);
  return includeInactive ? normalized : normalized.filter(p => p.active !== false);
}

async function saveEufyProducts(env, products) {
  const normalized = (Array.isArray(products) ? products : []).map(normalizeEufyProduct);
  await setSetting(env, "eufy_products_json", JSON.stringify(normalized));
  return normalized;
}


function eufyProductCard(p) {
  const id = escapeHtml(p.id);
  const couponId = `coupon-${id}`;
  const hasCoupon = Number(p.discount || 0) > 0 && !!p.coupon;
  const priceHtml = hasCoupon
    ? `<div class="eufy-price-row v40"><span class="eufy-current">${money(p.regular_price || p.price)}</span><span class="eufy-after">After coupon: ${money(p.sale_price || p.price)}</span></div>`
    : `<div class="eufy-price-row v40"><span class="eufy-after no-coupon-price">${money(p.regular_price || p.price)}</span></div>`;
  const couponHtml = hasCoupon
    ? `<label class="eufy-coupon-check"><input type="checkbox" id="${couponId}"><span>Save ${money(p.discount || 0)} <em>with Code: ${escapeHtml(p.coupon)}</em></span><button type="button" onclick="eufyCopyCode('${escapeHtml(p.coupon)}')">Copy Code</button></label>`
    : `<div class="eufy-no-coupon-note">No coupon currently listed for this item.</div>`;
  return `<article class="eufy-shop-card"><a class="eufy-card-image" href="/security-camera-systems/eufy-poe-nvr-camera-systems/${encodeURIComponent(p.id)}"><img src="${escapeHtml(p.image)}" alt="${escapeHtml(p.name)}" loading="lazy"></a><div class="eufy-card-body"><div class="eufy-category">${escapeHtml(p.category || "PoE NVR Security System")}</div><h3><a href="/security-camera-systems/eufy-poe-nvr-camera-systems/${encodeURIComponent(p.id)}">${escapeHtml(p.name)}</a></h3><p>${escapeHtml(p.desc)}</p>${priceHtml}${couponHtml}<div class="eufy-actions"><a class="btn small" href="/security-camera-systems/eufy-poe-nvr-camera-systems/${encodeURIComponent(p.id)}">View Details</a><button type="button" class="orange small" onclick="event.preventDefault();event.stopPropagation();eufyAddToCart('${id}',1,document.getElementById('${couponId}')&&document.getElementById('${couponId}').checked)">Add to Cart</button></div></div></article>`;
}


