async function pageEufyCheckout(env) {
  const products = await quoteProductsForEnv(env);
  const acfg = authNetConfig(env);
  const acceptJsV1 = authNetMode(env) === "sandbox" ? "https://jstest.authorize.net/v1/Accept.js" : "https://js.authorize.net/v1/Accept.js";
  const body = `${HB_SHOP_BACKGROUND_STYLE}<main class="hb-shop-page-v192 eufy-checkout-page"><section class="hb-shop-hero-v192"><div class="container"><div><div class="kicker">Checkout</div><h1>Secure Checkout</h1><p>Complete delivery, live UPS rating, ZipTax, and payment in a clean secure checkout.</p></div><a class="hb-pro-soft-btn" href="/cart">Back to Cart</a></div></section><section class="hb-pro-shop-section"><div class="container hb-pro-checkout-layout">${eufyCheckoutForm()}${eufyCartPanel(false)}</div><script>window.HB_ACCEPT_CONFIG={login:${JSON.stringify(acfg.login)},clientKey:${JSON.stringify(acfg.publicKey)},ready:${authNetReady(env)?"true":"false"}};</script><script src="${acceptJsV1}"></script>${eufyStoreScript(products)}<script>(function(){const K='hb_eufy_quote_cart';function m(n){return new Intl.NumberFormat('en-US',{style:'currency',currency:'USD'}).format(Number(n)||0)}function q(id){return document.getElementById(id)}function cart(){try{return JSON.parse(localStorage.getItem(K)||'[]')}catch(e){return[]}}function ship(){return{street:(q('shipStreet')||{}).value||'',city:(q('shipCity')||{}).value||'',state:(q('shipState')||{}).value||'',zip:(q('shipZip')||{}).value||''}}function fulfill(){let r=document.querySelector('input[name=fulfillment_type]:checked');return r?r.value:'ups'}function setShipReq(on){['shipStreet','shipCity','shipState','shipZip'].forEach(id=>{let e=q(id);if(e)e.required=on});let b=q('shippingAddressBlock');if(b)b.style.display=on?'block':'none'}async function rate(){let box=q('shippingRateBox'),c=cart(),f=fulfill();setShipReq(f!=='pickup');if(f==='pickup'){window.hbEufyShippingReady=true;window.hbEufyShipCost=0;if(q('shipCost'))q('shipCost').value='0';if(q('eufyCartShipping'))q('eufyCartShipping').textContent=m(0);if(q('shipService'))q('shipService').value='pickup';if(box)box.innerHTML='<strong>Pickup selected</strong><br><small>No shipping charge.</small>';calc();return}window.hbEufyShippingReady=false;let s=ship();if(!s.zip||String(s.zip).replace(/\D/g,'').length<5){window.hbEufyShipCost=0;if(q('shipCost'))q('shipCost').value='0';if(q('eufyCartShipping'))q('eufyCartShipping').textContent=(f==='fedex'?'FedEx needed':'UPS needed');if(box)box.innerHTML='<strong>'+(f==='fedex'?'FedEx Ground':'UPS Ground')+'</strong><br><small>Enter shipping ZIP to calculate live carrier rate.</small>';calc();return}try{let r=await fetch('/api/shipping/rate',{method:'POST',headers:{'content-type':'application/json'},body:JSON.stringify({cart:c,shipping:s,fulfillment_type:f})});let j=await r.json(),x=j.rates&&j.rates[0];if(!j.ok||!x)throw new Error(j.message||'Carrier rate unavailable');window.hbEufyShippingReady=true;window.hbEufyShipCost=Number(x.amount||0);if(q('shipCost'))q('shipCost').value=String(x.amount||0);if(q('shipService'))q('shipService').value=x.code||f;if(q('eufyCartShipping'))q('eufyCartShipping').textContent=m(x.amount||0);if(box)box.innerHTML='<strong>'+x.label+'</strong> '+m(x.amount||0)+'<br><small>'+(j.source||'live carrier rate')+'</small>'}catch(e){if(box)box.innerHTML='<strong>Carrier rate could not be calculated</strong><br><small>Please verify ZIP/address or choose Pickup. Admin can also verify shipping.</small>';window.hbEufyShipCost=0;window.hbEufyShippingReady=false}calc()}async function calc(){let c=cart();if(!c.length)return;try{let r=await fetch('/api/tax/calculate',{method:'POST',headers:{'content-type':'application/json'},body:JSON.stringify({cart:c,shipping:ship(),checkout_coupon_code:(q('checkoutCouponCode')||{}).value||''})});let j=await r.json();if(!j.ok)return;let tax=Number(j.tax_amount||0),sub=Number(j.taxable_amount||0),rate=Number(j.rate||0),sh=Number(window.hbEufyShipCost||0);if(q('eufyCartTax'))q('eufyCartTax').textContent=m(tax);if(q('eufyCartTotal'))q('eufyCartTotal').textContent=m(sub+tax+sh);if(q('eufyQuoteItemNote'))q('eufyQuoteItemNote').textContent='Destination tax from '+(j.source||'ZipTax')+' ('+rate.toFixed(3)+'%).'}catch(e){}}window.hbUpdateShippingRate=rate;['shipStreet','shipCity','shipState','shipZip','checkoutCouponCode'].forEach(id=>{let el=q(id);if(el){el.addEventListener('input',()=>setTimeout(rate,350));el.addEventListener('blur',rate)}});document.addEventListener('change',e=>{if(e.target&&e.target.name==='fulfillment_type')rate()});document.addEventListener('DOMContentLoaded',()=>setTimeout(rate,700));})();</script></section></main>`;
  return htmlPage('Checkout | HB Commerce Solutions', layout(env, 'Checkout', body));
}

async function pageEufyProduct(env, id) {
  const products = await eufyProductsForEnv(env);
  const catalog = await quoteProductsForEnv(env);
  const p = eufyProductById(decodeURIComponent(id || ''), products);
  if (!p) return htmlPage('Product Not Found', layout(env, 'Security', `<section class="section"><div class="container"><div class="notice error">eufy product not found.</div><p><a class="btn" href="/security-camera-systems">Back to eufy Products</a></p></div></section>`), 404);
  const bullets = (p.bullets || []).map(b => `<li>${escapeHtml(b)}</li>`).join('');
  const hasCoupon = Number(p.discount || 0) > 0 && !!p.coupon;
  const priceHtml = hasCoupon ? `<div class="eufy-price-row detail v40"><span class="eufy-current">${money(p.regular_price || p.price)}</span><span class="eufy-after">After coupon: ${money(p.sale_price || p.price)}</span></div>` : `<div class="eufy-price-row detail v40"><span class="eufy-after no-coupon-price">${money(p.regular_price || p.price)}</span></div>`;
  const couponHtml = hasCoupon ? `<label class="eufy-coupon-check big"><input type="checkbox" id="detailCoupon"><span>Save ${money(p.discount || 0)} <em>with Code: ${escapeHtml(p.coupon)}</em></span><button type="button" onclick="eufyCopyCode('${escapeHtml(p.coupon)}')">Copy Code</button></label>` : `<div class="notice">No coupon is currently listed for this item.</div>`;
  const videoHtml = p.video ? `<div class="eufy-video-box"><a class="btn" target="_blank" rel="noopener" href="${escapeHtml(p.video)}">Watch Product Video</a></div>` : ``;
  const body = `<main class="eufy-detail-page"><section class="section"><div class="container"><a class="back-link" href="/security-camera-systems/eufy-poe-nvr-camera-systems">← Back to eufy PoE NVR Camera Systems</a><div class="eufy-detail-grid"><div class="eufy-detail-image"><img src="${escapeHtml(p.image)}" alt="${escapeHtml(p.name)}">${videoHtml}</div><div class="eufy-detail-info"><div class="eufy-category">${escapeHtml(p.category || 'PoE NVR Security System')}</div><h1>${escapeHtml(p.name)}</h1><p class="lead">${escapeHtml(p.desc)}</p>${priceHtml}${couponHtml}<ul class="eufy-detail-bullets">${bullets}</ul><div class="notice">This hardware order creates a quote first. The product ships only after the quote is approved and payment is received/cleared.</div><div class="eufy-detail-actions"><input id="detailQty" type="number" min="1" value="1"><button class="orange" type="button" onclick="event.preventDefault();eufyAddToCart('${escapeHtml(p.id)}',document.getElementById('detailQty').value,document.getElementById('detailCoupon')&&document.getElementById('detailCoupon').checked)">Add to Cart</button></div></div></div><div class="eufy-info-panels"><div><h3>What is an NVR system?</h3><p>An NVR system records digital video from IP cameras to a Network Video Recorder for local storage and centralized management.</p></div><div><h3>Why order through HB Commerce?</h3><p>We generate a quote first, collect your preferred payment method, then finalize fulfillment only after signed approval and payment clearance.</p></div></div>${eufyStoreScript(catalog)}</div></section></main>`;
  return htmlPage(`${p.name} | HB Commerce Solutions`, layout(env, 'Security', body));
}

async function handleEufyOrder(request, env, customer = null) {
  const products = await quoteProductsForEnv(env);
  const fd = await request.formData();
  let cart = [];
  try { cart = JSON.parse(String(fd.get('cart_json') || '[]')); } catch { cart = []; }
  const checkoutCouponCode = String(fd.get('checkout_coupon_code') || '').trim().toUpperCase();
  const items = [];
  let hasQuoteOnlyItems = false;
  let hasPricedEufyItems = false;
  for (const row of cart) {
    const p = eufyProductById(String(row.id || ''), products) || ltsProductById(String(row.id || ''), products);
    if (!p) continue;
    const qty = Math.max(1, parseInt(row.qty || 1, 10) || 1);
    const quoteOnly = !!p.quote_only;
    if (quoteOnly) hasQuoteOnlyItems = true; else hasPricedEufyItems = true;
    const regular = quoteOnly ? 0 : Number(p.regular_price || p.price || 0);
    const productCouponCode = String(p.coupon || '').trim().toUpperCase();
    const couponApplied = !quoteOnly && (Number(p.discount || 0) > 0) && (!!row.coupon || (!!checkoutCouponCode && productCouponCode === checkoutCouponCode));
    const discount = couponApplied ? Number(p.discount || 0) : 0;
    const finalPrice = Math.max(0, regular - discount);
    const couponText = quoteOnly ? ' Pricing to be confirmed by HB Commerce before quote is emailed.' : (couponApplied ? ` Coupon applied: ${p.coupon || 'HB-EUFY-NVR'} saves ${money(discount)} per unit.` : ' Coupon not applied.');
    items.push({ qty, name: p.name, desc: p.desc + couponText + ' | Payment preference selected at checkout. eufy order total uses destination sales tax from ZipTax when available. Hardware ships only after payment is received/cleared.', cost: finalPrice, sale_price: regular, markup: 0, discount, taxable: true, source: p.brand || 'hardware', image: p.image, video: p.video || '', coupon_applied: couponApplied, coupon_code: couponApplied ? (p.coupon || 'HB-EUFY-NVR') : '' });
  }
  if (!items.length) return htmlPage('eufy Order', layout(env, 'Security', `<section class="section"><div class="container"><div class="notice error">No hardware products were selected.</div><p><a class="btn" href="/security-camera-systems">Back to Security Camera Systems</a></p></div></section>`));
  const first = String(fd.get('first_name') || '').trim();
  const last = String(fd.get('last_name') || '').trim();
  const email = String(fd.get('email') || '').trim();
  const phone = String(fd.get('phone') || '').trim();
  const paymentPreference = String(fd.get('payment_preference') || '').trim();
  const fulfillmentType = String(fd.get('fulfillment_type') || 'ups').trim();
  const shippingCost = fulfillmentType === 'pickup' ? 0 : Math.max(0, Number(fd.get('shipping_cost') || 0));
  const shipState = String(fd.get('shipping_state') || '').trim().toUpperCase();
  const ship = { street: String(fd.get('shipping_street') || '').trim(), city: String(fd.get('shipping_city') || '').trim(), state: shipState, zip: String(fd.get('shipping_zip') || '').trim() };
  const taxInfo = await taxForItems(env, ship, items);
  const orderType = hasQuoteOnlyItems ? 'OnlineQuoteOrder' : 'OnlineOrder';
  const orderLabel = orderType === 'OnlineQuoteOrder' ? 'Online Quote Order' : 'Online Order';
  const order = {
    customer_account_id: customer ? customer.id : '',
    customer_account_email: customer ? customer.email : '',
    id: randomId(), token: randomHex(16), type: orderType, business: 'camera', number: nextOrderNumber(orderType), doc_date: today(), valid_until: plusDays(7), prepared_by: orderType === 'OnlineQuoteOrder' ? 'Website Quote Order' : 'Website eufy Order', customer_name: `${first} ${last}`.trim(), billing_street: String(fd.get('billing_street') || ''), billing_city: String(fd.get('billing_city') || ''), billing_state: String(fd.get('billing_state') || ''), billing_zip: String(fd.get('billing_zip') || ''), shipping_same_as_billing: 0, shipping_street: ship.street, shipping_city: ship.city, shipping_state: shipState, shipping_zip: ship.zip, street: ship.street, city: ship.city, state: shipState, zip: ship.zip, email, phone, tax_rate: Number(taxInfo.rate || 10), tax_source: taxInfo.source || 'ZipTax destination lookup', tax_exact: !!taxInfo.exact, shipping_cost: shippingCost, shipping_carrier: fulfillmentType, shipping_service: String(fd.get('shipping_service') || ''), shipping_rate_label: fulfillmentType === 'pickup' ? 'Pickup / No Shipping' : (fulfillmentType === 'fedex' ? 'FedEx Ground' : 'UPS Ground'), shipping_rate_source: fulfillmentType, items, status: 'New Order', paid: 0, created_at: now(), updated_at: now(), payment_preference: paymentPreference, checkout_coupon_code: checkoutCouponCode, order_type: orderType, has_quote_only_items: hasQuoteOnlyItems, has_priced_eufy_items: hasPricedEufyItems, customer_notes: `Preferred payment option: ${paymentPreference}. eufy priced products use destination sales tax from ZipTax when available. Check/Zelle orders remain pending in Admin; credit card orders are paid online by customer. LTS quote-only items require Admin pricing before final approval.`, eufy_order: {
      first_name: first, last_name: last, email, phone, payment_preference: paymentPreference, fulfillment_type: fulfillmentType, shipping_cost: shippingCost, shipping_service: String(fd.get('shipping_service') || ''), checkout_coupon_code: checkoutCouponCode,
      billing: { street: String(fd.get('billing_street') || ''), city: String(fd.get('billing_city') || ''), state: String(fd.get('billing_state') || ''), zip: String(fd.get('billing_zip') || '') },
      shipping: { street: String(fd.get('shipping_street') || ''), city: String(fd.get('shipping_city') || ''), state: shipState, zip: String(fd.get('shipping_zip') || '') }
    }
  };
  order.final_sale_notice_ack = String(fd.get('final_sale_notice_ack') || '') === '1' ? 1 : 0;
  order.final_sale_notice_text = 'ALL SALES ARE FINAL. Any changes in the pricing after placing the order anywhere online are not subject for difference refund or return of an order. We are not responsible for change in web price after the sale is completed.';
  if (order.eufy_order) {
    order.eufy_order.final_sale_notice_ack = order.final_sale_notice_ack;
    order.eufy_order.final_sale_notice_text = order.final_sale_notice_text;
  }
  let paidOnline = false, payResult = null;
  if (orderType === "OnlineOrder" && paymentPreference === "Credit Card") {
    try {
      payResult = await authNetChargeOpaque(request, env, order, String(fd.get("dataDescriptor") || ""), String(fd.get("dataValue") || ""));
      paidOnline = true;
      order.paid = 1;
      order.paid_at = now();
      order.payment_method = "Credit Card";
      order.status = "Paid Online";
      order.authnet_transaction_id = payResult.transId;
      order.authnet_auth_code = payResult.authCode;
      order.authnet_paid_amount = payResult.amount;
    } catch (err) {
      return htmlPage("Card Payment Failed", layout(env, "Checkout", `<main class="section"><div class="container"><div class="form-section"><div class="form-title">Card Payment Failed</div><div class="notice error">${escapeHtml(err.message || "The card payment was not approved.")}</div><p>Your card was not charged. Please return to checkout and try again, or choose Check/Zelle.</p><div class="btn-row"><a class="btn orange" href="/checkout">Back to Checkout</a><a class="btn" href="/cart">View Cart</a></div></div></div></main>`));
    }
  }
  await saveDoc(env, order);
  await sendAdminMobileNotification(env, orderType === "OnlineQuoteOrder" ? "New Online Quote Order" : (paidOnline ? "Paid eufy Online Order" : "New Online Order"), `${order.number} received from ${order.customer_name || order.email || "website customer"}.`, `${new URL(request.url).origin}${orderType === "OnlineQuoteOrder" ? "/admin/quote-orders" : "/admin/orders"}`).catch(err => console.error("online order phone notification failed", err));
  return htmlPage(paidOnline ? "Payment Approved" : orderLabel + ' Received', layout(env, 'Security', `<main class="section"><div class="container"><div class="form-section success-order"><div class="form-title">${paidOnline ? "Payment Approved" : escapeHtml(orderLabel) + " Received"}</div><div class="notice success"><strong>Thank you.</strong> ${paidOnline ? "Your card payment was approved and your online order was received." : "Your online hardware request " + escapeHtml(order.number) + " was received."}</div><p>${paidOnline ? "Transaction ID: " + escapeHtml(payResult && payResult.transId || "") : "Tax was calculated from the shipping destination when available. Check/Zelle orders appear in Admin Portal as online orders for follow-up."}</p><div class="btn-row"><a class="btn" href="/account/orders">My Orders</a><a class="btn orange" href="/">Return Home</a></div></div></div><script>localStorage.removeItem('hb_eufy_quote_cart');if(window.hbEufyCartUpdate)window.hbEufyCartUpdate();</script></main>`));
}

function nextOrderNumber(type = 'OnlineOrder') {
  const d = new Date().toISOString().slice(0,10).replaceAll('-', '');
  const prefix = type === 'OnlineQuoteOrder' ? 'QORD' : 'ORD';
  return `${prefix}-HB-${d}-${randomHex(2).toUpperCase()}`;
}

