async function customerOrderHistoryPage(request, env) {
  const account = await requireVerifiedCustomer(request, env);
  if (!account) return redirect(accountLoginUrl(request));
  const res = await env.DB.prepare("SELECT id,type,number,business,customer_name,email,status,paid,total,updated_at,data_json FROM documents ORDER BY updated_at DESC LIMIT 800").all();
  const rows = (res.results || []).map(row => {
    let detail = {};
    try { detail = JSON.parse(row.data_json || "{}"); } catch {}
    return { ...row, detail };
  }).filter(row => {
    const d = row.detail || {};
    return d.customer_account_id === account.id || row.email === account.email || d.customer_account_email === account.email;
  }).filter(row => ["OnlineOrder","OnlineQuoteOrder","Quote","Invoice"].includes(row.type));
  const table = rows.length ? `<div class="table-wrap account-order-history"><table><thead><tr><th>Number</th><th>Type</th><th>Status</th><th>Total</th><th>Updated</th><th>Action</th></tr></thead><tbody>${rows.map(row => {
    const customerLink = row.detail && row.detail.token ? `/review/${encodeURIComponent(row.id)}/${encodeURIComponent(row.detail.token)}` : "";
    return `<tr><td>${escapeHtml(row.number || "")}</td><td>${escapeHtml(row.type || "")}</td><td>${escapeHtml(row.status || "")}</td><td>${money(row.total || (row.detail && row.detail.total) || 0)}</td><td>${escapeHtml(String(row.updated_at || "").slice(0, 10))}</td><td>${customerLink ? `<a class="btn small" href="${customerLink}">View</a>` : `<a class="btn small" href="/account">Account</a>`}</td></tr>`;
  }).join("")}</tbody></table></div>` : `<div class="notice">No order or quote history found for this account yet.</div>`;
  const body = accountLayout("Order History", `<div class="kicker">Client Account</div><h1>Order History</h1><p>Review your recent online orders, quote requests, quotes, and invoices connected to your verified account.</p>${table}<div class="btn-row"><a class="btn" href="/account">Back to My Account</a><a class="btn orange" href="/security-camera-systems">Continue Shopping</a></div>`);
  return htmlPage("Order History | HB Commerce Solutions", layout(env, "Account", body));
}

