function quoteRequestPage(requestOrEnv, message = "", customer = null) {
  const hasRequest = requestOrEnv && typeof requestOrEnv.url === "string";
  const selectedService = hasRequest ? String(new URL(requestOrEnv.url).searchParams.get("service") || "") : "";
  const serviceOption = (value) => `<option ${selectedService === value ? "selected" : ""}>${escapeHtml(value)}</option>`;
  const fullName = customer ? `${customer.first_name || ""} ${customer.last_name || ""}`.trim() : "";
  const body = `<main class="v15-info-page"><section class="v15-info-hero"><div class="container"><div class="kicker">Quote Request</div><h1>Tell us what your business needs.</h1><p>Complete the form and we will follow up with the right solution for your business.</p></div></section><section class="section"><div class="container"><div class="form-section v15-request-form">${message}<div class="notice success">Logged in as ${escapeHtml(customer ? customer.email : "verified customer")}.</div><form method="post" action="/quote-request"><div class="grid-2"><div class="field"><label>Your Name</label><input name="name" value="${escapeHtml(fullName)}" required></div><div class="field"><label>Business Name</label><input name="business_name" value="${escapeHtml(customer ? customer.business_name || "" : "")}" required></div></div><div class="grid-2"><div class="field"><label>Email</label><input name="email" type="email" value="${escapeHtml(customer ? customer.email : "")}" required></div><div class="field"><label>Phone</label><input name="phone" value="${escapeHtml(customer ? customer.phone || "" : "")}"></div></div><div class="field"><label>Solution Needed</label><select name="service">${serviceOption("Merchant Services")}${serviceOption("POS Software for Retail")}${serviceOption("Security Camera Systems")}${serviceOption("Multiple Solutions")}</select></div><div class="field"><label>Project Details</label><textarea name="message" required></textarea></div><button class="primary">Submit Quote Request</button></form></div></div></section></main>`;
  return htmlPage("Quote Request | HB Commerce Solutions", layout(null, "Quote Request", body));
}

