const ADMIN_PERMISSION_LIST = [
  ["dashboard","Dashboard"],
  ["documents","Quotes / Invoices"],
  ["orders","Online Orders"],
  ["quoteOrders","Online Quote Orders"],
  ["customers","Customers"],
  ["products","EUFY / LTS Products"],
  ["applications","Applications"],
  ["reports","Sales Reports"],
  ["pnl_reports","P&L Reports"],
  ["notifications","Notifications / Tasks"],
  ["tax","Tax"],
  ["users","Users"],
  ["roles","Roles"]
];

function defaultRolePermissions() {
  const all = ADMIN_PERMISSION_LIST.map(p => p[0]);
  return {
    Admin: all,
    Manager: all.filter(p => !["users","roles"].includes(p)),
    Employee: ["dashboard","documents","orders","quoteOrders","customers"]
  };
}

async function adminRolePermissions(env) {
  try {
    const raw = await getSetting(env, "admin_role_permissions_json", "");
    const obj = raw ? JSON.parse(raw) : {};
    return { ...defaultRolePermissions(), ...obj, Admin: defaultRolePermissions().Admin };
  } catch { return defaultRolePermissions(); }
}

async function adminStaffProfiles(env) {
  try {
    const raw = await getSetting(env, "admin_staff_profiles_json", "");
    const arr = raw ? JSON.parse(raw) : [];
    return Array.isArray(arr) ? arr : [];
  } catch { return []; }
}

async function saveAdminStaffProfiles(env, arr) {
  await setSetting(env, "admin_staff_profiles_json", JSON.stringify(Array.isArray(arr) ? arr : []));
}

function staffRoleFor(session, profiles) {
  const email = String(session?.email || "").toLowerCase();
  const p = (profiles || []).find(x => String(x.email || "").toLowerCase() === email || String(x.user_id || "") === String(session?.user_id || ""));
  return p?.role || "Admin";
}

function permissionForAdminPath(path) {
  if (path.startsWith("/admin/users")) return "users";
  if (path.startsWith("/admin/roles")) return "roles";
  if (path.startsWith("/admin/settings")) return "roles";
  if (path.startsWith("/admin/reports")) return "reports";
  if (path.startsWith("/admin/pnl-reports")) return "pnl_reports";
  if (path.startsWith("/admin/notifications") || path.startsWith("/admin/reminder") || path.startsWith("/admin/push") || path.startsWith("/admin/ios-device") || path.startsWith("/admin/todos")) return "notifications";
  if (path.startsWith("/admin/tax")) return "tax";
  if (path.startsWith("/admin/eufy") || path.startsWith("/admin/lts") || path.startsWith("/admin/inventory-search")) return "products";
  if (path.startsWith("/admin/applications")) return "applications";
  if (path.startsWith("/admin/pos-support")) return "customers";
  if (path.startsWith("/admin/customers")) return "customers";
  if (path.startsWith("/admin/quote-orders")) return "quoteOrders";
  if (path.startsWith("/admin/orders")) return "orders";
  if (path.startsWith("/admin/clone")) return "documents";
  if (path.startsWith("/admin/document") || path.startsWith("/admin/create") || path.startsWith("/admin/email") || path.startsWith("/admin/convert") || path.startsWith("/admin/pay") || path.startsWith("/admin/paid") || path.startsWith("/admin/cancel") || path.startsWith("/admin/restore") || path.startsWith("/admin/invoice-templates")) return "documents";
  if (path.startsWith("/admin/dashboard")) return "dashboard";
  return "";
}

async function adminAccessDenied(request, env, path) {
  const perm = permissionForAdminPath(path);
  if (!perm) return null;
  const session = await requireAuth(request, env);
  if (!session) return null;
  const profiles = await adminStaffProfiles(env);
  const role = staffRoleFor(session, profiles);
  if (role === "Admin") return null;
  const perms = await adminRolePermissions(env);
  if ((perms[role] || []).includes(perm)) return null;
  const body = `<main class="section admin-dashboard"><div class="container"><div class="form-section"><div class="form-title">Access Denied</div><div class="notice error">Your role (${escapeHtml(role)}) does not have permission to access this Admin Portal section.</div><div class="btn-row"><a class="btn" href="/admin/dashboard?app=1">Dashboard</a><a class="btn danger" href="/admin/logout">Logout</a></div></div></div></main>`;
  return htmlPage("Access Denied | HB Commerce", layout(env, "Dashboard", body), 403);
}

function roleOptions(selected) {
  return ["Admin","Manager","Employee"].map(r => `<option value="${r}" ${r === selected ? "selected" : ""}>${r}</option>`).join("");
}

async function adminUsersPage(request, env, message = "") {
  const user = await requireAuth(request, env);
  if (!user) return redirect("/admin-app");
  const profiles = await adminStaffProfiles(env);
  const rows = (await env.DB.prepare("SELECT id,email,created_at FROM users ORDER BY created_at DESC LIMIT 200").all()).results || [];
  const bodyRows = rows.map(u => {
    const p = profiles.find(x => String(x.user_id||"") === String(u.id) || String(x.email||"").toLowerCase() === String(u.email||"").toLowerCase()) || {};
    const name = [p.first_name,p.last_name].filter(Boolean).join(" ") || "—";
    return `<tr><td>${escapeHtml(name)}</td><td>${escapeHtml(u.email)}</td><td>${escapeHtml(p.role || "Admin")}</td><td>${escapeHtml(p.phone || "")}</td><td>${escapeHtml([p.city,p.state,p.zip].filter(Boolean).join(", "))}</td></tr>`;
  }).join("") || `<tr><td colspan="5">No users found.</td></tr>`;
  const body = `<main class="section admin-dashboard admin-users-page"><div class="container"><div class="section-title"><h2>Admin Users</h2><div class="btn-row"><a class="btn" href="/admin/dashboard?app=1">Dashboard</a><a class="btn orange" href="/admin/roles">Manage Roles</a></div></div>${message}<section class="form-section"><div class="form-title">Add Employee / Admin User</div><form method="post" action="/admin/users"><div class="grid-2"><div class="field"><label>First Name</label><input name="first_name" required></div><div class="field"><label>Last Name</label><input name="last_name" required></div></div><div class="field"><label>Address</label><input name="address"></div><div class="grid-3"><div class="field"><label>Zipcode</label><input name="zip"></div><div class="field"><label>City</label><input name="city"></div><div class="field"><label>State</label><input name="state"></div></div><div class="grid-2"><div class="field"><label>Phone Number</label><input name="phone" type="tel"></div><div class="field"><label>Email Address</label><input name="email" type="email" required></div></div><div class="grid-3"><div class="field"><label>Password</label><input name="password" type="password" minlength="8" required></div><div class="field"><label>Verify Password</label><input name="password2" type="password" minlength="8" required></div><div class="field"><label>Role</label><select name="role">${roleOptions("Employee")}</select></div></div><button class="primary">Create User</button></form></section><section class="form-section"><div class="form-title">Current Admin Portal Users</div><div class="table-wrap"><table><thead><tr><th>Name</th><th>Email</th><th>Role</th><th>Phone</th><th>Location</th></tr></thead><tbody>${bodyRows}</tbody></table></div></section></div></main>`;
  return htmlPage("Admin Users | HB Commerce", layout(env, "Dashboard", body));
}

async function adminUsersPost(request, env) {
  const user = await requireAuth(request, env);
  if (!user) return redirect("/admin-app");
  const fd = await request.formData();
  const email = String(fd.get("email") || "").trim().toLowerCase();
  const password = String(fd.get("password") || "");
  const password2 = String(fd.get("password2") || "");
  if (!email || password.length < 8 || password !== password2) return adminUsersPage(request, env, `<div class="notice error">Enter a valid email and matching passwords with at least 8 characters.</div>`);
  const id = crypto.randomUUID(), salt = randomHex(16), iterations = 100000;
  try {
    await env.DB.prepare("INSERT INTO users (id,email,password_hash,salt,iterations,created_at) VALUES (?,?,?,?,?,?)").bind(id, email, await hashPassword(password, salt, iterations), salt, iterations, now()).run();
  } catch(e) {
    return adminUsersPage(request, env, `<div class="notice error">Could not create user. The email may already exist.</div>`);
  }
  const profiles = (await adminStaffProfiles(env)).filter(p => String(p.email||"").toLowerCase() !== email);
  profiles.push({ user_id:id,email,first_name:String(fd.get("first_name")||"").trim(),last_name:String(fd.get("last_name")||"").trim(),address:String(fd.get("address")||"").trim(),zip:String(fd.get("zip")||"").trim(),city:String(fd.get("city")||"").trim(),state:String(fd.get("state")||"").trim(),phone:String(fd.get("phone")||"").trim(),role:String(fd.get("role")||"Employee"),created_at:now() });
  await saveAdminStaffProfiles(env, profiles);
  return adminUsersPage(request, env, `<div class="notice success">Admin Portal user created.</div>`);
}

async function adminRolesPage(request, env, message = "") {
  const user = await requireAuth(request, env);
  if (!user) return redirect("/admin-app");
  const perms = await adminRolePermissions(env);
  const roles = ["Admin","Manager","Employee"];
  const blocks = roles.map(role => `<section class="form-section"><div class="form-title">${role} Permissions ${role==="Admin" ? '<span class="hint">Owner/admin full access is protected.</span>' : ''}</div><div class="permission-grid">${ADMIN_PERMISSION_LIST.map(([k,label]) => `<label class="perm-card"><input type="checkbox" name="${role}_${k}" value="1" ${role==="Admin" || (perms[role]||[]).includes(k) ? "checked" : ""} ${role==="Admin" ? "disabled" : ""}> <span>${escapeHtml(label)}</span></label>`).join("")}</div></section>`).join("");
  const body = `<main class="section admin-dashboard admin-roles-page"><div class="container"><div class="section-title"><h2>Role Permissions</h2><div class="btn-row"><a class="btn" href="/admin/users">Users</a><a class="btn" href="/admin/dashboard?app=1">Dashboard</a></div></div>${message}<form method="post" action="/admin/roles">${blocks}<button class="primary">Save Role Permissions</button></form></div></main>`;
  return htmlPage("Role Permissions | HB Commerce", layout(env, "Dashboard", body));
}

async function adminRolesPost(request, env) {
  const user = await requireAuth(request, env);
  if (!user) return redirect("/admin-app");
  const fd = await request.formData();
  const defaults = defaultRolePermissions();
  const next = { Admin: defaults.Admin };
  for (const role of ["Manager","Employee"]) next[role] = ADMIN_PERMISSION_LIST.filter(([k]) => fd.get(`${role}_${k}`)).map(([k]) => k);
  await setSetting(env, "admin_role_permissions_json", JSON.stringify(next));
  return adminRolesPage(request, env, `<div class="notice success">Role permissions saved.</div>`);
}

async function setupPage(request, env, error = "") {
  if (await userCount(env) > 0) return redirect("/admin/login");

  const expected = getSetupCode(env);
  const provided = setupCodeFromRequest(request);

  if (!expected) {
    const body = `<main class="section"><div class="container"><div class="form-section" style="max-width:760px;margin:auto"><div class="form-title">Admin Setup Locked</div><div class="notice error"><strong>SETUP_CODE is not configured yet.</strong><br>Set it from your project folder with:<br><br><code>npx wrangler secret put SETUP_CODE</code><br><br>Then redeploy and open <code>/setup?code=YOUR-CODE</code>.</div></div></div></main>`;
    return htmlPage("Admin Setup Locked | HB Commerce Solutions", layout(env, "Setup Locked", body));
  }

  if (provided !== expected) {
    const body = `<main class="section"><div class="container"><div class="form-section" style="max-width:620px;margin:auto"><div class="form-title">Private Admin Setup</div>${error ? `<div class="notice error">${escapeHtml(error)}</div>` : ""}<div class="notice">This setup page is protected. Enter your private setup code to create the first admin account.</div><form method="get" action="/setup"><div class="field"><label>Setup Code</label><input name="code" type="password" required autocomplete="off"></div><button class="primary">Unlock Setup</button></form></div></div></main>`;
    return htmlPage("Private Setup | HB Commerce Solutions", layout(env, "Private Setup", body));
  }

  const safeCode = escapeHtml(provided);
  const body = `<main class="section"><div class="container"><div class="form-section" style="max-width:720px;margin:auto"><div class="form-title">Create First Admin Account</div>${error ? `<div class="notice error">${escapeHtml(error)}</div>` : ""}<div class="notice success">Setup unlocked. Create your admin account. After the first admin is created, this setup page automatically closes.</div><form method="post" action="/setup"><input type="hidden" name="setup_code" value="${safeCode}"><div class="grid-2"><div class="field"><label>Admin Email / Username</label><input name="email" type="email" required></div><div class="field"><label>Admin Password</label><input name="password" type="password" minlength="8" required></div></div><button class="primary">Create Admin Account</button></form></div></div></main>`;
  return htmlPage("Admin Setup | HB Commerce Solutions", layout(env, "Setup", body));
}

async function setupPost(request, env) {
  if (await userCount(env) > 0) return redirect("/admin/login");
  const fd = await request.formData();
  if (!isSetupAuthorized(request, env, fd)) {
    return setupPage(request, env, "Invalid or missing setup code.");
  }
  const email = String(fd.get("email") || "").trim().toLowerCase();
  const password = String(fd.get("password") || "");
  if (!email || password.length < 8) return setupPage(request, env, "Enter a valid email and password with at least 8 characters.");
  const salt = randomHex(16);
  const iterations = 100000;
  const passwordHash = await hashPassword(password, salt, iterations);
  await env.DB.prepare("INSERT INTO users (id,email,password_hash,salt,iterations,created_at) VALUES (?,?,?,?,?,?)").bind(crypto.randomUUID(), email, passwordHash, salt, iterations, now()).run();
  return redirect("/admin/login?setup=1");
}

