async function loginPost(request, env) {
  const fd = await request.formData();
  const email = String(fd.get("email") || "").trim().toLowerCase();
  const password = String(fd.get("password") || "");
  const user = await env.DB.prepare("SELECT * FROM users WHERE email = ?").bind(email).first();
  if (!user) return loginPage(request, env, "Invalid email or password.");
  const hash = await hashPassword(password, user.salt, user.iterations);
  if (hash !== user.password_hash) return loginPage(request, env, "Invalid email or password.");
  const sid = randomHex(32);
  const expires = new Date(Date.now() + 7 * 24 * 3600 * 1000).toISOString();
  await env.DB.prepare("INSERT INTO sessions (id,user_id,expires_at,created_at) VALUES (?,?,?,?)").bind(sid, user.id, expires, now()).run();
  return redirect("/admin/dashboard?app=1", { "set-cookie": cookie("hb_sid", sid, 7 * 24 * 3600) });
}

async function logout(request, env) {
  const sid = getCookie(request, "hb_sid");
  if (sid) await env.DB.prepare("DELETE FROM sessions WHERE id = ?").bind(sid).run();
  return redirect("/admin-app?loggedout=1", { "set-cookie": cookie("hb_sid", "", 0) });
}

async function requireAuth(request, env) {
  if (await userCount(env) === 0) return null;
  const sid = getCookie(request, "hb_sid");
  if (!sid) return null;
  const session = await env.DB.prepare("SELECT sessions.*, users.email FROM sessions JOIN users ON users.id = sessions.user_id WHERE sessions.id = ?").bind(sid).first();
  if (!session) return null;
  if (new Date(session.expires_at).getTime() < Date.now()) {
    await env.DB.prepare("DELETE FROM sessions WHERE id = ?").bind(sid).run();
    return null;
  }
  return session;
}

async function adminOnlineOrdersPage(request, env, message = '', docType = 'OnlineOrder') {
  const user = await requireAuth(request, env);
  if (!user) return redirect('/admin-app');

  const isQuoteOrder = docType === 'OnlineQuoteOrder';
  const basePath = isQuoteOrder ? '/admin/quote-orders' : '/admin/orders';
  const pageTitle = isQuoteOrder ? 'Online Quote Orders' : 'Online Orders';
  const pageSubtitle = isQuoteOrder
    ? 'LTS and quote-only hardware requests are separated here so Admin can add cost/sale price, finalize the quote, and email it to the client.'
    : 'eufy checkout orders are listed here with ZipTax destination tax on priced products when available.';

  const url = new URL(request.url);
  const selectedId = url.searchParams.get('id') || '';
  const res = await env.DB.prepare("SELECT id,type,number,business,customer_name,email,phone,status,paid,total,updated_at,data_json FROM documents WHERE type=? ORDER BY updated_at DESC LIMIT 500").bind(docType).all();
  const orders = (res.results || []).map(row => {
    let detail = {};
    try { detail = JSON.parse(row.data_json || '{}'); } catch {}
    return { ...row, detail };
  });
  const pending = orders.filter(o => o.status !== 'Converted to Quote' && o.status !== 'Canceled' && !o.detail.canceled_at && !o.detail.deleted_at);
  const selected = selectedId ? orders.find(o => o.id === selectedId) : (pending[0] || orders[0]);
  const queryMsg = url.searchParams.get('converted') ? `<div class="notice success">${isQuoteOrder ? 'Online quote order' : 'Online order'} converted to quote. Review, revise, then use Save and Email when ready.</div>` : url.searchParams.get('canceled') ? `<div class="notice success">${isQuoteOrder ? 'Online quote order' : 'Online order'} was canceled/deleted and the customer notification was ${url.searchParams.get('email') === 'sent' ? 'sent' : 'not sent'}.</div>` : '';
  const listRows = (orders.length ? orders : []).map(o => {
    const active = selected && selected.id === o.id;
    const d = o.detail || {};
    const count = (d.items || []).reduce((a,it)=>a+(parseInt(it.qty)||0),0);
    return `<a class="online-order-list-item ${active ? 'active' : ''}" href="${basePath}?id=${encodeURIComponent(o.id)}"><strong>${escapeHtml(o.number)}</strong><span>${escapeHtml(o.customer_name || '')}</span><small>${count} item${count===1?'':'s'} · ${money(o.total || 0)} · ${escapeHtml(o.status || (isQuoteOrder ? 'New Quote Order' : 'New Order'))}</small></a>`;
  }).join('') || `<div class="notice">No ${isQuoteOrder ? 'online quote orders' : 'online orders'} yet.</div>`;
  const detail = selected ? selected.detail || {} : null;
  const items = detail && Array.isArray(detail.items) ? detail.items : [];
  const totals = detail ? calcTotals(detail) : { subtotal: 0, tax: 0, total: 0 };
  const itemRows = items.map(it => {
    const quoteItem = Number(regularUnit(it)) <= 0 && (it.source === 'lts' || String(it.desc || '').includes('Pricing to be confirmed'));
    const couponText = quoteItem ? 'Pricing to be quoted' : (it.coupon_applied ? ('Coupon ' + (it.coupon_code || '') + ' applied') : 'No coupon applied');
    return `<tr><td>${escapeHtml(it.name || '')}<br><span class="hint">${escapeHtml(couponText)}</span></td><td>${parseInt(it.qty || 0) || 0}</td><td>${quoteItem ? 'Quote' : money(regularUnit(it))}</td><td>${quoteItem ? 'Quote' : money(Number(it.discount || 0))}</td><td>${quoteItem ? 'Quote' : money(lineTotal(it))}</td></tr>`;
  }).join('') || `<tr><td colspan="5">No items found.</td></tr>`;
  const orderInfo = detail && detail.eufy_order ? detail.eufy_order : {};
  const shipping = orderInfo.shipping || {};
  const billing = orderInfo.billing || {};
  const converted = detail && detail.converted_to_quote_id;
  const finalSaleNoticeHtml = detail && detail.final_sale_notice_ack ? `<div class="notice warning"><strong>Customer final-sale notice:</strong> OK acknowledged at checkout.<br>${escapeHtml(detail.final_sale_notice_text || '')}</div>` : '';
  const detailHtml = selected ? `<section class="form-section online-order-detail"><div class="form-title">${isQuoteOrder ? 'Quote Order Detail' : 'Order Detail'}</div><div class="grid-2"><div><h3>${escapeHtml(selected.number)}</h3><p><strong>${escapeHtml(selected.customer_name || '')}</strong><br>${escapeHtml(selected.email || '')}<br>${escapeHtml(selected.phone || '')}</p><p><strong>Payment preference:</strong> ${escapeHtml(detail.payment_preference || orderInfo.payment_preference || '')}<br><strong>Fulfillment:</strong> ${escapeHtml(orderInfo.fulfillment_type || detail.fulfillment_type || 'shipping')}<br><strong>Shipping cost:</strong> ${money(detail.shipping_cost || orderInfo.shipping_cost || 0)}</p><p><strong>Status:</strong> ${escapeHtml(selected.status || (isQuoteOrder ? 'New Quote Order' : 'New Order'))}</p>${(selected.status === 'Canceled' || detail.canceled_at) ? `<div class="notice warning"><strong>Cancel Reason:</strong><br>${escapeHtml(detail.canceled_reason || 'No reason saved.')}</div>` : ''}</div><div><h4>Shipping Address</h4><p>${escapeHtml(shipping.street || detail.street || '')}<br>${escapeHtml(shipping.city || detail.city || '')}, ${escapeHtml(shipping.state || detail.state || '')} ${escapeHtml(shipping.zip || detail.zip || '')}</p><h4>Billing Address</h4><p>${escapeHtml(billing.street || '')}<br>${escapeHtml(billing.city || '')}, ${escapeHtml(billing.state || '')} ${escapeHtml(billing.zip || '')}</p></div></div><div class="table-wrap"><table><thead><tr><th>Item</th><th>Qty</th><th>Regular</th><th>Discount</th><th>Line Total</th></tr></thead><tbody>${itemRows}</tbody></table></div><div class="totals-card online-order-totals"><div class="total-row"><span>Subtotal</span><span>${money(totals.subtotal)}</span></div><div class="total-row"><span>Sales Tax (10%)</span><span>${money(totals.tax)}</span></div><div class="total-row grand"><span>Total</span><span>${money(totals.total)}</span></div></div><div class="notice tax-final-note"><strong>Tax workflow:</strong> eufy priced products use ZipTax destination tax when available. Check/Zelle orders stay pending here; credit card orders can be paid online.</div>${finalSaleNoticeHtml}<div class="btn-row">${converted ? `<a class="btn green" href="/admin/document?id=${encodeURIComponent(detail.converted_to_quote_id)}">Open Converted Quote ${escapeHtml(detail.converted_to_quote_number || '')}</a>` : `<a class="btn orange" href="/admin/orders/convert?id=${encodeURIComponent(selected.id)}" onclick="return confirm('Convert this ${isQuoteOrder ? 'online quote order' : 'online order'} into a quote for review?')">Convert to Quote</a>`}<a class="btn" target="_blank" href="${isQuoteOrder ? '/security-camera-systems/lts-dvr-nvr' : '/security-camera-systems/eufy-poe-nvr-camera-systems'}">${isQuoteOrder ? 'View LTS Pages' : 'View eufy Page'}</a>${(selected.status !== 'Canceled' && !detail.canceled_at) ? `<a class="btn danger" href="/admin/orders/cancel?id=${encodeURIComponent(selected.id)}">Cancel/Delete ${isQuoteOrder ? 'Quote Order' : 'Order'}</a>` : ''}</div></section>` : `<section class="form-section"><div class="notice">Select a ${isQuoteOrder ? 'quote order' : 'online order'} from the list.</div></section>`;
  const body = `<main class="section admin-dashboard admin-orders-page"><div class="container"><div class="section-title"><h2>${pageTitle}</h2><div class="btn-row"><a class="btn" href="/admin/dashboard?app=1">Dashboard</a><a class="btn" href="/admin/orders">Online Orders</a><a class="btn" href="/admin/quote-orders">Online Quote Orders</a><a class="btn" href="${isQuoteOrder ? '/admin/lts' : '/admin/eufy'}">${isQuoteOrder ? 'LTS Manager' : 'EUFY Manager'}</a></div></div>${message || queryMsg}<div class="notice">${escapeHtml(pageSubtitle)}</div><div class="online-orders-grid"><aside class="online-orders-list"><div class="online-orders-head"><strong>${isQuoteOrder ? 'Quote Orders' : 'Orders'}</strong><span>${pending.length} pending</span></div>${listRows}</aside>${detailHtml}</div></div></main>`;
  return htmlPage(`${pageTitle} | HB Commerce`, layout(env, 'Dashboard', body));
}


async function adminCancelOnlineOrderPage(request, env, message = "") {
  const user = await requireAuth(request, env);
  if (!user) return redirect("/admin-app");
  const id = new URL(request.url).searchParams.get("id") || "";
  const order = id ? await getDoc(env, id) : null;
  if (!order || !["OnlineOrder","OnlineQuoteOrder"].includes(order.type)) return redirect("/admin/orders");
  const basePath = order.type === "OnlineQuoteOrder" ? "/admin/quote-orders" : "/admin/orders";
  const label = order.type === "OnlineQuoteOrder" ? "Online Quote Order" : "Online Order";
  const body = `<main class="section admin-dashboard admin-orders-page"><div class="container"><div class="section-title"><h2>Cancel / Delete ${escapeHtml(label)}</h2><div class="btn-row"><a class="btn" href="${basePath}?id=${encodeURIComponent(id)}">Back to ${escapeHtml(label)}</a><a class="btn" href="/admin/dashboard?app=1">Dashboard</a></div></div>${message}<section class="form-section"><div class="form-title">Cancel Order ${escapeHtml(order.number || "")}</div><div class="notice warning"><strong>This will mark the online request as canceled/deleted.</strong> Enter the reason below. If email is configured and the customer has an email address, the customer will receive this reason by email.</div><form method="post" action="/admin/orders/cancel"><input type="hidden" name="id" value="${escapeHtml(id)}"><div class="field"><label>Reason for canceling/deleting this order</label><textarea name="reason" required placeholder="Example: Product is not available / discontinued / cannot fulfill this order."></textarea></div><div class="btn-row"><button class="danger" onclick="return confirm('Cancel/delete this online order and notify the customer?')">Cancel/Delete Order and Notify Customer</button><a class="btn" href="${basePath}?id=${encodeURIComponent(id)}">Keep ${escapeHtml(label)}</a></div></form></section></div></main>`;
  return htmlPage("Cancel Online Order | HB Commerce", layout(env, "Dashboard", body));
}

async function adminCancelOnlineOrderPost(request, env) {
  const user = await requireAuth(request, env);
  if (!user) return redirect("/admin-app");
  const fd = await request.formData();
  const id = String(fd.get("id") || "").trim();
  const reason = String(fd.get("reason") || "").trim();
  const order = id ? await getDoc(env, id) : null;
  if (!order || !["OnlineOrder","OnlineQuoteOrder"].includes(order.type)) return redirect("/admin/orders");
  const basePath = order.type === "OnlineQuoteOrder" ? "/admin/quote-orders" : "/admin/orders";
  if (!reason) return adminCancelOnlineOrderPage(request, env, `<div class="notice error">Please enter a reason before canceling/deleting the order.</div>`);
  order.status = "Canceled";
  order.canceled_at = now();
  order.deleted_at = now();
  order.canceled_by = user.email || "Admin";
  order.canceled_reason = reason;
  order.updated_at = now();
  let emailSent = false;
  if (env.RESEND_API_KEY && order.email) {
    emailSent = await sendEmail(env, {
      to: order.email,
      subject: `HB Commerce Solutions Order ${order.number || ""} Canceled`,
      html: `<p>Hello ${escapeHtml(order.customer_name || "Customer")},</p><p>Your online order request <strong>${escapeHtml(order.number || "")}</strong> has been canceled.</p><p><strong>Reason:</strong><br>${escapeHtml(reason).replaceAll("\\n","<br>")}</p><p>If you have any questions, please reply to this email or contact HB Commerce Solutions.</p><p>Thank you,<br>HB Commerce Solutions</p>`
    }).catch(err => {
      console.error("online order cancel email failed", err);
      return false;
    });
  }
  order.cancel_email_sent = emailSent ? now() : "";
  await saveDoc(env, order);
  return redirect(`${basePath}?canceled=1&email=${emailSent ? "sent" : "not_sent"}`);
}

async function adminConvertOnlineOrder(request, env) {
  const user = await requireAuth(request, env);
  if (!user) return redirect('/admin-app');
  const id = new URL(request.url).searchParams.get('id') || '';
  const order = id ? await getDoc(env, id) : null;
  if (!order || !['OnlineOrder','OnlineQuoteOrder'].includes(order.type)) return redirect('/admin/orders');
  const basePath = order.type === 'OnlineQuoteOrder' ? '/admin/quote-orders' : '/admin/orders';
  if (order.converted_to_quote_id) return redirect(`/admin/document?id=${encodeURIComponent(order.converted_to_quote_id)}`);
  const e = order.eufy_order || {};
  const ship = e.shipping || { street: order.shipping_street || order.street, city: order.shipping_city || order.city, state: order.shipping_state || order.state, zip: order.shipping_zip || order.zip };
  const bill = e.billing || { street: order.billing_street || order.street, city: order.billing_city || order.city, state: order.billing_state || order.state, zip: order.billing_zip || order.zip };
  const taxInfo = await taxForItems(env, ship, order.items || []);
  const quote = JSON.parse(JSON.stringify(order));
  quote.billing_street = bill.street || "";
  quote.billing_city = bill.city || "";
  quote.billing_state = cleanStateCode(bill.state || "");
  quote.billing_zip = bill.zip || "";
  quote.shipping_street = ship.street || "";
  quote.shipping_city = ship.city || "";
  quote.shipping_state = cleanStateCode(ship.state || "");
  quote.shipping_zip = ship.zip || "";
  quote.shipping_same_as_billing = addressObjectsEqual(
    { street: quote.billing_street, city: quote.billing_city, state: quote.billing_state, zip: quote.billing_zip },
    { street: quote.shipping_street, city: quote.shipping_city, state: quote.shipping_state, zip: quote.shipping_zip }
  ) ? 1 : 0;
  quote.street = quote.shipping_street;
  quote.city = quote.shipping_city;
  quote.state = quote.shipping_state;
  quote.zip = quote.shipping_zip;
  quote.id = randomId();
  quote.token = randomHex(16);
  quote.type = 'Quote';
  quote.number = nextDocNumber('Quote');
  quote.doc_date = today();
  quote.valid_until = plusDays(7);
  quote.prepared_by = order.type === 'OnlineQuoteOrder' ? 'HB Commerce Online Quote Order Review' : 'HB Commerce Online Order Review';
  quote.status = 'Draft';
  quote.paid = 0;
  quote.tax_rate = Number(taxInfo.rate || 0);
  quote.tax_source = taxInfo.source || '';
  quote.tax_exact = !!taxInfo.exact;
  quote.tax_county = taxInfo.county || (taxInfo.jurisdictions && taxInfo.jurisdictions.county) || '';
  quote.tax_city = taxInfo.city || '';
  quote.tax_state = taxInfo.state || '';
  quote.tax_amount_preview = Number(taxInfo.tax_amount || 0);
  quote.online_order_id = order.id;
  quote.online_order_number = order.number;
  quote.customer_notes = `Converted from ${order.type === 'OnlineQuoteOrder' ? 'online quote order' : 'online order'} ${order.number}. Preferred payment option: ${order.payment_preference || (e.payment_preference || '')}. Tax rate: fixed 10% HB Commerce company tax rate. Hardware ships only after approval and payment is received/cleared.`;
  quote.created_at = now();
  quote.updated_at = now();
  await saveDoc(env, quote);
  order.status = 'Converted to Quote';
  order.converted_at = now();
  order.converted_to_quote_id = quote.id;
  order.converted_to_quote_number = quote.number;
  await saveDoc(env, order);
  return redirect(`/admin/document?id=${encodeURIComponent(quote.id)}&from_order=1`);
}


function b64UrlEncodeBytes(bytes) {
  let bin = "";
  const arr = bytes instanceof Uint8Array ? bytes : new Uint8Array(bytes);
  for (let i = 0; i < arr.length; i += 0x8000) bin += String.fromCharCode(...arr.subarray(i, i + 0x8000));
  return btoa(bin).replaceAll("+","-").replaceAll("/","_").replaceAll("=","");
}

function b64UrlEncodeString(s) {
  return b64UrlEncodeBytes(new TextEncoder().encode(s));
}

function b64UrlToBytes(s) {
  s = String(s || "").replaceAll("-","+").replaceAll("_","/");
  while (s.length % 4) s += "=";
  const bin = atob(s);
  const out = new Uint8Array(bin.length);
  for (let i=0;i<bin.length;i++) out[i] = bin.charCodeAt(i);
  return out;
}

function jwkPublicToVapidPublicKey(jwk) {
  const x = b64UrlToBytes(jwk.x);
  const y = b64UrlToBytes(jwk.y);
  const out = new Uint8Array(65);
  out[0] = 4;
  out.set(x, 1);
  out.set(y, 33);
  return b64UrlEncodeBytes(out);
}

function derEcdsaToJose(signature) {
  const bytes = signature instanceof Uint8Array ? signature : new Uint8Array(signature);
  if (bytes.length === 64) return bytes;
  // DER encoded ECDSA signature: 30 len 02 rLen r 02 sLen s
  if (bytes[0] !== 0x30) return bytes.slice(0, 64);
  let idx = 2;
  if (bytes[1] & 0x80) idx = 2 + (bytes[1] & 0x7f);
  if (bytes[idx++] !== 0x02) return bytes.slice(0, 64);
  let rLen = bytes[idx++];
  let r = bytes.slice(idx, idx + rLen); idx += rLen;
  if (bytes[idx++] !== 0x02) return bytes.slice(0, 64);
  let sLen = bytes[idx++];
  let s = bytes.slice(idx, idx + sLen);
  if (r.length > 32) r = r.slice(r.length - 32);
  if (s.length > 32) s = s.slice(s.length - 32);
  const out = new Uint8Array(64);
  out.set(r, 32 - r.length);
  out.set(s, 64 - s.length);
  return out;
}

async function ensureVapidKeys(env) {
  let pub = await getSetting(env, "webpush_public_jwk", "");
  let priv = await getSetting(env, "webpush_private_jwk", "");
  if (pub && priv) {
    try {
      const publicJwk = JSON.parse(pub);
      const privateJwk = JSON.parse(priv);
      return { publicJwk, privateJwk, publicKey: jwkPublicToVapidPublicKey(publicJwk) };
    } catch {}
  }
  const pair = await crypto.subtle.generateKey({ name: "ECDSA", namedCurve: "P-256" }, true, ["sign", "verify"]);
  const publicJwk = await crypto.subtle.exportKey("jwk", pair.publicKey);
  const privateJwk = await crypto.subtle.exportKey("jwk", pair.privateKey);
  await setSetting(env, "webpush_public_jwk", JSON.stringify(publicJwk));
  await setSetting(env, "webpush_private_jwk", JSON.stringify(privateJwk));
  return { publicJwk, privateJwk, publicKey: jwkPublicToVapidPublicKey(publicJwk) };
}

async function makeVapidJwt(env, endpoint) {
  const { privateJwk, publicKey } = await ensureVapidKeys(env);
  const aud = new URL(endpoint).origin;
  const sub = `mailto:${extractEmailFromHeader(env.EMAIL_FROM) || env.EMAIL_BCC || "info@hbcommercesolution.com"}`;
  const header = b64UrlEncodeString(JSON.stringify({ typ:"JWT", alg:"ES256" }));
  const payload = b64UrlEncodeString(JSON.stringify({ aud, exp: Math.floor(Date.now()/1000) + 12*60*60, sub }));
  const key = await crypto.subtle.importKey("jwk", privateJwk, { name:"ECDSA", namedCurve:"P-256" }, false, ["sign"]);
  const signature = await crypto.subtle.sign({ name:"ECDSA", hash:"SHA-256" }, key, new TextEncoder().encode(`${header}.${payload}`));
  return { jwt: `${header}.${payload}.${b64UrlEncodeBytes(derEcdsaToJose(new Uint8Array(signature)))}`, publicKey };
}

async function hmacSha256Raw(keyBytes, dataBytes) {
  const key = await crypto.subtle.importKey("raw", keyBytes, { name: "HMAC", hash: "SHA-256" }, false, ["sign"]);
  return new Uint8Array(await crypto.subtle.sign("HMAC", key, dataBytes));
}

async function hkdfExtractRaw(salt, ikm) {
  return await hmacSha256Raw(salt, ikm);
}

async function hkdfExpandRaw(prk, info, len) {
  let prev = new Uint8Array(0);
  let out = new Uint8Array(0);
  let counter = 1;
  while (out.length < len) {
    const input = new Uint8Array(prev.length + info.length + 1);
    input.set(prev, 0);
    input.set(info, prev.length);
    input[input.length - 1] = counter++;
    prev = await hmacSha256Raw(prk, input);
    const next = new Uint8Array(out.length + prev.length);
    next.set(out, 0);
    next.set(prev, out.length);
    out = next;
  }
  return out.slice(0, len);
}

function concatBytes(...parts) {
  const total = parts.reduce((s, p) => s + p.length, 0);
  const out = new Uint8Array(total);
  let offset = 0;
  for (const p of parts) {
    out.set(p, offset);
    offset += p.length;
  }
  return out;
}

async function webPushEncryptPayload(subscription, payloadText) {
  if (!subscription || !subscription.keys || !subscription.keys.p256dh || !subscription.keys.auth) throw new Error("Push subscription missing encryption keys.");
  const receiverPublic = b64UrlToBytes(subscription.keys.p256dh);
  const authSecret = b64UrlToBytes(subscription.keys.auth);
  const appServerKeys = await crypto.subtle.generateKey({ name: "ECDH", namedCurve: "P-256" }, true, ["deriveBits"]);
  const appServerPublic = new Uint8Array(await crypto.subtle.exportKey("raw", appServerKeys.publicKey));
  const receiverKey = await crypto.subtle.importKey("raw", receiverPublic, { name: "ECDH", namedCurve: "P-256" }, false, []);
  const sharedSecret = new Uint8Array(await crypto.subtle.deriveBits({ name: "ECDH", public: receiverKey }, appServerKeys.privateKey, 256));
  const webPushInfo = concatBytes(new TextEncoder().encode("WebPush: info"), new Uint8Array([0]), receiverPublic, appServerPublic);
  const prkKey = await hkdfExtractRaw(authSecret, sharedSecret);
  const ikm = await hkdfExpandRaw(prkKey, webPushInfo, 32);
  const salt = crypto.getRandomValues(new Uint8Array(16));
  const prk = await hkdfExtractRaw(salt, ikm);
  const cek = await hkdfExpandRaw(prk, new TextEncoder().encode("Content-Encoding: aes128gcm\0"), 16);
  const nonce = await hkdfExpandRaw(prk, new TextEncoder().encode("Content-Encoding: nonce\0"), 12);
  const payloadBytes = new TextEncoder().encode(payloadText || "{}");
  const plain = new Uint8Array(payloadBytes.length + 1);
  plain.set(payloadBytes, 0);
  plain[plain.length - 1] = 2; // final record delimiter
  const aesKey = await crypto.subtle.importKey("raw", cek, { name: "AES-GCM" }, false, ["encrypt"]);
  const cipher = new Uint8Array(await crypto.subtle.encrypt({ name: "AES-GCM", iv: nonce, tagLength: 128 }, aesKey, plain));
  const header = new Uint8Array(16 + 4 + 1 + appServerPublic.length);
  header.set(salt, 0);
  const rs = 4096;
  header[16] = (rs >>> 24) & 255;
  header[17] = (rs >>> 16) & 255;
  header[18] = (rs >>> 8) & 255;
  header[19] = rs & 255;
  header[20] = appServerPublic.length;
  header.set(appServerPublic, 21);
  return concatBytes(header, cipher);
}

async function getPushSubscriptions(env) {
  try {
    const raw = await getSetting(env, "webpush_subscriptions", "[]");
    const arr = JSON.parse(raw || "[]");
    return Array.isArray(arr) ? arr.filter(s => s && s.endpoint) : [];
  } catch {
    return [];
  }
}

async function savePushSubscriptions(env, subs) {
  const clean = [];
  const seen = new Set();
  for (const s of subs || []) {
    if (!s || !s.endpoint || seen.has(s.endpoint)) continue;
    seen.add(s.endpoint);
    clean.push(s);
  }
  await setSetting(env, "webpush_subscriptions", JSON.stringify(clean.slice(-10)));
}

async function sendWebPushNotification(env, title, message, link = "") {
  const subs = await getPushSubscriptions(env);
  if (!subs.length) return { attempted: 0, sent: 0, errors: ["No Admin Portal app device is subscribed yet. Open Admin > Notifications on the device and tap Enable App Push."] };
  const errors = [];
  let sent = 0;
  const keep = [];
  for (const sub of subs) {
    try {
      const { jwt, publicKey } = await makeVapidJwt(env, sub.endpoint);
      // Use no-payload push for maximum reliability. The service worker displays a generic secure alert.
      // This avoids device-specific payload encryption issues and keeps details inside the private Admin Portal.
      const res = await fetch(sub.endpoint, {
        method: "POST",
        headers: {
          "Authorization": `vapid t=${jwt}, k=${publicKey}`,
          "Crypto-Key": `p256ecdsa=${publicKey}`,
          "TTL": "86400",
          "Urgency": "high",
          "Topic": "hb-admin-alert"
        }
      });
      if (res.status === 404 || res.status === 410) {
        errors.push("Removed expired push subscription.");
        continue;
      }
      if (!res.ok) {
        const txt = await res.text().catch(() => "");
        errors.push(`Push endpoint failed ${res.status}: ${txt.slice(0, 260)}`);
        keep.push(sub);
        continue;
      }
      sent++;
      keep.push(sub);
    } catch (err) {
      errors.push(err.message || String(err));
      keep.push(sub);
    }
  }
  if (keep.length !== subs.length) await savePushSubscriptions(env, keep);
  return { attempted: subs.length, sent, errors };
}

function adminPushServiceWorker() {
  const js = `const HB_ADMIN_PUSH_VERSION = '116';
self.addEventListener('install', function(event) {
  self.skipWaiting();
});
self.addEventListener('activate', function(event) {
  event.waitUntil(self.clients.claim());
});
self.addEventListener('push', function(event) {
  var title = 'HB Commerce Admin Alert';
  var options = {
    body: 'New admin update received. Open the Admin Portal to view details.',
    icon: '/assets/hb-app-icon-v33-192.png',
    badge: '/assets/hb-favicon-v33.png',
    tag: 'hb-admin-alert',
    renotify: true,
    data: { url: '/admin/dashboard?app=1' }
  };
  if (event.data) {
    try {
      var data = event.data.json();
      title = data.title || title;
      options.body = data.body || options.body;
      options.data.url = data.url || options.data.url;
    } catch(e) {
      try { options.body = event.data.text() || options.body; } catch(ignore) {}
    }
  }
  event.waitUntil(self.registration.showNotification(title, options));
});
self.addEventListener('notificationclick', function(event) {
  event.notification.close();
  var url = (event.notification.data && event.notification.data.url) || '/admin/dashboard?app=1';
  event.waitUntil(clients.matchAll({ type:'window', includeUncontrolled:true }).then(function(list) {
    for (var i=0;i<list.length;i++) {
      var client = list[i];
      if (client.url.indexOf('/admin') !== -1 && 'focus' in client) return client.focus();
    }
    return clients.openWindow(url);
  }));
});`;
  return new Response(js, { headers: { "content-type": "application/javascript; charset=utf-8", "cache-control": "no-store, no-cache, must-revalidate" } });
}

async function adminPushPublicKey(request, env) {
  const user = await requireAuth(request, env);
  if (!user) return jsonResponse({ error: "Unauthorized" }, 401);
  const { publicKey } = await ensureVapidKeys(env);
  return jsonResponse({ publicKey });
}

async function adminPushSubscribe(request, env) {
  const user = await requireAuth(request, env);
  if (!user) return jsonResponse({ error: "Unauthorized" }, 401);
  const sub = await request.json().catch(() => null);
  if (!sub || !sub.endpoint) return jsonResponse({ error: "Invalid push subscription." }, 400);
  const subs = await getPushSubscriptions(env);
  const filtered = subs.filter(s => s.endpoint !== sub.endpoint);
  filtered.push({ ...sub, admin_email: user.email || "", created_at: now(), label: "Admin Portal App" });
  await savePushSubscriptions(env, filtered);
  return jsonResponse({ ok: true, count: filtered.length });
}

async function adminPushTest(request, env) {
  const user = await requireAuth(request, env);
  if (!user) return jsonResponse({ error: "Unauthorized" }, 401);
  const origin = new URL(request.url).origin;
  const result = await sendWebPushNotification(env, "Test Notification", "This is a test app push alert from HB Commerce Admin Portal.", `${origin}/admin/dashboard?app=1`);
  return jsonResponse({ ok: result.sent > 0, ...result });
}


async function getIosApnsDevices(env) {
  try {
    const raw = await getSetting(env, "ios_apns_devices", "[]");
    const arr = JSON.parse(raw || "[]");
    return Array.isArray(arr) ? arr.filter(d => d && d.token) : [];
  } catch {
    return [];
  }
}

async function saveIosApnsDevices(env, devices) {
  const clean = [];
  const seen = new Set();
  for (const d of devices || []) {
    const token = String(d.token || "").replace(/[^a-fA-F0-9]/g, "");
    if (!token || seen.has(token)) continue;
    seen.add(token);
    clean.push({
      token,
      label: String(d.label || "HB Commerce Admin iPhone").slice(0, 80),
      platform: String(d.platform || "iOS").slice(0, 20),
      appVersion: String(d.appVersion || "").slice(0, 30),
      admin_email: String(d.admin_email || "").slice(0, 120),
      created_at: d.created_at || now(),
      updated_at: d.updated_at || now()
    });
  }
  await setSetting(env, "ios_apns_devices", JSON.stringify(clean.slice(-10)));
  return clean;
}

async function adminIosDeviceRegister(request, env) {
  const user = await requireAuth(request, env);
  if (!user) return jsonResponse({ ok: false, error: "Unauthorized" }, 401);
  const body = await request.json().catch(() => ({}));
  const token = String(body.token || "").replace(/[^a-fA-F0-9]/g, "");
  if (!token || token.length < 32) return jsonResponse({ ok: false, error: "Invalid APNs device token." }, 400);
  const devices = await getIosApnsDevices(env);
  const filtered = devices.filter(d => d.token !== token);
  filtered.push({
    token,
    label: String(body.label || "HB Commerce Admin iPhone"),
    platform: "iOS",
    appVersion: String(body.appVersion || ""),
    admin_email: user.email || "",
    created_at: now(),
    updated_at: now()
  });
  const saved = await saveIosApnsDevices(env, filtered);
  return jsonResponse({ ok: true, count: saved.length });
}

async function adminIosDeviceTest(request, env) {
  const user = await requireAuth(request, env);
  if (!user) return jsonResponse({ ok: false, error: "Unauthorized" }, 401);
  const origin = new URL(request.url).origin;
  const result = await sendIosNativePushNotification(env, "HB Commerce Admin", "Native iOS test notification sent from the Admin Portal.", `${origin}/admin/dashboard?app=1`);
  return jsonResponse({ ok: result.sent > 0, ...result });
}

function pemToArrayBuffer(pem) {
  const clean = String(pem || "")
    .replace("-----BEGIN PRIVATE KEY-----", "")
    .replace("-----END PRIVATE KEY-----", "")
    .replace(/\s+/g, "");
  const bin = atob(clean);
  const out = new Uint8Array(bin.length);
  for (let i = 0; i < bin.length; i++) out[i] = bin.charCodeAt(i);
  return out.buffer;
}

async function getApnsPrivateKey(env) {
  const base64 = String(env.APNS_KEY_BASE64 || await getSetting(env, "apns_key_base64", "") || "").trim();
  if (!base64) throw new Error("APNS_KEY_BASE64 is not configured.");
  const pem = atob(base64);
  return crypto.subtle.importKey("pkcs8", pemToArrayBuffer(pem), { name: "ECDSA", namedCurve: "P-256" }, false, ["sign"]);
}

async function makeApnsJwt(env) {
  const keyId = String(env.APNS_KEY_ID || await getSetting(env, "apns_key_id", "") || "").trim();
  const teamId = String(env.APPLE_TEAM_ID || await getSetting(env, "apple_team_id", "") || "").trim();
  if (!keyId) throw new Error("APNS_KEY_ID is not configured.");
  if (!teamId) throw new Error("APPLE_TEAM_ID is not configured.");
  const header = b64UrlEncodeString(JSON.stringify({ alg: "ES256", kid: keyId }));
  const payload = b64UrlEncodeString(JSON.stringify({ iss: teamId, iat: Math.floor(Date.now() / 1000) }));
  const key = await getApnsPrivateKey(env);
  const sig = new Uint8Array(await crypto.subtle.sign({ name: "ECDSA", hash: "SHA-256" }, key, new TextEncoder().encode(`${header}.${payload}`)));
  return `${header}.${payload}.${b64UrlEncodeBytes(derEcdsaToJose(sig))}`;
}

async function sendApnsToToken(env, token, title, body, link = "") {
  const bundleId = String(env.IOS_BUNDLE_ID || await getSetting(env, "ios_bundle_id", "com.hbcommerce.admin") || "com.hbcommerce.admin").trim();
  const apnsJwt = await makeApnsJwt(env);
  const production = String(env.APNS_ENV || await getSetting(env, "apns_env", "production") || "production") !== "sandbox";
  const host = production ? "https://api.push.apple.com" : "https://api.sandbox.push.apple.com";
  const payload = {
    aps: {
      alert: { title: title || "HB Commerce Admin", body: body || "New admin update received." },
      sound: "default",
      badge: 1
    },
    url: link || "/admin/dashboard?app=1"
  };
  const res = await fetch(`${host}/3/device/${token}`, {
    method: "POST",
    headers: {
      "authorization": `bearer ${apnsJwt}`,
      "apns-topic": bundleId,
      "apns-push-type": "alert",
      "apns-priority": "10",
      "content-type": "application/json"
    },
    body: JSON.stringify(payload)
  });
  const text = await res.text().catch(() => "");
  if (!res.ok) {
    let reason = text;
    try { reason = JSON.parse(text).reason || text; } catch {}
    return { ok: false, status: res.status, error: reason || `APNs HTTP ${res.status}` };
  }
  return { ok: true, status: res.status, error: "" };
}

async function sendIosNativePushNotification(env, title, message, link = "") {
  const devices = await getIosApnsDevices(env);
  if (!devices.length) return { attempted: 0, sent: 0, errors: ["No native iOS app devices are registered yet. Open the iOS app, log in, and allow notifications."] };
  let sent = 0;
  const errors = [];
  const keep = [];
  for (const d of devices) {
    try {
      const result = await sendApnsToToken(env, d.token, title, message, link);
      if (result.ok) {
        sent++;
        keep.push({ ...d, last_push_at: now() });
      } else if (result.status === 400 && (String(result.error).includes("BadDeviceToken") || String(result.error).includes("Unregistered"))) {
        errors.push(`${d.label || "iOS device"} removed: ${result.error}`);
      } else {
        errors.push(`${d.label || "iOS device"}: ${result.error}`);
        keep.push(d);
      }
    } catch (err) {
      errors.push(`${d.label || "iOS device"}: ${err.message || String(err)}`);
      keep.push(d);
    }
  }
  if (keep.length !== devices.length) await saveIosApnsDevices(env, keep);
  return { attempted: devices.length, sent, errors };
}


async function sendAdminMobileNotification(env, title, message, link = "") {
  const ios = await sendIosNativePushNotification(env, title, message, link).catch(err => ({ attempted: 0, sent: 0, errors: [err.message || String(err)] }));
  const web = await sendWebPushNotification(env, title, message, link).catch(err => ({ attempted: 0, sent: 0, errors: [err.message || String(err)] }));
  return { ...web, iosAttempted: ios.attempted, iosSent: ios.sent, iosErrors: ios.errors || [] };
}

function defaultAdminTodos() {
  return [
    { id: randomId(), text: "Review new online orders", done: false, due: "", reminder: 30, created_at: now() },
    { id: randomId(), text: "Follow up on Quote", done: false, due: "", reminder: 30, created_at: now() },
    { id: randomId(), text: "Follow up on open invoices", done: false, due: "", reminder: 30, created_at: now() },
    { id: randomId(), text: "Review merchant applications", done: false, due: "", reminder: 30, created_at: now() },
    { id: randomId(), text: "Verify LTS/EUFY product images", done: false, due: "", reminder: 30, created_at: now() }
  ];
}

function cleanAdminTodos(items) {
  const arr = Array.isArray(items) ? items : [];
  return arr.slice(0, 100).map(t => ({
    id: String(t.id || randomId()),
    text: String(t.text || "").trim().slice(0, 180),
    done: !!t.done,
    due: String(t.due || "").trim().slice(0, 32),
    reminder: Math.max(0, Math.min(10080, parseInt(t.reminder || 30, 10) || 0)),
    created_at: String(t.created_at || now())
  })).filter(t => t.text);
}

async function getAdminTodos(env) {
  try {
    const raw = await getSetting(env, "admin_todos_json", "");
    if (!raw) return defaultAdminTodos();
    const parsed = JSON.parse(raw);
    const clean = cleanAdminTodos(parsed);
    return clean.length ? clean : defaultAdminTodos();
  } catch {
    return defaultAdminTodos();
  }
}

async function saveAdminTodos(env, items) {
  const clean = cleanAdminTodos(items);
  await setSetting(env, "admin_todos_json", JSON.stringify(clean));
  return clean;
}

async function ensureCalendarToken(env) {
  let token = await getSetting(env, "admin_todo_calendar_token", "");
  if (!token) {
    token = randomHex(24);
    await setSetting(env, "admin_todo_calendar_token", token);
  }
  return token;
}

async function adminTodosJson(request, env) {
  const user = await requireAuth(request, env);
  if (!user) return jsonResponse({ error: "Unauthorized" }, 401);
  const origin = new URL(request.url).origin;
  const token = await ensureCalendarToken(env);
  return jsonResponse({ items: await getAdminTodos(env), calendarUrl: `${origin}/admin/todos.ics?key=${token}`, webcalUrl: `${origin.replace(/^https?:/, "webcal:")}/admin/todos.ics?key=${token}` });
}

async function adminTodosSave(request, env) {
  const user = await requireAuth(request, env);
  if (!user) return jsonResponse({ error: "Unauthorized" }, 401);
  const body = await request.json().catch(() => ({}));
  const items = await saveAdminTodos(env, body.items || []);
  return jsonResponse({ ok: true, items });
}

function icsEscape(v) {
  return String(v || "").replace(/\\/g, "\\\\").replace(/;/g, "\\;").replace(/,/g, "\\,").replace(/\n/g, "\\n");
}

function icsDateLocal(v) {
  const s = String(v || "").trim();
  if (!s) return "";
  const compact = s.replace(/[-:]/g, "").replace("T", "T");
  return compact.length === 13 ? compact + "00" : compact.slice(0, 15);
}

async function adminTodosIcs(request, env) {
  const url = new URL(request.url);
  const key = url.searchParams.get("key") || "";
  const token = await ensureCalendarToken(env);
  if (key !== token) return new Response("Invalid calendar key", { status: 403 });
  const todos = (await getAdminTodos(env)).filter(t => !t.done && t.due);
  const stamp = new Date().toISOString().replace(/[-:]/g, "").split(".")[0] + "Z";
  const lines = [
    "BEGIN:VCALENDAR",
    "VERSION:2.0",
    "PRODID:-//HB Commerce Solutions//Admin Tasks//EN",
    "CALSCALE:GREGORIAN",
    "METHOD:PUBLISH",
    "X-WR-CALNAME:HB Commerce Admin Tasks",
    "X-WR-CALDESC:Admin Portal to-do tasks with reminders"
  ];
  for (const t of todos) {
    const dt = icsDateLocal(t.due);
    if (!dt) continue;
    lines.push("BEGIN:VEVENT");
    lines.push(`UID:${icsEscape(t.id)}@hbcommerce-admin`);
    lines.push(`DTSTAMP:${stamp}`);
    lines.push(`DTSTART:${dt}`);
    lines.push(`SUMMARY:${icsEscape(t.text)}`);
    lines.push(`DESCRIPTION:${icsEscape("HB Commerce Admin Portal task")}`);
    lines.push("STATUS:CONFIRMED");
    lines.push("BEGIN:VALARM");
    lines.push(`TRIGGER:-PT${Math.max(0, parseInt(t.reminder || 30, 10) || 0)}M`);
    lines.push("ACTION:DISPLAY");
    lines.push(`DESCRIPTION:${icsEscape("Reminder: " + t.text)}`);
    lines.push("END:VALARM");
    lines.push("END:VEVENT");
  }
  lines.push("END:VCALENDAR");
  return new Response(lines.join("\r\n"), { headers: { "content-type": "text/calendar; charset=utf-8", "cache-control": "no-store", "content-disposition": 'inline; filename="hb-admin-tasks.ics"' } });
}

async function adminNotificationsPage(request, env, message = "") {
  const user = await requireAuth(request, env);
  if (!user) return redirect("/admin/login");
  const subs = await getPushSubscriptions(env);
  const iosDevices = await getIosApnsDevices(env);
  const body = `<main class="section admin-dashboard admin-notifications-page"><div class="container"><div class="section-title"><h2>App Push Notifications</h2><div class="btn-row"><a class="btn orange" href="/admin/dashboard?app=1">Dashboard</a><a class="btn" href="/admin/reports">Reports</a></div></div>${message}
<section class="form-section hb-app-push-section"><div class="form-title">Native iOS App Notifications</div><div class="notice success"><strong>Best option for your real iPhone app.</strong> Registered native iOS devices: <strong>${iosDevices.length}</strong>.</div><div class="btn-row"><button type="button" class="orange" id="testNativePushBtn">Send Native iOS Test Push</button></div><div id="nativePushStatus" class="notice" style="display:none;margin-top:12px"></div><script>(function(){var s=document.getElementById("nativePushStatus");function show(m,o){s.style.display="block";s.className="notice "+(o?"success":"error");s.textContent=m;}document.getElementById("testNativePushBtn")?.addEventListener("click",async function(){try{var r=await fetch("/admin/ios-device/test",{method:"POST",credentials:"same-origin"});var d=await r.json();if(d.ok)show("Native iOS push sent to "+d.sent+"/"+d.attempted+" device(s).",true);else show("Native iOS push failed: "+((d.errors||[]).join(" | ")||d.error||"No device registered."),false);}catch(e){show(e.message||String(e),false);}});})();</script></section><section class="form-section hb-app-push-section"><div class="form-title">Free Admin App Push Notifications</div><div class="notice success"><strong>No SMS cost.</strong> Use this section for your installed Admin Portal app. Current subscribed admin devices: <strong>${subs.length}</strong>.</div><div class="notice warning"><strong>Important:</strong> Open this page from the installed Admin Portal app on your phone, tap Enable, then tap Local Test first. On iPhone, push notifications require the Home Screen installed app and notification permission enabled for the app.</div><div class="btn-row"><button type="button" class="primary" id="enablePushBtn">Enable / Reset App Push on This Device</button><button type="button" class="btn" id="localPushBtn">Show Local Test Notification</button><button type="button" class="orange" id="testPushBtn">Send Server Push Test</button></div><div id="pushStatus" class="notice" style="display:none;margin-top:12px"></div><script>
(function(){
  function b64ToUint8Array(base64String){
    var padding='='.repeat((4-base64String.length%4)%4);
    var base64=(base64String+padding).replace(/-/g,'+').replace(/_/g,'/');
    var raw=atob(base64);
    var output=new Uint8Array(raw.length);
    for(var i=0;i<raw.length;i++)output[i]=raw.charCodeAt(i);
    return output;
  }
  var status=document.getElementById('pushStatus');
  function show(msg, ok){ status.style.display='block'; status.className='notice '+(ok?'success':'error'); status.textContent=msg; }
  async function getReadyRegistration(){
    var regs = await navigator.serviceWorker.getRegistrations();
    for (var i=0;i<regs.length;i++){
      if ((regs[i].active && regs[i].active.scriptURL.indexOf('/admin-push-sw.js') !== -1) || (regs[i].installing && regs[i].installing.scriptURL.indexOf('/admin-push-sw.js') !== -1) || (regs[i].waiting && regs[i].waiting.scriptURL.indexOf('/admin-push-sw.js') !== -1)) {
        try { await regs[i].unregister(); } catch(e) {}
      }
    }
    var reg=await navigator.serviceWorker.register('/admin-push-sw.js?v=116', { scope: '/' });
    await navigator.serviceWorker.ready;
    return reg;
  }
  function supportSummary(){
    return 'Support: SW='+(('serviceWorker' in navigator)?'yes':'no')+', Push='+(('PushManager' in window)?'yes':'no')+', Notification='+(('Notification' in window)?Notification.permission:'no')+'. ';
  }
  async function enablePush(){
    try{
      if(!('serviceWorker' in navigator) || !('PushManager' in window) || !('Notification' in window)){ show(supportSummary()+'This device/browser does not support app push notifications.', false); return; }
      var permission=await Notification.requestPermission();
      if(permission!=='granted'){ show(supportSummary()+'Notification permission was not granted on this device.', false); return; }
      var reg=await getReadyRegistration();
      var keyResp=await fetch('/admin/push-public-key',{credentials:'same-origin',cache:'no-store'});
      var keyData=await keyResp.json();
      if(!keyData.publicKey) throw new Error('No push public key returned by server.');
      // Always reset the existing subscription so old VAPID keys do not break server push.
      var oldSub=await reg.pushManager.getSubscription();
      if(oldSub){ try{ await oldSub.unsubscribe(); }catch(ignore){} }
      var sub=await reg.pushManager.subscribe({userVisibleOnly:true, applicationServerKey:b64ToUint8Array(keyData.publicKey)});
      var save=await fetch('/admin/push-subscribe',{method:'POST',credentials:'same-origin',headers:{'content-type':'application/json'},body:JSON.stringify(sub)});
      var saveData=await save.json();
      if(!save.ok || !saveData.ok) throw new Error(saveData.error || 'Subscription save failed.');
      show(supportSummary()+'App push is enabled/reset on this device. Saved subscriptions: '+(saveData.count||1)+'. Now tap Local Test, then Server Push Test.', true);
    }catch(err){ show(supportSummary()+(err.message || String(err)), false); }
  }
  async function localPush(){
    try{
      if(!('Notification' in window)) { show('Notifications are not supported on this device/browser.', false); return; }
      var permission=Notification.permission==='granted' ? 'granted' : await Notification.requestPermission();
      if(permission!=='granted'){ show('Notification permission was not granted.', false); return; }
      var reg=await getReadyRegistration();
      await reg.showNotification('HB Commerce Admin Alert', { body:'Local app notification test was successful.', icon:'/assets/hb-app-icon-v33-192.png', badge:'/assets/hb-favicon-v33.png', data:{url:'/admin/dashboard?app=1'} });
      show('Local notification displayed. If you saw it, this device can show notifications. Now try Server Push Test.', true);
    }catch(err){ show(err.message || String(err), false); }
  }
  async function testPush(){
    try{
      var res=await fetch('/admin/push-test',{method:'POST',credentials:'same-origin'});
      var data=await res.json();
      if(data.ok) show('Server push sent to '+data.sent+'/'+data.attempted+' subscribed device(s). Check notification center if no banner appeared.', true);
      else show('Server push did not send: '+((data.errors||[]).join(' | ') || 'No subscribed device found. Tap Enable / Reset first.'), false);
    }catch(err){ show(err.message || String(err), false); }
  }
  document.getElementById('enablePushBtn')?.addEventListener('click', enablePush);
  document.getElementById('testPushBtn')?.addEventListener('click', testPush);
  document.getElementById('localPushBtn')?.addEventListener('click', localPush);
})();
</script></section></div></main>`;
  return htmlPage("App Push Notifications | HB Commerce", layout(env, "Dashboard", body));
}

async function adminNotificationsPost(request, env) {
  const user = await requireAuth(request, env);
  if (!user) return redirect("/admin/login");
  return adminNotificationsPage(request, env, `<div class="notice success">App push notifications are managed from the buttons below. SMS setup has been removed.</div>`);
}


async function adminDocsSnapshot(env) {
  const docsResult = await env.DB.prepare("SELECT id,type,number,business,customer_name,email,status,paid,total,updated_at,data_json FROM documents ORDER BY updated_at DESC LIMIT 1000").all();
  const allRows = (docsResult.results || []).map(row => { let detail={}; try{detail=JSON.parse(row.data_json||"{}");}catch{} const isCanceled=row.status==="Canceled"||row.status==="Deleted"||!!detail.canceled_at||!!detail.deleted_at; const isConvertedQuote=row.type==="Quote"&&(row.status==="Converted"||!!detail.converted_to_invoice_id); return {...row,detail,isCanceled,isConvertedQuote}; });
  const invoiceById = new Map(allRows.filter(r=>r.type==="Invoice").map(r=>[r.id,r]));
  for (const r of allRows) if (r.type==="Quote"&&r.detail&&r.detail.converted_to_invoice_id){const inv=invoiceById.get(r.detail.converted_to_invoice_id); if(inv){r.convertedInvoice=inv;r.convertedInvoicePaid=!!inv.paid;r.convertedInvoiceStatus=inv.status||"";r.convertedInvoicePaymentMethod=(inv.detail&&inv.detail.payment_method)||"";r.convertedInvoicePaidAt=(inv.detail&&inv.detail.paid_at)||"";}}
  const visibleRows=allRows.filter(r=>!r.isCanceled&&r.type!=="OnlineOrder"&&r.type!=="OnlineQuoteOrder"&&r.type!=="MerchantApplication");
  const activeQuoteRows=visibleRows.filter(r=>r.type==="Quote"&&r.status!=="Approved"&&!r.isConvertedQuote);
  const approvedQuoteRows=visibleRows.filter(r=>r.type==="Quote"&&(r.status==="Approved"||r.isConvertedQuote));
  const activeApprovedQuoteWorkflowRows=approvedQuoteRows.filter(r=>!r.convertedInvoicePaid);
  const openInvoiceRows=visibleRows.filter(r=>r.type==="Invoice"&&!r.paid);
  const paidInvoiceRows=visibleRows.filter(r=>r.type==="Invoice"&&!!r.paid);
  const onlineOrderRows=allRows.filter(r=>!r.isCanceled&&r.type==="OnlineOrder"&&r.status!=="Converted to Quote");
  const onlineQuoteOrderRows=allRows.filter(r=>!r.isCanceled&&r.type==="OnlineQuoteOrder"&&r.status!=="Converted to Quote");
  const applicationRows=allRows.filter(r=>!r.isCanceled&&r.type==="MerchantApplication"&&r.status!=="Draft");
  return {allRows,activeQuoteRows,approvedQuoteRows,activeApprovedQuoteWorkflowRows,openInvoiceRows,paidInvoiceRows,onlineOrderRows,onlineQuoteOrderRows,applicationRows};
}

function adminPopupShell(title, subtitle, inner) {
  return `<main class="section admin-dashboard admin-popup-page"><div class="container"><div class="admin-popup-head"><a class="btn small" href="/admin/dashboard?app=1">← Back</a><div><h2>${escapeHtml(title)}</h2>${subtitle?`<p>${escapeHtml(subtitle)}</p>`:""}</div></div>${inner}</div></main>`;
}

async function adminDocListPage(request, env, kind) {
  const user=await requireAuth(request, env); if(!user) return redirect('/admin-app');
  const snap=await adminDocsSnapshot(env); const map={quotes:[snap.activeQuoteRows,'Quotes','Active quotes and draft quote records.'],approved:[snap.approvedQuoteRows,'Approved Quotes','Approved and converted quote records.'],invoices:[snap.openInvoiceRows,'Open Invoices','Invoices waiting for payment.'],paid:[snap.paidInvoiceRows,'Paid Invoices','Invoices marked paid.']};
  const [rows,title,desc]=map[kind]||map.quotes;
  const bodyRows=rows.map(r=>dashboardRow(r,kind)).join('')||`<tr><td colspan="8">No records found.</td></tr>`;
  const inner=`<section class="purple-panel hb-template-card hb-selected-records"><div class="purple-panel-head"><h3>${escapeHtml(title)}</h3><span>${escapeHtml(desc)}</span></div><div class="table-wrap"><table><thead><tr><th>Number</th><th>Type</th><th>Customer</th><th>Total</th><th>Status</th><th>Payment</th><th>Updated</th><th>Actions</th></tr></thead><tbody>${bodyRows}</tbody></table></div></section>${paymentModalHtml()}<script>${paymentModalScript()}</script>`;
  return htmlPage(`${title} | HB Commerce`, layout(env,'Dashboard',adminPopupShell(title,desc,inner)));
}

function statusProgressHtmlFromSnapshot(snap) {
  const totalOrders=snap.allRows.filter(r=>!r.isCanceled&&r.type==="OnlineOrder"), converted=totalOrders.filter(r=>r.status==="Converted to Quote"||!!(r.detail&&r.detail.converted_to_quote_id));
  const qt=snap.activeQuoteRows.length+snap.activeApprovedQuoteWorkflowRows.length, it=snap.openInvoiceRows.length+snap.paidInvoiceRows.length;
  const rows=[{name:'Online Orders',due:'Converted to Quote',current:converted.length,total:totalOrders.length,accent:'orange',href:'/admin/orders'},{name:'Quotes',due:'Approved / Converted',current:snap.activeApprovedQuoteWorkflowRows.length,total:qt,accent:'blue',href:'/admin/quotes'},{name:'Invoices',due:'Paid',current:snap.paidInvoiceRows.length,total:it,accent:'green',href:'/admin/open-invoices'},{name:'Applications',due:'Submitted Review',current:snap.applicationRows.length,total:Math.max(snap.applicationRows.length+2,snap.applicationRows.length),accent:'purple',href:'/admin/applications/pos-merchant'}];
  return rows.map((r,i)=>{const pct=r.total?Math.min(100,Math.round(r.current/r.total*100)):0;return `<a class="hb-status-row ${r.accent}" href="${r.href}"><span>${i+1}</span><strong>${escapeHtml(r.name)}</strong><em>${escapeHtml(r.due)}</em><b>${r.current}/${r.total||0}</b><i class="hb-progress"><u style="width:${pct}%"></u></i></a>`}).join('');
}

async function adminStatusProgressPage(request, env){const user=await requireAuth(request,env); if(!user)return redirect('/admin-app'); const snap=await adminDocsSnapshot(env); const inner=`<section class="purple-panel hb-template-card hb-status-card"><div class="purple-panel-head"><h3>Status Progress</h3><span>Quotes, invoices, online orders</span></div><div class="hb-status-list">${statusProgressHtmlFromSnapshot(snap)}</div></section>`; return htmlPage('Status Progress | HB Commerce', layout(env,'Dashboard',adminPopupShell('Status Progress','Workflow status overview',inner)));}

function todoPanelMarkup(){return `<section class="purple-panel hb-template-card hb-todo-card"><div class="purple-panel-head"><h3>Todo List</h3><span>Server synced + calendar reminders</span></div><form id="hbTodoForm" class="hb-todo-add hb-todo-add-v112"><input id="hbTodoInput" placeholder="Add a task, ex: Follow up on Quote"><input id="hbTodoDue" type="datetime-local" title="Due date and time"><select id="hbTodoReminder"><option value="15">15 min reminder</option><option value="30" selected>30 min reminder</option><option value="60">1 hour reminder</option><option value="1440">1 day reminder</option></select><button type="submit">Add</button></form><div class="hb-calendar-sync"><strong>Phone Calendar Sync:</strong><a id="hbCalendarWebcal" href="#">Subscribe Calendar</a><a id="hbCalendarIcs" href="#" target="_blank">Open ICS Feed</a><small>Add the subscription link once on your calendar. Tasks with due dates will sync with reminders.</small></div><ul id="hbTodoList" class="hb-todo-list"><li><span>Loading tasks...</span></li></ul></section>`;}

function todoPanelScript(){return `(function(){const list=document.getElementById('hbTodoList'),input=document.getElementById('hbTodoInput'),due=document.getElementById('hbTodoDue'),reminder=document.getElementById('hbTodoReminder'),form=document.getElementById('hbTodoForm'),webcal=document.getElementById('hbCalendarWebcal'),ics=document.getElementById('hbCalendarIcs');let items=[];if(!list||!input||!form)return;function esc(s){return String(s||'').replace(/[&<>]/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;'}[c]));}function dueLabel(v){if(!v)return '<small>No calendar due date</small>';try{return '<small>Due: '+new Date(v).toLocaleString()+'</small>'}catch(e){return '<small>Due: '+esc(v)+'</small>'}}async function load(){const r=await fetch('/admin/todos.json',{credentials:'same-origin'}),d=await r.json();items=d.items||[];if(webcal&&d.webcalUrl)webcal.href=d.webcalUrl;if(ics&&d.calendarUrl)ics.href=d.calendarUrl;render()}async function save(){await fetch('/admin/todos/save',{method:'POST',credentials:'same-origin',headers:{'content-type':'application/json'},body:JSON.stringify({items})})}function render(){list.innerHTML=items.map((it,i)=>'<li class="'+(it.done?'done':'')+'"><label><input type="checkbox" '+(it.done?'checked':'')+' data-i="'+i+'"><span>'+esc(it.text)+dueLabel(it.due)+'</span></label><button type="button" data-remove="'+i+'">×</button></li>').join('')||'<li><span>No tasks yet.</span></li>'}list.addEventListener('change',async e=>{if(e.target.matches('input[type="checkbox"]')){items[+e.target.dataset.i].done=e.target.checked;await save();render()}});list.addEventListener('click',async e=>{if(e.target.matches('button[data-remove]')){items.splice(+e.target.dataset.remove,1);await save();render()}});form.addEventListener('submit',async e=>{e.preventDefault();const v=input.value.trim();if(!v)return;items.push({id:crypto.randomUUID?crypto.randomUUID():String(Date.now()),text:v,done:false,due:due.value||'',reminder:parseInt(reminder.value||30,10),created_at:new Date().toISOString()});await save();input.value='';due.value='';reminder.value='30';render()});load().catch(err=>{list.innerHTML='<li><span>Todo sync failed: '+esc(err.message||err)+'</span></li>'})})();`;}
async function adminTodoPanelPage(request,env){const user=await requireAuth(request,env); if(!user)return redirect('/admin-app'); const inner=todoPanelMarkup()+`<script>${todoPanelScript()}</script>`; return htmlPage('Todo List | HB Commerce', layout(env,'Dashboard',adminPopupShell('Todo List','Server synced tasks and calendar reminders',inner)));}

function icsDateOnly(v){const s=String(v||'').slice(0,10);return /^\d{4}-\d{2}-\d{2}$/.test(s)?s.replaceAll('-',''):''}function icsNextDate(v){const s=String(v||'').slice(0,10);const d=new Date(s+'T00:00:00Z'); if(isNaN(d))return ''; d.setUTCDate(d.getUTCDate()+1); return d.toISOString().slice(0,10).replaceAll('-','');}
async function adminDueDatesIcs(request,env,pathKey=""){const url=new URL(request.url),key=pathKey||url.searchParams.get('key')||'',token=await ensureCalendarToken(env); if(key!==token)return new Response('Invalid calendar key',{status:403,headers:{'content-type':'text/plain; charset=utf-8','cache-control':'no-store'}}); const snap=await adminDocsSnapshot(env), rows=[...snap.activeQuoteRows,...snap.approvedQuoteRows.filter(r=>!r.convertedInvoicePaid),...snap.openInvoiceRows]; const stamp=new Date().toISOString().replace(/[-:]/g,'').split('.')[0]+'Z',lines=['BEGIN:VCALENDAR','VERSION:2.0','PRODID:-//HB Commerce Solutions//Quote Invoice Due Dates//EN','CALSCALE:GREGORIAN','METHOD:PUBLISH','X-WR-CALNAME:HB Commerce Quote & Invoice Due Dates','X-WR-CALDESC:Quote expiration dates and open invoice due dates','X-WR-TIMEZONE:America/Chicago']; for(const r of rows){const d=r.detail||{}; const dateVal=d.valid_until||d.doc_date; const due=icsDateOnly(dateVal),end=icsNextDate(dateVal); if(!due||!end)continue; const label=r.type==='Invoice'?'Invoice Due':'Quote Expires', uid=`${String(r.id||r.number||randomHex(4)).replace(/[^A-Za-z0-9_-]/g,'')}-${r.type}-${due}@hbcommerce-due`; lines.push('BEGIN:VEVENT',`UID:${icsEscape(uid)}`,`DTSTAMP:${stamp}`,`DTSTART;VALUE=DATE:${due}`,`DTEND;VALUE=DATE:${end}`,`SUMMARY:${icsEscape(label+': '+(r.number||''))}`,`DESCRIPTION:${icsEscape((r.customer_name||'')+' '+(r.email||''))}`,'STATUS:CONFIRMED','TRANSP:TRANSPARENT','END:VEVENT');} lines.push('END:VCALENDAR'); return new Response(lines.join('\r\n'),{headers:{'content-type':'text/calendar; charset=utf-8','cache-control':'public, max-age=300','access-control-allow-origin':'*','content-disposition':'inline; filename="hb-quote-invoice-due-dates.ics"'}})}
async function adminDueCalendarPage(request,env){const user=await requireAuth(request,env); if(!user)return redirect('/admin-app'); const origin=new URL(request.url).origin,token=await ensureCalendarToken(env),url=`${origin}/calendar/hb-due-dates-${token}.ics`,oldUrl=`${origin}/admin/due-dates.ics?key=${token}`,webcal=url.replace(/^https?:/,'webcal:'),google=`https://calendar.google.com/calendar/u/0/r/settings/addbyurl?cid=${encodeURIComponent(url)}`; const inner=`<section class="form-section"><div class="form-title">Quote & Invoice Due Date Calendar</div><div class="notice success">Subscribe once in Google Calendar or your PC calendar app. Quote expiration dates and open invoice due dates will appear automatically.</div><div class="btn-row"><a class="btn orange" href="${escapeHtml(google)}" target="_blank">Open Google Add by URL</a><a class="btn green" href="${escapeHtml(webcal)}">Subscribe in Calendar App</a><a class="btn" href="${escapeHtml(url)}" target="_blank">Test / Open ICS Feed</a></div><div class="field"><label>Copy this URL into Google Calendar → Other calendars + → From URL</label><input readonly value="${escapeHtml(url)}" onclick="this.select()"></div><div class="notice"><strong>If Google says unable to add:</strong> first click <em>Test / Open ICS Feed</em>. You should see text beginning with BEGIN:VCALENDAR. Then copy the URL above and add it manually in Google Calendar using Other calendars → + → From URL. Google can take several minutes to show newly subscribed events.</div><p class="hint">Old admin feed still works for compatibility: ${escapeHtml(oldUrl)}</p></section>`;return htmlPage('Due Date Calendar | HB Commerce',layout(env,'Dashboard',adminPopupShell('Due Date Calendar','Sync quote expirations and open invoice due dates',inner)));}


