function normalizeTaxZip(zip) {
  return String(zip || "").replace(/\D/g, "").slice(0, 5);
}

function normalizeTaxCity(city) {
  return String(city || "").trim().replace(/\s+/g, " ").toUpperCase();
}

function cityCombinedTaxFallback(state, city = "", zip = "") {
  state = String(state || "").toUpperCase();
  const cityKey = `${state}|${normalizeTaxCity(city)}`;
  if (CITY_COMBINED_TAX_RATES_DEFAULT[cityKey]) {
    const r = CITY_COMBINED_TAX_RATES_DEFAULT[cityKey];
    return { ok: true, zip: normalizeTaxZip(zip), city: r.city || city, state: r.state || state, rate: Number(r.rate || 0), state_rate: Number(r.state_rate || STATE_RATES[state] || 0), local_rate: Number(r.local_rate || Math.max(0, Number(r.rate || 0) - Number(STATE_RATES[state] || 0))), source: r.source || "Built-in city combined fallback", cityCombined: true, exact: false };
  }
  return null;
}

function taxRateFromStateFallback(state, city = "", zip = "") {
  state = String(state || "").toUpperCase();
  city = String(city || "").toLowerCase();
  zip = normalizeTaxZip(zip);
  const cityRate = cityCombinedTaxFallback(state, city, zip);
  if (cityRate) return cityRate;
  let rate = Number(STATE_RATES[state] || 0);
  if (state === "PA") {
    if (city.includes("philadelphia") || zip.startsWith("191")) rate = 8;
    else if (city.includes("pittsburgh") || zip.startsWith("152")) rate = 7;
    else rate = 6;
  }
  return { ok: true, zip, city, state, rate, source: "State base only — local city/village/county/district tax not verified", stateOnly: true, needs_review: true, exact: false };
}

async function getCustomTaxOverrides(env) {
  try {
    const raw = await getSetting(env, "tax_rate_overrides_json", "");
    if (!raw) return {};
    const parsed = JSON.parse(raw);
    return parsed && typeof parsed === "object" && !Array.isArray(parsed) ? parsed : {};
  } catch (err) {
    console.error("tax overrides load failed", err);
    return {};
  }
}

async function getTaxOverrides(env) {
  const custom = await getCustomTaxOverrides(env);
  return { ...TAX_OVERRIDES_DEFAULT, ...custom };
}

function normalizeTaxOverride(entry = {}, fallbackZip = "") {
  const zip = normalizeTaxZip(entry.zip || fallbackZip);
  return {
    zip,
    city: String(entry.city || "").trim(),
    state: String(entry.state || "").trim().toUpperCase(),
    rate: Math.max(0, Number(entry.rate || 0)),
    source: String(entry.source || entry.note || "Admin Tax Override").trim()
  };
}

const FIXED_TAX_RATE_PERCENT = 10;

function fixedTaxInfo(zip = "", city = "", state = "", street = "", taxableAmount = 0) {
  const rate = FIXED_TAX_RATE_PERCENT;
  const amount = Number(taxableAmount || 0);
  return {
    ok: true,
    zip: normalizeTaxZip(zip || ""),
    city: String(city || "").trim(),
    state: String(state || "").trim().toUpperCase(),
    street: String(street || "").trim(),
    rate,
    tax_amount: amount * rate / 100,
    taxable_amount: amount,
    source: "Fixed HB Commerce company tax rate",
    exact: true,
    fixed: true,
    override: false
  };
}


function extractZipTaxSalesRatePercent(data = {}) {
  const summaries = Array.isArray(data.taxSummaries) ? data.taxSummaries : [];
  const sales = summaries.find(s => String(s.taxType || "").toUpperCase() === "SALES_TAX" && String(s.summaryName || "").toLowerCase().includes("total")) ||
    summaries.find(s => String(s.taxType || "").toUpperCase() === "SALES_TAX") ||
    summaries[0];
  let rate = Number(sales && sales.rate);
  if (!rate && sales && Array.isArray(sales.displayRates)) {
    const total = sales.displayRates.find(r => String(r.name || "").toLowerCase().includes("total")) || sales.displayRates[0];
    rate = Number(total && total.rate);
  }
  if (!rate && Array.isArray(data.baseRates)) {
    rate = data.baseRates
      .filter(r => String(r.jurType || "").toUpperCase().includes("SALES_TAX"))
      .reduce((sum, r) => sum + Number(r.rate || 0), 0);
  }
  if (!Number.isFinite(rate) || rate < 0) return 0;
  return Math.round((rate <= 1 ? rate * 100 : rate) * 1000) / 1000;
}

async function zipTaxLookupForAddress(env, { street = "", city = "", state = "", zip = "" } = {}) {
  const key = String(env.ZIPTAX_API_KEY || env.ZIP_TAX_API_KEY || env.ZIPTAX_KEY || "").trim();
  const address = [street, city, state, zip].filter(Boolean).join(" ").replace(/\s+/g, " ").trim();
  if (!key) {
    return {
      ok: false,
      needs_review: true,
      message: "ZipTax API key is not configured. Add ZIPTAX_API_KEY as a Cloudflare Worker secret, then retry the destination tax lookup.",
      source: "ZipTax not configured"
    };
  }
  if (!address || !zip) {
    return { ok: false, needs_review: true, message: "Enter a full destination address with ZIP before using ZipTax.", source: "ZipTax address missing" };
  }
  const endpoint = `https://api.zip-tax.com/request/v60?address=${encodeURIComponent(address)}`;
  const res = await fetch(endpoint, { headers: { "X-API-Key": key, "accept": "application/json" } });
  const raw = await res.text();
  let data = {};
  try { data = raw ? JSON.parse(raw) : {}; } catch (err) { data = { raw }; }
  const response = data && data.metadata && data.metadata.response ? data.metadata.response : {};
  if (!res.ok || (response.code && Number(response.code) !== 100)) {
    return {
      ok: false,
      needs_review: true,
      message: response.message || `ZipTax lookup failed with HTTP ${res.status}.`,
      source: "ZipTax lookup failed",
      response_code: response.code || res.status
    };
  }
  const rate = extractZipTaxSalesRatePercent(data);
  if (!rate) {
    return { ok: false, needs_review: true, message: "ZipTax responded but no sales tax rate was found. Check the address.", source: "ZipTax no rate" };
  }
  const normalized = data.addressDetail && data.addressDetail.normalizedAddress ? String(data.addressDetail.normalizedAddress) : address;
  const sourcing = data.sourcingRules && data.sourcingRules.description ? String(data.sourcingRules.description) : "";
  const jurisdictions = Array.isArray(data.baseRates) ? data.baseRates
    .filter(r => String(r.jurType || "").toUpperCase().includes("SALES_TAX"))
    .map(r => ({
      name: String(r.jurName || ""),
      type: String(r.jurType || ""),
      description: String(r.jurDescription || ""),
      rate: Math.round((Number(r.rate || 0) <= 1 ? Number(r.rate || 0) * 100 : Number(r.rate || 0)) * 1000) / 1000
    })) : [];
  return {
    ok: true,
    exact: true,
    ziptax: true,
    rate,
    city: String(city || ""),
    state: String(state || "").toUpperCase(),
    zip: normalizeTaxZip(zip || ""),
    street: String(street || ""),
    normalized_address: normalized,
    sourcing_description: sourcing,
    source: "ZipTax address-level destination lookup",
    jurisdictions,
    raw_response_code: response.code || 100
  };
}

