async function taxForItems(env, ship = {}, items = []) {
  const amount = Number(calcTotals({ items, tax_rate: FIXED_TAX_RATE_PERCENT }).subtotal || 0);
  const z = await zipTaxLookupForAddress(env, ship).catch(() => null);
  if (z && z.ok) return { ...z, taxable_amount: amount, tax_amount: amount * Number(z.rate || 0) / 100 };
  return fixedTaxInfo(ship.zip, ship.city, ship.state, ship.street, amount);
}


async function publicShippingRate(request, env) {
  try {
    const body = await request.json();
    const ship = body.shipping || {};
    const zip = normalizeTaxZip(ship.zip || "");
    const mode = String(body.fulfillment_type || "ups").toLowerCase();
    if (mode === "pickup") return jsonResponse({ ok:true, rates:[{ code:"pickup", label:"Pickup at HB Commerce", amount:0, carrier:"Pickup" }], source:"pickup" });
    if (!zip) return jsonResponse({ ok:false, message:"Enter shipping ZIP to calculate shipping." }, 400);
    if (mode === "fedex") {
      const fx = await fedExGroundRate(env, ship, body.cart || []).catch(err => ({ ok:false, error:String(err && err.message || err) }));
      if (fx && fx.ok) return jsonResponse({ ok:true, rates:[fx.rate], source:"FedEx" });
      console.error("FedEx rating unavailable", fx && fx.error);
      return jsonResponse({ ok:false, carrier_required:true, message:"FedEx rate is unavailable: " + String(fx && fx.error || "Check FedEx API credentials, environment, and account/project Rate API access.") }, 503);
    }
    const ups = await upsGroundRate(env, ship, body.cart || []).catch(err => ({ ok:false, error:String(err && err.message || err) }));
    if (ups && ups.ok) return jsonResponse({ ok:true, rates:[ups.rate], source:"UPS" });
    if (ups && ups.error) console.error("UPS rating unavailable", ups.error);
    if (String(env.ALLOW_STANDARD_SHIPPING_FALLBACK || "") === "1") {
      const fallback = Number(env.STANDARD_SHIPPING_FALLBACK || 0);
      return jsonResponse({ ok:true, needs_review:true, rates:[{ code:"standard", label:"Standard Shipping", amount:fallback, carrier:"HB Commerce" }], source:"Standard shipping fallback" });
    }
    return jsonResponse({ ok:false, carrier_required:true, message:"UPS rate is unavailable. Check UPS API credentials or choose FedEx/Pickup." }, 503);
  } catch (err) {
    return jsonResponse({ ok:false, message:"Shipping rate calculation failed." }, 500);
  }
}

function cartPackageWeightLbs(cart = [], fallback = 18) {
  const rows = Array.isArray(cart) ? cart : [];
  const fallbackWeight = Math.max(1, Number(fallback || 18) || 18);
  const total = rows.reduce((sum, row) => {
    const qty = Math.max(1, Number(row && row.qty || 1) || 1);
    const explicitWeight = Number(row && (row.weight_lbs || row.package_weight_lbs || row.weight) || 0);
    return sum + qty * (explicitWeight > 0 ? explicitWeight : fallbackWeight);
  }, 0);
  return Math.max(1, total || fallbackWeight);
}

async function upsGroundRate(env, ship = {}, cart = []) {
  const id=String(env.UPS_CLIENT_ID||"").trim(), sec=String(env.UPS_CLIENT_SECRET||"").trim(), acct=String(env.UPS_ACCOUNT_NUMBER||"").trim();
  if(!id||!sec||!acct) throw new Error("UPS credentials are not configured. Required secrets: UPS_CLIENT_ID, UPS_CLIENT_SECRET, UPS_ACCOUNT_NUMBER.");
  const prod=String(env.UPS_FORCE_SANDBOX||"").trim()!=="1";
  const base=prod?"https://onlinetools.ups.com":"https://wwwcie.ups.com";
  const tx="hb-"+Date.now();
  const authRes=await fetch(base+"/security/v1/oauth/token",{method:"POST",headers:{authorization:"Basic "+btoa(id+":"+sec),"content-type":"application/x-www-form-urlencoded","transId":tx,"transactionSrc":"hb-commerce"},body:"grant_type=client_credentials"});
  const authText=await authRes.text();
  let authJson={};try{authJson=authText?JSON.parse(authText):{}}catch{}
  if(!authRes.ok||!authJson.access_token){
    const em=authJson.response?.errors?.[0]?.message||authJson.error_description||authJson.error||authText||"Invalid Authentication Information";
    throw new Error("UPS OAuth failed before rating request: "+em+". This means UPS_CLIENT_ID/UPS_CLIENT_SECRET do not match the selected environment or the app is not active for API OAuth.");
  }
  const fromZip=String(env.UPS_ORIGIN_ZIP||env.TAX_ORIGIN_ZIP||"60193"), toZip=normalizeTaxZip(ship.zip||"");
  const weight = cartPackageWeightLbs(cart, Number(env.EUFY_PACKAGE_WEIGHT_LB || 18));
  const req={RateRequest:{Request:{RequestOption:"Rate"},Shipment:{Shipper:{Name:"HB Commerce Solutions",ShipperNumber:acct,Address:{PostalCode:fromZip,CountryCode:"US"}},ShipTo:{Address:{PostalCode:toZip,CountryCode:"US",ResidentialAddressIndicator:""}},ShipFrom:{Address:{PostalCode:fromZip,CountryCode:"US"}},PaymentDetails:{ShipmentCharge:{Type:"01",BillShipper:{AccountNumber:acct}}},Service:{Code:"03",Description:"UPS Ground"},Package:{PackagingType:{Code:"02",Description:"Package"},PackageWeight:{UnitOfMeasurement:{Code:"LBS"},Weight:String(Math.ceil(weight))}}}}};
  const rateRes=await fetch(base+"/api/rating/v1/Rate",{method:"POST",headers:{authorization:"Bearer "+authJson.access_token,"content-type":"application/json","transId":tx,"transactionSrc":"hb-commerce"},body:JSON.stringify(req)});
  const rateText=await rateRes.text();
  let data={};try{data=rateText?JSON.parse(rateText):{}}catch{}
  if(!rateRes.ok){
    const em=data.response?.errors?.[0]?.message||data.response?.errors?.[0]?.code||rateText||"UPS rate failed";
    throw new Error("UPS Rating failed after OAuth succeeded: "+em+". This usually means the Developer App is missing Rating API access or the UPS_ACCOUNT_NUMBER is not linked to the app.");
  }
  const rated=data.RateResponse?.RatedShipment, val=Number(rated?.TotalCharges?.MonetaryValue||0);
  if(!val) throw new Error("UPS OAuth succeeded but no rate was returned. Confirm UPS_ACCOUNT_NUMBER, origin ZIP, destination ZIP, and Rating API access.");
  return {ok:true, rate:{code:"ups_ground", label:"UPS Ground", amount:val, carrier:"UPS"}};
}

function fedExAddressFromEnv(env, fallbackZip = "60193") {
  return {
    postalCode: String(env.FEDEX_ORIGIN_ZIP || env.UPS_ORIGIN_ZIP || env.TAX_ORIGIN_ZIP || fallbackZip).trim(),
    countryCode: String(env.FEDEX_ORIGIN_COUNTRY || env.TAX_ORIGIN_COUNTRY || "US").trim() || "US",
    stateOrProvinceCode: cleanStateCode(env.FEDEX_ORIGIN_STATE || env.TAX_ORIGIN_STATE || "IL"),
    city: String(env.FEDEX_ORIGIN_CITY || env.TAX_ORIGIN_CITY || "").trim()
  };
}

function fedExRecipientAddress(ship = {}) {
  return {
    postalCode: normalizeTaxZip(ship.zip || ""),
    countryCode: String(ship.country || "US").trim() || "US",
    stateOrProvinceCode: cleanStateCode(ship.state || ""),
    city: String(ship.city || "").trim(),
    residential: ship.residential === false ? false : true
  };
}

function fedExCleanAddress(addr = {}) {
  const out = { postalCode: String(addr.postalCode || "").trim(), countryCode: String(addr.countryCode || "US").trim() || "US" };
  if (addr.stateOrProvinceCode) out.stateOrProvinceCode = cleanStateCode(addr.stateOrProvinceCode);
  if (addr.city) out.city = String(addr.city || "").trim();
  if (addr.residential !== undefined) out.residential = !!addr.residential;
  return out;
}

function fedExChargeAmount(obj) {
  if (!obj || typeof obj !== "object") return 0;
  const candidates = [
    obj.totalNetFedExCharge,
    obj.totalNetCharge,
    obj.totalBaseCharge,
    obj.totalNetChargeWithDutiesAndTaxes,
    obj.shipmentRateDetail && obj.shipmentRateDetail.totalNetFedExCharge,
    obj.shipmentRateDetail && obj.shipmentRateDetail.totalNetCharge,
    obj.shipmentRateDetail && obj.shipmentRateDetail.totalBaseCharge,
    obj.shipmentRateDetail && obj.shipmentRateDetail.totalNetChargeWithDutiesAndTaxes,
    obj.ratedPackages && obj.ratedPackages[0] && obj.ratedPackages[0].packageRateDetail && obj.ratedPackages[0].packageRateDetail.netCharge,
    obj.ratedPackages && obj.ratedPackages[0] && obj.ratedPackages[0].packageRateDetail && obj.ratedPackages[0].packageRateDetail.totalNetCharge
  ];
  for (const c of candidates) {
    const n = Number(c && (c.amount ?? c.value ?? c));
    if (Number.isFinite(n) && n > 0) return n;
  }
  return 0;
}

function fedExRateErrorText(data = {}, raw = "") {
  const errs = Array.isArray(data.errors) ? data.errors : [];
  if (errs.length) return errs.map(e => [e.code, e.message].filter(Boolean).join(": ")).join(" | ");
  const alerts = data.output && Array.isArray(data.output.alerts) ? data.output.alerts : [];
  if (alerts.length) return alerts.map(e => [e.code, e.message].filter(Boolean).join(": ")).join(" | ");
  return data.error_description || data.error || raw || "rate failed";
}

async function fedExRateQuote(env, base, token, acct, ship = {}, cart = [], serviceType = "") {
  const from = fedExCleanAddress(fedExAddressFromEnv(env));
  const to = fedExCleanAddress(fedExRecipientAddress(ship));
  const weight = cartPackageWeightLbs(cart, Number(env.FEDEX_PACKAGE_WEIGHT_LB || env.EUFY_PACKAGE_WEIGHT_LB || 18));
  const service = String(serviceType || "").trim().toUpperCase();
  const payload = {
    accountNumber: { value: acct },
    carrierCodes: ["FDXG"],
    requestedShipment: {
      shipper: { address: from },
      recipient: { address: to },
      pickupType: String(env.FEDEX_PICKUP_TYPE || "DROPOFF_AT_FEDEX_LOCATION"),
      packagingType: "YOUR_PACKAGING",
      rateRequestType: ["ACCOUNT", "LIST"],
      shipDateStamp: today(),
      shippingChargesPayment: { paymentType: "SENDER", payor: { responsibleParty: { accountNumber: { value: acct }, address: { countryCode: "US" } } } },
      requestedPackageLineItems: [{
        groupPackageCount: 1,
        weight: { units: "LB", value: Math.ceil(weight) },
        dimensions: { length: Number(env.FEDEX_PACKAGE_LENGTH_IN || 24), width: Number(env.FEDEX_PACKAGE_WIDTH_IN || 18), height: Number(env.FEDEX_PACKAGE_HEIGHT_IN || 12), units: "IN" }
      }]
    },
    rateRequestControlParameters: { returnTransitTimes: true, servicesNeededOnRateFailure: true }
  };
  if (service) payload.requestedShipment.serviceType = service;
  const rr = await fetch(base + "/rate/v1/rates/quotes", { method:"POST", headers:{ "authorization":"Bearer " + token, "content-type":"application/json", "x-locale":"en_US", "x-customer-transaction-id":"hb-fedex-" + Date.now() }, body:JSON.stringify(payload) });
  const rt = await rr.text();
  let data = {}; try { data = rt ? JSON.parse(rt) : {}; } catch {}
  if (!rr.ok) throw new Error(fedExRateErrorText(data, rt));
  const details = data.output && Array.isArray(data.output.rateReplyDetails) ? data.output.rateReplyDetails : [];
  const preferred = details.find(d => service && String(d.serviceType || "").toUpperCase() === service) || details.find(d => ["GROUND_HOME_DELIVERY","FEDEX_GROUND"].includes(String(d.serviceType || "").toUpperCase())) || details[0] || {};
  let amount = 0;
  for (const detail of [preferred, ...details]) {
    const ratedRows = Array.isArray(detail.ratedShipmentDetails) ? detail.ratedShipmentDetails : [];
    for (const rated of ratedRows) {
      amount = fedExChargeAmount(rated);
      if (amount > 0) {
        const svc = String(detail.serviceType || service || "FEDEX_GROUND").toUpperCase();
        const label = svc === "GROUND_HOME_DELIVERY" ? "FedEx Ground Home Delivery" : "FedEx Ground";
        return { ok:true, rate:{ code:svc.toLowerCase(), label, amount, carrier:"FedEx" } };
      }
    }
  }
  throw new Error("FedEx OAuth and rating succeeded but no usable charge amount was returned. Check account rating permissions, package dimensions, origin ZIP, and destination ZIP.");
}

async function fedExGroundRate(env, ship = {}, cart = []) {
  const id = String(env.FEDEX_CLIENT_ID || env.FEDEX_API_KEY || "").trim();
  const sec = String(env.FEDEX_CLIENT_SECRET || env.FEDEX_SECRET_KEY || "").trim();
  const acct = String(env.FEDEX_ACCOUNT_NUMBER || "").trim();
  if (!id || !sec || !acct) throw new Error("FedEx credentials are not configured. Required secrets: FEDEX_CLIENT_ID, FEDEX_CLIENT_SECRET, FEDEX_ACCOUNT_NUMBER.");
  const sandbox = String(env.FEDEX_FORCE_SANDBOX || "").trim() === "1";
  const base = sandbox ? "https://apis-sandbox.fedex.com" : "https://apis.fedex.com";
  const auth = await fetch(base + "/oauth/token", { method:"POST", headers:{ "content-type":"application/x-www-form-urlencoded" }, body:"grant_type=client_credentials&client_id=" + encodeURIComponent(id) + "&client_secret=" + encodeURIComponent(sec) });
  const authText = await auth.text();
  let aj = {}; try { aj = authText ? JSON.parse(authText) : {}; } catch {}
  if (!auth.ok || !aj.access_token) throw new Error("FedEx OAuth failed before rating request: " + (aj.errors?.[0]?.message || aj.error_description || aj.error || authText || "authentication failed") + ". This means FEDEX_CLIENT_ID/FEDEX_CLIENT_SECRET do not match the selected environment or the FedEx project is not active.");
  const forcedService = String(env.FEDEX_SERVICE_TYPE || "").trim().toUpperCase();
  const services = forcedService ? [forcedService] : ["GROUND_HOME_DELIVERY", "FEDEX_GROUND"];
  const errors = [];
  for (const svc of services) {
    try {
      return await fedExRateQuote(env, base, aj.access_token, acct, ship, cart, svc);
    } catch (err) {
      errors.push(svc + ": " + String(err && err.message || err));
    }
  }
  throw new Error("FedEx rating failed after OAuth succeeded. " + errors.join(" | ") + ". Confirm the FedEx project has Rates and Transit Times API access, the account number is linked to that project, FEDEX_FORCE_SANDBOX matches the credential environment, and the destination/origin ZIPs are valid.");
}



async function publicTaxCalculate(request, env) {
  try {
    const body = await request.json();
    const products = await eufyProductsForEnv(env);
    const rows = Array.isArray(body.cart) ? body.cart : [];
    const items = [];
    const checkoutCouponCode = String(body.checkout_coupon_code || '').trim().toUpperCase();
    for (const row of rows) {
      const p = eufyProductById(String(row.id || ''), products) || ltsProductById(String(row.id || ''), products);
      if (!p) continue;
      const qty = Math.max(1, parseInt(row.qty || 1, 10) || 1);
      const quoteOnly = !!p.quote_only;
      const regular = quoteOnly ? 0 : Number(p.regular_price || p.price || 0);
      const productCouponCode = String(p.coupon || '').trim().toUpperCase();
      const couponApplied = !quoteOnly && (Number(p.discount || 0) > 0) && (!!row.coupon || (!!checkoutCouponCode && productCouponCode === checkoutCouponCode));
      const discount = couponApplied ? Number(p.discount || 0) : 0;
      items.push({ qty, name: p.name, desc: p.desc || '', cost: regular, sale_price: regular, markup: 0, discount, taxable: true });
    }
    const info = await taxForItems(env, body.shipping || {}, items);
    return jsonResponse({ ...info, ok: true });
  } catch (err) {
    console.error('public tax calculation failed', err);
    return jsonResponse({ ok: false, error: 'Tax calculation failed.' }, 500);
  }
}

async function taxRateForLocation(env, zip, city = '', state = '', street = '') {
  return fixedTaxInfo(zip, city, state, street, 0);
}

async function adminTaxLookup(request, env) {
  const user = await requireAuth(request, env);
  if (!user) return jsonResponse({ ok: false, error: "Not logged in" }, 401);
  const url = new URL(request.url);
  const zip = normalizeTaxZip(url.searchParams.get("zip") || "");
  let city = String(url.searchParams.get("city") || "").trim();
  let state = String(url.searchParams.get("state") || "").trim().toUpperCase();
  const street = String(url.searchParams.get("street") || "").trim();
  const forceZipTax = url.searchParams.get("force_ziptax") === "1" || url.searchParams.get("ziptax") === "1";
  const incomingCity = city;
  const incomingState = state;

  if (zip) {
    try {
      const r = await fetch(`https://api.zippopotam.us/us/${zip}`);
      if (r.ok) {
        const j = await r.json();
        const p = j.places && j.places[0];
        if (p) {
          const zipCity = String(p["place name"] || "");
          const zipState = String(p["state abbreviation"] || "");
          if (zipCity) city = zipCity;
          if (zipState) state = zipState.toUpperCase();
        }
      }
    } catch (err) {
      console.error("zip city/state lookup failed", err);
    }
  }

  if (forceZipTax || state === "IL") {
    const z = await zipTaxLookupForAddress(env, { street, city, state, zip }).catch(err => {
      console.error("ziptax lookup failed", err);
      return { ok: false, needs_review: true, message: "ZipTax lookup failed. Check API key and address.", source: "ZipTax error" };
    });
    if (z.ok) return jsonResponse({ ...z, city: z.city || city, state: z.state || state, zip, street });
    return jsonResponse({
      ok: true,
      needs_review: true,
      city,
      state,
      zip,
      street,
      rate: 0,
      source: z.source || "ZipTax lookup unavailable",
      message: z.message || z.error || "ZipTax lookup unavailable. Enter the rate manually or check API setup."
    });
  }

  return jsonResponse({ ...fixedTaxInfo(zip, city, state, street, 0), ok: true });
}

function jsonResponse(obj, status = 200) {
  return new Response(JSON.stringify(obj), { status, headers: { "content-type": "application/json; charset=utf-8", "cache-control": "no-store" } });
}




function authNetMask(v){const s=String(v||"").trim();return s?`${s.slice(0,4)}…${s.slice(-4)} (${s.length} chars)`:"missing"}
async function authNetAuthenticateTest(env){const c=authNetConfig(env);if(!c.login||!c.key)return{ok:false,code:"LOCAL",text:"API Login ID or Transaction Key missing"};try{const res=await fetch(c.api,{method:"POST",headers:{"content-type":"application/json","accept":"application/json"},body:JSON.stringify({authenticateTestRequest:{merchantAuthentication:{name:c.login,transactionKey:c.key}}})});const data=JSON.parse((await res.text()).replace(/^\uFEFF/,""));const m=(data.messages&&data.messages.message&&data.messages.message[0])||{};return{ok:data.messages&&data.messages.resultCode==="Ok",code:m.code||"",text:m.text||""}}catch(e){return{ok:false,code:"FETCH",text:e.message||String(e)}}}
async function adminAuthNetTest(request, env){const user=await requireAuth(request,env);if(!user)return redirect('/admin-app');const c=authNetConfig(env),raw=String(env.AUTHORIZE_NET_ENV||"").trim()||"unset";const rows=[["AUTHORIZE_NET_API_LOGIN_ID",c.login],["AUTHORIZE_NET_TRANSACTION_KEY",c.key],["AUTHORIZE_NET_PUBLIC_CLIENT_KEY",c.publicKey]].map(x=>`<div><span>${x[0]}</span><strong class="${x[1]?'ok':'bad'}">${x[1]?authNetMask(x[1]):'missing'}</strong></div>`).join('');const t=await authNetAuthenticateTest(env);const ok=t.ok;let msg=ok?`<div class="notice success"><strong>Server API authentication passed.</strong><br>API Login ID + Transaction Key are valid for the ${escapeHtml(c.mode)} endpoint.</div>`:`<div class="notice error"><strong>Server API authentication failed.</strong><br>${escapeHtml((t.code?`${t.code}: `:'')+(t.text||'Unknown error'))}</div>`;if(t.code==='E00007')msg+=`<div class="notice warning"><strong>Fix:</strong> the API Login ID/Transaction Key do not match the ${escapeHtml(c.mode)} endpoint. Regenerate the Transaction Key or switch AUTHORIZE_NET_ENV to match your credential set.</div>`;msg+=`<div class="notice"><strong>Screenshot clue:</strong> the payment-page error happens in AcceptUI before the Worker charges the card. That step uses <strong>API Login ID + Public Client Key</strong>. If the server test passes but the Pay button still shows E_WC_21/E_WC_19, regenerate Manage Public Client Key in the same Authorize.Net account/environment and update AUTHORIZE_NET_PUBLIC_CLIENT_KEY.</div>`;const body=`<main class="section admin-dashboard"><div class="container"><div class="section-title"><h2>Authorize.Net Connection Test</h2><div class="btn-row"><a class="btn" href="/admin/dashboard?app=1">Dashboard</a><a class="btn" href="/admin/open-invoices">Open Invoices</a></div></div><section class="form-section"><div class="form-title">Gateway Configuration</div><p>Worker mode: <strong>${escapeHtml(c.mode)}</strong> · AUTHORIZE_NET_ENV: <strong>${escapeHtml(raw)}</strong></p><p>API endpoint: <strong>${escapeHtml(c.api)}</strong><br>AcceptUI script: <strong>${escapeHtml(c.acceptJs)}</strong></p><div class="ups-secret-grid">${rows}</div>${msg}<div class="notice warning"><strong>Production collection:</strong> use live Authorize.Net credentials and delete AUTHORIZE_NET_ENV. Use AUTHORIZE_NET_ENV=sandbox only with sandbox credentials/test cards.</div></section></div></main>`;return htmlPage('Authorize.Net Test | HB Commerce',layout(env,'Dashboard',body))}

async function adminFedExTest(request, env) {
  const user = await requireAuth(request, env);
  if (!user) return redirect('/admin-app');
  const url = new URL(request.url);
  const zip = normalizeTaxZip(url.searchParams.get('zip') || '60123');
  const forcedSandbox = String(env.FEDEX_FORCE_SANDBOX || '').trim() === '1';
  const envMode = forcedSandbox ? 'sandbox' : 'production';
  const secrets = [
    ['FEDEX_CLIENT_ID', !!String(env.FEDEX_CLIENT_ID||env.FEDEX_API_KEY||'').trim()],
    ['FEDEX_CLIENT_SECRET', !!String(env.FEDEX_CLIENT_SECRET||env.FEDEX_SECRET_KEY||'').trim()],
    ['FEDEX_ACCOUNT_NUMBER', !!String(env.FEDEX_ACCOUNT_NUMBER||'').trim()],
    ['FEDEX_ORIGIN_ZIP', !!String(env.FEDEX_ORIGIN_ZIP||'').trim()]
  ];
  const secretRows = secrets.map(([k,v])=>`<div><span>${k}</span><strong class="${v?'ok':'bad'}">${v?'saved':'missing'}</strong></div>`).join('');
  const envNote = forcedSandbox ? `<div class="notice warning"><strong>Sandbox mode:</strong> FEDEX_FORCE_SANDBOX=1 is active. Use only sandbox FedEx credentials in this mode.</div>` : `<div class="notice success"><strong>Production mode:</strong> no sandbox override is active. Use production FedEx credentials.</div>`;
  let result = '';
  try {
    const r = await fedExGroundRate(env, { zip }, [{ qty:1 }]);
    result = `<div class="notice success"><strong>FedEx rating connected.</strong><br>${escapeHtml(r.rate.label)} to ZIP ${escapeHtml(zip)}: ${money(r.rate.amount)}</div>`;
  } catch (err) {
    const msg = String(err.message || err);
    result = `<div class="notice error"><strong>FedEx test failed.</strong><br>${escapeHtml(msg)}</div><div class="notice"><strong>Most common FedEx fixes:</strong><br>1) For live rates, delete FEDEX_FORCE_SANDBOX or leave it unset. For sandbox-only credentials, set FEDEX_FORCE_SANDBOX=1.<br>2) Confirm the same FedEx Developer Project has the <strong>Rates and Transit Times API</strong> enabled.<br>3) Confirm the FedEx account number ending <strong>${escapeHtml(String(env.FEDEX_ACCOUNT_NUMBER||'').slice(-6) || 'not saved')}</strong> is linked to that project.<br>4) This version tries <strong>GROUND_HOME_DELIVERY</strong> first for residential destinations and then falls back to <strong>FEDEX_GROUND</strong>.</div>`;
  }
  const body = `<main class="section admin-dashboard"><div class="container"><div class="section-title"><h2>FedEx Rating API Test</h2><div class="btn-row"><a class="btn" href="/admin/dashboard?app=1">Dashboard</a><a class="btn" href="/admin/ups-test?zip=${encodeURIComponent(zip)}">UPS Test</a></div></div><section class="form-section"><div class="form-title">FedEx Connection Test</div><p>Environment used by Worker: <strong>${escapeHtml(envMode)}</strong></p>${envNote}<div class="ups-secret-grid">${secretRows}</div><form method="get"><div class="field"><label>Destination ZIP for test</label><input name="zip" value="${escapeHtml(zip)}"></div><button class="orange">Run FedEx Test</button></form>${result}<div class="notice">Cloudflare secrets used: FEDEX_CLIENT_ID, FEDEX_CLIENT_SECRET, FEDEX_ACCOUNT_NUMBER, FEDEX_ORIGIN_ZIP. Optional: FEDEX_ORIGIN_CITY, FEDEX_ORIGIN_STATE, FEDEX_SERVICE_TYPE. Use FEDEX_FORCE_SANDBOX=1 only for sandbox credentials.</div></section></div></main>`;
  return htmlPage("FedEx Rating API Test | HB Commerce", layout(env, "Dashboard", body));
}


async function adminUpsTest(request, env) {
  const user = await requireAuth(request, env);
  if (!user) return redirect('/admin-app');
  const url = new URL(request.url);
  const zip = normalizeTaxZip(url.searchParams.get('zip') || '60193');
  const forcedSandbox = String(env.UPS_FORCE_SANDBOX || '').trim() === '1';
  const envMode = forcedSandbox ? 'sandbox' : 'production';
  const oldEnv = String(env.UPS_ENV || '').trim();
  const secrets = [
    ['UPS_CLIENT_ID', !!String(env.UPS_CLIENT_ID||'').trim()],
    ['UPS_CLIENT_SECRET', !!String(env.UPS_CLIENT_SECRET||'').trim()],
    ['UPS_ACCOUNT_NUMBER', !!String(env.UPS_ACCOUNT_NUMBER||'').trim()],
    ['UPS_ORIGIN_ZIP', !!String(env.UPS_ORIGIN_ZIP||'').trim()]
  ];
  const secretRows = secrets.map(([k,v])=>`<div><span>${k}</span><strong class="${v?'ok':'bad'}">${v?'saved':'missing'}</strong></div>`).join('');
  const envNote = oldEnv ? `<div class="notice warning"><strong>Old UPS_ENV secret detected:</strong> ${escapeHtml(oldEnv)}. This version ignores UPS_ENV so production is used unless UPS_FORCE_SANDBOX=1 is set.</div>` : `<div class="notice success"><strong>Production mode:</strong> no sandbox override is active.</div>`;
  let result = '';
  try {
    const r = await upsGroundRate(env, { zip }, [{ qty: 1 }]);
    result = `<div class="notice success"><strong>UPS rating connected.</strong><br>${escapeHtml(r.rate.label)} to ZIP ${escapeHtml(zip)}: ${money(r.rate.amount)}</div>`;
  } catch (err) {
    const msg = String(err.message || err);
    result = `<div class="notice error"><strong>UPS test failed.</strong><br>${escapeHtml(msg)}</div><div class="notice"><strong>What the screenshot tells us:</strong><br>Your UPS Developer app screenshot shows Tracking, Address Validation, Authorization (OAuth), and Shipping approved. This Worker calls the UPS <strong>Rating API</strong> endpoint. If OAuth succeeds but rating fails, add/enable <strong>Rating API</strong> access for the same UPS Developer App and confirm account number <strong>${escapeHtml(String(env.UPS_ACCOUNT_NUMBER||'').slice(-6) || 'not saved')}</strong> is linked to that app.<br><br><strong>Production setup:</strong> Use production UPS Developer App Client ID + Secret. Do not use your UPS.com password.</div>`;
  }
  const body = `<main class="section admin-dashboard admin-ups-test"><div class="container"><div class="section-title"><h2>UPS Rating API Test</h2><div class="btn-row"><a class="btn" href="/admin/dashboard?app=1">Dashboard</a><a class="btn" href="/admin/orders">Online Orders</a></div></div><section class="form-section"><div class="form-title">UPS Connection Test</div><p>Environment used by Worker: <strong>${escapeHtml(envMode)}</strong></p>${envNote}<div class="ups-secret-grid">${secretRows}</div><form method="get"><div class="field"><label>Destination ZIP for test</label><input name="zip" value="${escapeHtml(zip)}"></div><button class="orange">Run UPS Test</button></form>${result}</section></div></main>`;
  return htmlPage('UPS Test | HB Commerce', layout(env, 'Dashboard', body));
}

async function adminTaxPage(request, env, message = "") {
  const user = await requireAuth(request, env);
  if (!user) return redirect("/admin-app");
  const body = `<main class="section admin-dashboard admin-tax-page"><div class="container"><div class="section-title"><h2>Fixed Sales Tax</h2><div class="btn-row"><a class="btn" href="/admin/dashboard?app=1">Dashboard</a><a class="btn" href="/admin/reports">Reports</a></div></div>${message}<section class="form-section"><div class="form-title">Tax Setting</div><div class="notice success"><strong>Fixed tax rate is active:</strong> HB Commerce Solutions is now configured to charge a fixed <strong>10.000%</strong> sales tax rate across quotes, invoices, converted online orders, reports, PDFs, CSV exports, and admin calculations.</div><div class="summary-grid"><div class="totals-card"><div class="total-row grand"><span>Current Tax Rate</span><span>10.000%</span></div><div class="total-row"><span>Lookup / Override Logic</span><span>Disabled</span></div><div class="total-row"><span>Tax Source</span><span>Fixed company tax rate</span></div></div></div><p class="hint">ZIP/city/state lookup can still fill address fields, but it no longer changes tax. All taxable line items use the fixed 10% rate.</p></section></div></main>`;
  return htmlPage("Fixed Sales Tax | HB Commerce", layout(env, "Dashboard", body));
}

async function adminTaxPost(request, env) {
  const user = await requireAuth(request, env);
  if (!user) return redirect("/admin-app");
  return adminTaxPage(request, env, `<div class="notice success">Fixed 10% tax is already active. Tax overrides are disabled.</div>`);
}

async function getSetting(env, key, fallback = "") {
  const row = await env.DB.prepare("SELECT value FROM settings WHERE key=?").bind(key).first();
  return row ? String(row.value || "") : fallback;
}

async function setSetting(env, key, value) {
  await env.DB.prepare("INSERT OR REPLACE INTO settings (key,value) VALUES (?,?)").bind(key, String(value || "")).run();
}

function invoiceCostTotal(doc) {
  return (doc.items || []).reduce((sum, it) => {
    const qty = Math.max(0, parseInt(it.qty || 0, 10) || 0);
    const cost = Number(it.cost || 0);
    return sum + qty * cost;
  }, 0);
}

function reportInvoiceState(doc = {}) {
  const shipLegacy = doc.shipping_address && typeof doc.shipping_address === "object" ? doc.shipping_address : {};
  const billLegacy = doc.billing_address && typeof doc.billing_address === "object" ? doc.billing_address : {};
  const eufyOrder = doc.eufy_order && typeof doc.eufy_order === "object" ? doc.eufy_order : {};
  const eufyShip = eufyOrder.shipping && typeof eufyOrder.shipping === "object" ? eufyOrder.shipping : {};
  const eufyBill = eufyOrder.billing && typeof eufyOrder.billing === "object" ? eufyOrder.billing : {};
  return cleanStateCode(
    doc.shipping_state || shipLegacy.state || eufyShip.state ||
    doc.state || doc.billing_state || billLegacy.state || eufyBill.state || ""
  );
}

function reportStateLabel(state) {
  return cleanStateCode(state) || "N/A";
}

function sortReportRowsByState(rows = []) {
  return [...(rows || [])].sort((a, b) => {
    const as = cleanStateCode(a.state || "ZZ");
    const bs = cleanStateCode(b.state || "ZZ");
    return as.localeCompare(bs)
      || String(a.date || "").localeCompare(String(b.date || ""))
      || String(a.customer || "").localeCompare(String(b.customer || ""))
      || String(a.number || "").localeCompare(String(b.number || ""));
  });
}

async function paidInvoiceReportRows(env, year = "") {
  const docs = await env.DB.prepare("SELECT id,type,number,customer_name,status,paid,total,updated_at,data_json FROM documents WHERE type='Invoice' ORDER BY updated_at DESC LIMIT 2000").all();
  const rows = [];
  for (const row of (docs.results || [])) {
    let doc = {};
    try { doc = JSON.parse(row.data_json || "{}"); } catch {}
    if (!row.paid && !doc.paid) continue;
    if (row.status === "Canceled" || row.status === "Deleted" || doc.status === "Canceled" || doc.canceled_at || doc.deleted_at) continue;
    const date = String(doc.paid_at || row.updated_at || doc.doc_date || "").slice(0, 10);
    if (!date || (year && date.slice(0, 4) !== String(year))) continue;
    const c = calcTotals(doc);
    const cost = invoiceCostTotal(doc);
    const subtotal = Number(c.subtotal || 0);
    const taxable = Number(c.taxable || 0);
    const nonTaxable = Math.max(0, subtotal - taxable);
    const profit = subtotal - cost;
    const state = reportInvoiceState(doc);
    rows.push({
      id: row.id,
      state,
      date,
      month: date.slice(0, 7),
      number: row.number || doc.number || "",
      customer: row.customer_name || doc.customer_name || "",
      subtotal,
      taxable,
      nonTaxable,
      tax: Number(c.tax || 0),
      total: Number(c.total || row.total || 0),
      cost,
      profit,
      method: doc.payment_method || ""
    });
  }
  rows.sort((a,b) => String(a.date).localeCompare(String(b.date)) || String(a.number).localeCompare(String(b.number)));
  return rows;
}

function emptyReportTotals() {
  return { subtotal: 0, taxable: 0, nonTaxable: 0, tax: 0, total: 0, federal: 0, count: 0, cost: 0, profit: 0 };
}

function summarizeReportRows(rows, federalRate = 0) {
  const totals = emptyReportTotals();
  for (const r of rows) {
    totals.subtotal += Number(r.subtotal || 0);
    totals.taxable += Number(r.taxable || 0);
    totals.nonTaxable += Number(r.nonTaxable || 0);
    totals.tax += Number(r.tax || 0);
    totals.total += Number(r.total || 0);
    totals.cost += Number(r.cost || 0);
    totals.profit += Number(r.profit || 0);
    totals.count += 1;
  }
  totals.federal = Math.max(0, Number(totals.subtotal || 0)) * Number(federalRate || 0) / 100;
  return totals;
}

function monthlyBreakdownFromRows(rows, year) {
  const months = Array.from({ length: 12 }, (_, i) => {
    const m = String(i + 1).padStart(2, "0");
    return { month: `${year}-${m}`, label: new Date(Number(year), i, 1).toLocaleString("en-US", { month: "short" }), ...emptyReportTotals() };
  });
  for (const r of rows) {
    const idx = Number(String(r.month || "").slice(5, 7)) - 1;
    if (idx < 0 || idx > 11) continue;
    const m = months[idx];
    m.subtotal += Number(r.subtotal || 0);
    m.taxable += Number(r.taxable || 0);
    m.nonTaxable += Number(r.nonTaxable || 0);
    m.tax += Number(r.tax || 0);
    m.total += Number(r.total || 0);
    m.cost += Number(r.cost || 0);
    m.profit += Number(r.profit || 0);
    m.count += 1;
  }
  return months;
}

async function buildMonthlyReport(env, month, federalRate) {
  const year = String(month || new Date().toISOString().slice(0,7)).slice(0, 4);
  const yearRows = await paidInvoiceReportRows(env, year);
  const rows = yearRows.filter(r => r.month === month);
  return {
    mode: "month",
    month,
    year,
    periodLabel: month,
    federalRate: Number(federalRate || 0),
    rows,
    allYearRows: yearRows,
    monthly: monthlyBreakdownFromRows(yearRows, year),
    totals: summarizeReportRows(rows, federalRate)
  };
}

async function buildYearlyReport(env, year, federalRate) {
  year = String(year || new Date().getFullYear());
  const rows = await paidInvoiceReportRows(env, year);
  return {
    mode: "year",
    month: "",
    year,
    periodLabel: year,
    federalRate: Number(federalRate || 0),
    rows,
    allYearRows: rows,
    monthly: monthlyBreakdownFromRows(rows, year),
    totals: summarizeReportRows(rows, federalRate)
  };
}

function reportKind(report) {
  return report && report.reportKind === "pnl" ? "pnl" : "sales";
}

function isPnlReport(report) {
  return reportKind(report) === "pnl";
}

function reportTitle(report) {
  const kind = isPnlReport(report) ? "P&L" : "Sales";
  const period = report && report.mode === "year" ? "Yearly" : "Monthly";
  return `${period} ${kind} Report`;
}

function reportBasePath(reportOrKind) {
  const kind = typeof reportOrKind === "string" ? reportOrKind : reportKind(reportOrKind);
  return kind === "pnl" ? "/admin/pnl-reports" : "/admin/reports";
}

function reportFilePrefix(report) {
  return isPnlReport(report) ? "HB-Commerce-PL-Report" : "HB-Commerce-Sales-Report";
}

function reportSafeLabel(report) {
  return String(report.periodLabel || report.month || report.year || "Report").replace(/[^0-9A-Za-z_-]+/g, "-");
}

function reportSummaryRows(report) {
  const t = report.totals || emptyReportTotals();
  if (isPnlReport(report)) {
    const margin = Number(t.subtotal || 0) ? (Number(t.profit || 0) / Number(t.subtotal || 0) * 100) : 0;
    return [
      ["Paid Invoices", String(t.count || 0)],
      ["Sales Before Tax", money(t.subtotal)],
      ["Internal Cost", money(t.cost)],
      ["Gross Profit", money(t.profit)],
      ["Profit Margin", `${margin.toFixed(2)}%`],
      ["Sales Tax Collected", money(t.tax)],
      ["Total Collected", money(t.total)],
      [`Federal Estimate (${Number(report.federalRate || 0).toFixed(3)}%)`, money(t.federal)]
    ];
  }
  return [
    ["Paid Invoices", String(t.count || 0)],
    ["Sales Before Tax", money(t.subtotal)],
    ["Taxable Sales", money(t.taxable)],
    ["Non-Taxable Sales", money(t.nonTaxable)],
    ["Sales Tax Collected", money(t.tax)],
    ["Total Collected", money(t.total)]
  ];
}

function reportCsv(report) {
  const lines = [];
  const title = reportTitle(report);
  lines.push(["HB COMMERCE SOLUTIONS"].map(csvEscape).join(","));
  lines.push([title].map(csvEscape).join(","));
  lines.push(["Period", report.periodLabel || report.month || report.year || ""].map(csvEscape).join(","));
  lines.push(["Generated", formatDateTime(now())].map(csvEscape).join(","));
  lines.push([]);
  lines.push(["SUMMARY"].map(csvEscape).join(","));
  for (const [label, value] of reportSummaryRows(report)) lines.push([label, value].map(csvEscape).join(","));
  if (report.mode === "year" && report.showBreakdown) {
    lines.push([]);
    lines.push([`MONTHLY BREAKDOWN ${report.year || ""}`].map(csvEscape).join(","));
    if (isPnlReport(report)) {
      lines.push(["Month","Paid Invoices","Sales Before Tax","Internal Cost","Gross Profit","Sales Tax","Total Collected"].map(csvEscape).join(","));
      for (const m of (report.monthly || [])) lines.push([m.month, m.count, m.subtotal.toFixed(2), m.cost.toFixed(2), m.profit.toFixed(2), m.tax.toFixed(2), m.total.toFixed(2)].map(csvEscape).join(","));
    } else {
      lines.push(["Month","Paid Invoices","Sales Before Tax","Taxable Sales","Non-Taxable Sales","Sales Tax","Total Collected"].map(csvEscape).join(","));
      for (const m of (report.monthly || [])) lines.push([m.month, m.count, m.subtotal.toFixed(2), m.taxable.toFixed(2), m.nonTaxable.toFixed(2), m.tax.toFixed(2), m.total.toFixed(2)].map(csvEscape).join(","));
    }
  }
  lines.push([]);
  lines.push([isPnlReport(report) ? "P&L INVOICE DETAIL" : "PAID INVOICE SALES DETAIL"].map(csvEscape).join(","));
  if (isPnlReport(report)) {
    lines.push(["Date","Invoice #","Customer","Sales Before Tax","Internal Cost","Gross Profit","Sales Tax","Invoice Total","Payment Method"].map(csvEscape).join(","));
    for (const r of report.rows) lines.push([r.date, r.number, r.customer, r.subtotal.toFixed(2), r.cost.toFixed(2), r.profit.toFixed(2), r.tax.toFixed(2), r.total.toFixed(2), r.method].map(csvEscape).join(","));
    if (!report.rows.length) lines.push(["No paid invoices found for this period.","","","","","","","",""] .map(csvEscape).join(","));
  } else {
    lines.push(["State","Date","Invoice #","Customer","Sales Before Tax","Taxable Sales","Non-Taxable Sales","Sales Tax","Invoice Total","Payment Method"].map(csvEscape).join(","));
    for (const r of report.rows) lines.push([reportStateLabel(r.state), r.date, r.number, r.customer, r.subtotal.toFixed(2), r.taxable.toFixed(2), r.nonTaxable.toFixed(2), r.tax.toFixed(2), r.total.toFixed(2), r.method].map(csvEscape).join(","));
    if (!report.rows.length) lines.push(["No paid invoices found for this period.","","","","","","","","",""] .map(csvEscape).join(","));
  }
  lines.push([]);
  lines.push(["NOTES"].map(csvEscape).join(","));
  lines.push([(isPnlReport(report)
    ? "P&L report includes internal cost and gross profit for owner/internal financial review. Verify final filing amounts with your accountant."
    : "Sales report is sorted by destination state and is accountant-friendly, intentionally excluding internal cost and gross profit. Sales tax is based on tax collected on paid invoices."
  )].map(csvEscape).join(","));
  return lines.join("\r\n");
}

function csvEscape(v) {
  const s = String(v ?? "");
  return /[",\n]/.test(s) ? `"${s.replaceAll('"','""')}"` : s;
}

function excelStyleMoney(n) {
  return Number(n || 0).toFixed(2);
}

function reportExcelHtml(report) {
  const logo = `data:${LOGO_MIME};base64,${LOGO_B64}`;
  const reportLogoWidth = 150;
  const reportLogoHeight = Math.round(reportLogoWidth * HB_PDF_LOGO_ALPHA_HEIGHT / HB_PDF_LOGO_ALPHA_WIDTH);
  const title = reportTitle(report);
  const showBreakdown = report.mode === "year" && report.showBreakdown;
  const values = report.monthly || [];
  const summaryCells = reportSummaryRows(report).map(([label, value]) => `<td><div class="label">${escapeHtml(label)}</div><div class="value">${escapeHtml(value)}</div></td>`).join("");
  const monthlyBreakdown = showBreakdown ? (isPnlReport(report)
    ? `<h2>Monthly P&L Breakdown ${escapeHtml(report.year || "")}</h2><table class="data-table"><thead><tr><th>Month</th><th>Paid Invoices</th><th>Sales Before Tax</th><th>Internal Cost</th><th>Gross Profit</th><th>Sales Tax</th><th>Total Collected</th></tr></thead><tbody>${values.map(m => `<tr><td>${escapeHtml(m.month)}</td><td>${m.count}</td><td>${excelStyleMoney(m.subtotal)}</td><td>${excelStyleMoney(m.cost)}</td><td>${excelStyleMoney(m.profit)}</td><td>${excelStyleMoney(m.tax)}</td><td>${excelStyleMoney(m.total)}</td></tr>`).join("")}</tbody></table>`
    : `<h2>Monthly Sales Breakdown ${escapeHtml(report.year || "")}</h2><table class="data-table"><thead><tr><th>Month</th><th>Paid Invoices</th><th>Sales Before Tax</th><th>Taxable Sales</th><th>Non-Taxable Sales</th><th>Sales Tax</th><th>Total Collected</th></tr></thead><tbody>${values.map(m => `<tr><td>${escapeHtml(m.month)}</td><td>${m.count}</td><td>${excelStyleMoney(m.subtotal)}</td><td>${excelStyleMoney(m.taxable)}</td><td>${excelStyleMoney(m.nonTaxable)}</td><td>${excelStyleMoney(m.tax)}</td><td>${excelStyleMoney(m.total)}</td></tr>`).join("")}</tbody></table>`
  ) : "";
  const detailHead = isPnlReport(report)
    ? `<tr><th>Date</th><th>Invoice #</th><th>Customer</th><th>Sales Before Tax</th><th>Internal Cost</th><th>Gross Profit</th><th>Sales Tax</th><th>Invoice Total</th><th>Payment Method</th></tr>`
    : `<tr><th>State</th><th>Date</th><th>Invoice #</th><th>Customer</th><th>Sales Before Tax</th><th>Taxable Sales</th><th>Non-Taxable Sales</th><th>Sales Tax</th><th>Invoice Total</th><th>Payment Method</th></tr>`;
  const detailColspan = isPnlReport(report) ? 9 : 10;
  const detailRows = report.rows.map(r => isPnlReport(report)
    ? `<tr><td>${escapeHtml(r.date)}</td><td>${escapeHtml(r.number)}</td><td>${escapeHtml(r.customer)}</td><td>${excelStyleMoney(r.subtotal)}</td><td>${excelStyleMoney(r.cost)}</td><td>${excelStyleMoney(r.profit)}</td><td>${excelStyleMoney(r.tax)}</td><td>${excelStyleMoney(r.total)}</td><td>${escapeHtml(r.method)}</td></tr>`
    : `<tr><td>${escapeHtml(reportStateLabel(r.state))}</td><td>${escapeHtml(r.date)}</td><td>${escapeHtml(r.number)}</td><td>${escapeHtml(r.customer)}</td><td>${excelStyleMoney(r.subtotal)}</td><td>${excelStyleMoney(r.taxable)}</td><td>${excelStyleMoney(r.nonTaxable)}</td><td>${excelStyleMoney(r.tax)}</td><td>${excelStyleMoney(r.total)}</td><td>${escapeHtml(r.method)}</td></tr>`
  ).join("") || `<tr><td colspan="${detailColspan}">No paid invoices found for this period.</td></tr>`;
  return `<!doctype html>
<html>
<head>
<meta charset="utf-8">
<style>
  body{font-family:Arial,Helvetica,sans-serif;background:#06101f;color:#ffffff;margin:0;padding:24px;}
  .sheet{background:#07152a;border:2px solid #ff6a00;border-radius:18px;padding:20px;}
  .report-head{width:100%;border-collapse:collapse;margin:0 auto 18px auto;}
  .report-head td{text-align:center!important;border:0!important;padding:0!important;background:transparent!important;}
  .logo-center{text-align:center!important;margin:4px auto 10px auto;width:100%;}
  .logo-center img{width:150px;height:118px;max-width:150px;max-height:118px;object-fit:contain;display:block;margin:0 auto;}
  .title{text-align:center!important;font-size:28px;font-weight:900;color:#ffffff;letter-spacing:.02em;margin:2px auto 0 auto;width:100%;box-sizing:border-box;padding-right:14px;}
  .subtitle{text-align:center!important;font-size:13px;color:#dbe7f5;margin:8px 0 18px;width:100%;}
  .summary{width:100%;border-collapse:separate;border-spacing:10px;margin:10px 0 18px;}
  .summary td{background:#0b1f38;border:1px solid #ff8c21;border-radius:12px;padding:14px;color:#ffffff;min-width:130px;}
  .summary .label{font-size:11px;text-transform:uppercase;color:#cbd5e1;font-weight:800;}
  .summary .value{font-size:20px;font-weight:900;color:#ffffff;}
  h2{font-size:20px;color:#ffffff;margin:22px 0 10px;}
  .data-table{width:100%;border-collapse:collapse;margin-bottom:18px;background:#ffffff;color:#111827;}
  .data-table th{background:#06284d;color:#ffffff;border:1px solid #d9e2ef;padding:8px;font-weight:800;}
  .data-table td{border:1px solid #d9e2ef;padding:7px;color:#111827;}
  .data-table tr:nth-child(even) td{background:#f3f7fb;}
  .note{background:#0b1f38;border:1px solid #ff8c21;border-radius:12px;color:#dbe7f5;padding:12px;font-size:12px;margin-top:10px;}
</style>
</head>
<body>
<div class="sheet">
  <table class="report-head" width="100%">
    <tr><td colspan="${detailColspan}" align="center" style="text-align:center;"><div class="logo-center"><img src="${logo}" alt="HB Commerce Solutions" width="${reportLogoWidth}" height="${reportLogoHeight}" style="width:${reportLogoWidth}px;height:${reportLogoHeight}px;display:block;margin:0 auto;object-fit:contain;"></div></td></tr>
    <tr><td colspan="${detailColspan}" align="center"><div class="title">${escapeHtml(title)}</div></td></tr>
    <tr><td colspan="${detailColspan}" align="center"><div class="subtitle">Period: ${escapeHtml(report.periodLabel || report.month || report.year || "")} &nbsp; | &nbsp; Generated: ${escapeHtml(formatDateTime(now()))}</div></td></tr>
  </table>
  <table class="summary"><tr>${summaryCells}</tr></table>
  ${monthlyBreakdown}
  <h2>${isPnlReport(report) ? "P&L Invoice Detail" : "Paid Invoice Sales Detail"}</h2>
  <table class="data-table"><thead>${detailHead}</thead><tbody>${detailRows}</tbody></table>
  <div class="note">${isPnlReport(report) ? "P&L report includes internal cost and gross profit for owner/internal financial review." : "Sales report is sorted by destination state and intentionally excludes internal cost and gross profit."} Export intentionally contains no graph; the report logo appears at the top center.</div>
</div>
</body>
</html>`;
}

function buildReportPdfBytes(report) {
  const navy = "0.024 0.157 0.302", orange = "1 0.416 0", green = "0.075 0.541 0.239", gray = "0.85 0.89 0.94", ink = "0.12 0.16 0.22", muted = "0.38 0.45 0.55", white = "1 1 1";
  const pages = [];
  let ops = [], y = 700;
  const title = reportTitle(report);
  const pnl = isPnlReport(report);

  function pdfTextWidthApprox(raw, size) {
    const safe = pdfSanitize(String(raw || ""));
    let units = 0;
    for (const ch of safe) {
      if (ch === " ") units += 0.28;
      else if ("ilI1.,:'!|".includes(ch)) units += 0.26;
      else if ("MW@#%&".includes(ch)) units += 0.82;
      else if (/[A-Z]/.test(ch)) units += 0.68;
      else if (/[0-9$]/.test(ch)) units += 0.56;
      else if (/[a-z]/.test(ch)) units += 0.52;
      else units += 0.42;
    }
    return units * size;
  }
  function text(x, yy, s, size=9, font="F1", color=ink, align="left") {
    const raw = String(s ?? "");
    s = pdfEscape(raw);
    let tx = x;
    const w = pdfTextWidthApprox(raw, size);
    if (align === "right") tx = x - w;
    if (align === "center") tx = x - (w / 2);
    ops.push(`BT /${font} ${size} Tf ${color} rg 1 0 0 1 ${tx.toFixed(2)} ${yy.toFixed(2)} Tm (${s}) Tj ET`);
  }
  function rect(x, yy, w, h, fill, stroke="") { ops.push(`q ${fill ? fill + " rg" : ""} ${stroke ? stroke + " RG 0.6 w" : ""} ${x} ${yy} ${w} ${h} re ${fill && stroke ? "B" : fill ? "f" : "S"} Q`); }
  function line(x1,y1,x2,y2,color=orange,w=1){ops.push(`q ${color} RG ${w} w ${x1} ${y1} m ${x2} ${y2} l S Q`);}
  function image(name, x, yy, w, h) { ops.push(`q ${w.toFixed(2)} 0 0 ${h.toFixed(2)} ${x.toFixed(2)} ${yy.toFixed(2)} cm /${name} Do Q`); }
  function fit(s, max) { s = String(s || ""); return s.length > max ? s.slice(0, max - 1) + "..." : s; }
  function newPage() {
    if (ops.length) pages.push(ops.join("\n"));
    ops = [];
    rect(0, 0, 612, 792, white);
    rect(0, 782, 612, 10, orange);
    rect(420, 782, 192, 10, green);
    const reportLogoW = 150;
    const reportLogoH = reportLogoW * HB_PDF_LOGO_ALPHA_HEIGHT / HB_PDF_LOGO_ALPHA_WIDTH;
    image("Logo", (612 - reportLogoW) / 2, 660, reportLogoW, reportLogoH);
    text(306, 633, title.toUpperCase(), 18, "F2", navy, "center");
    text(306, 616, `Period: ${report.periodLabel || report.month || report.year || ""}   |   Generated: ${formatDateTime(now())}`, 8, "F1", muted, "center");
    line(46, 598, 566, 598, orange, 2);
    y = 578;
  }
  function check(h){ if (y - h < 54) newPage(); }
  function summaryBox(x, yy, label, value, color=navy) {
    rect(x, yy, 160, 46, "0.97 0.98 1", gray);
    rect(x, yy+41, 160, 5, color);
    text(x+10, yy+27, label, 7.0, "F2", muted);
    text(x+10, yy+10, value, 12, "F2", navy);
  }
  function drawSummary() {
    const rows = reportSummaryRows(report).slice(0, pnl ? 8 : 6);
    const xs = [46, 226, 406];
    let rowY = y - 46;
    for (let i = 0; i < rows.length; i++) {
      const [label, value] = rows[i];
      summaryBox(xs[i % 3], rowY, label, value, label.toLowerCase().includes("profit") ? green : (i % 2 ? navy : orange));
      if (i % 3 === 2) rowY -= 58;
    }
    y = rowY - (rows.length % 3 ? 58 : 0) + 12;
  }
  function drawMonthlyBreakdown() {
    if (!(report.mode === "year" && report.showBreakdown)) return;
    check(110);
    text(46, y, `${report.year || ""} Monthly ${pnl ? "P&L" : "Sales"} Breakdown`, 12, "F2", navy); y -= 18;
    const columns = pnl
      ? [{l:"Month",w:58},{l:"Inv",w:42},{l:"Sales",w:84,a:"right"},{l:"Cost",w:80,a:"right"},{l:"Profit",w:82,a:"right"},{l:"Tax",w:76,a:"right"},{l:"Total",w:98,a:"right"}]
      : [{l:"Month",w:58},{l:"Inv",w:42},{l:"Sales",w:84,a:"right"},{l:"Taxable",w:84,a:"right"},{l:"Non-Tax",w:84,a:"right"},{l:"Tax",w:76,a:"right"},{l:"Total",w:92,a:"right"}];
    drawTableHeader(columns);
    for (const m of (report.monthly || [])) {
      check(21);
      const vals = pnl ? [m.month, m.count, money(m.subtotal), money(m.cost), money(m.profit), money(m.tax), money(m.total)] : [m.month, m.count, money(m.subtotal), money(m.taxable), money(m.nonTaxable), money(m.tax), money(m.total)];
      drawTableRow(columns, vals);
    }
    y -= 14;
  }
  function drawTableHeader(columns) {
    rect(46, y-18, 520, 20, navy);
    let x = 46;
    for (const c of columns) {
      const tx = c.a === "right" ? x + c.w - 6 : x + 6;
      text(tx, y-11, c.l, 6.7, "F2", white, c.a || "left");
      x += c.w;
    }
    y -= 20;
  }
  function drawTableRow(columns, vals) {
    rect(46, y-20, 520, 20, white, gray);
    let x = 46;
    for (let i = 0; i < columns.length; i++) {
      const c = columns[i], v = String(vals[i] ?? "");
      const max = c.w < 50 ? 8 : c.w < 70 ? 12 : c.w < 90 ? 16 : 24;
      const tx = c.a === "right" ? x + c.w - 6 : x + 6;
      text(tx, y-13, fit(v, max), 6.5, "F1", ink, c.a || "left");
      x += c.w;
    }
    y -= 20;
  }
  newPage();
  drawSummary();
  drawMonthlyBreakdown();

  check(75);
  text(46, y, pnl ? "P&L Invoice Detail" : "Paid Invoice Sales Detail", 12, "F2", navy); y -= 18;
  const detailColumns = pnl
    ? [{l:"Date",w:50},{l:"Invoice",w:80},{l:"Customer",w:130},{l:"Sales",w:58,a:"right"},{l:"Cost",w:56,a:"right"},{l:"Profit",w:56,a:"right"},{l:"Tax",w:48,a:"right"},{l:"Total",w:42,a:"right"}]
    : [{l:"State",w:30},{l:"Date",w:48},{l:"Invoice",w:78},{l:"Customer",w:118},{l:"Sales",w:55,a:"right"},{l:"Taxable",w:55,a:"right"},{l:"Tax",w:45,a:"right"},{l:"Total",w:55,a:"right"},{l:"Pay",w:36}];
  drawTableHeader(detailColumns);
  if (!report.rows.length) {
    text(56, y-14, "No paid invoices found for this period.", 9, "F1", muted); y -= 24;
  }
  for (const r of report.rows) {
    check(23);
    const vals = pnl
      ? [r.date, r.number, r.customer, money(r.subtotal), money(r.cost), money(r.profit), money(r.tax), money(r.total)]
      : [reportStateLabel(r.state), r.date, r.number, r.customer, money(r.subtotal), money(r.taxable), money(r.tax), money(r.total), r.method || ""];
    drawTableRow(detailColumns, vals);
  }
  y -= 14;
  check(58);
  text(46, y, "Notes", 10, "F2", navy); y -= 14;
  const note = pnl ? "P&L report includes internal cost and gross profit for owner/internal financial review. Verify final accounting and filing amounts." : "Sales report is sorted by destination state and is accountant-friendly, intentionally excluding internal cost and gross profit. Sales tax is based on tax collected on paid invoices.";
  for (const l of wrapPdfText(note, 100).slice(0, 4)) { text(46, y, l, 8, "F1", muted); y -= 11; }

  pages.push(ops.join("\n"));
  const objects = [];
  function addObj(s){objects.push(s);return objects.length;}
  const font1=addObj("<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>");
  const font2=addObj("<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica-Bold >>");
  const logoRgbHex = pdfBase64ToHex(HB_PDF_LOGO_RGB_FLATE_B64);
  const logoAlphaHex = pdfBase64ToHex(HB_PDF_LOGO_ALPHA_FLATE_B64);
  const logoMaskObj = addObj(`<< /Type /XObject /Subtype /Image /Width ${HB_PDF_LOGO_ALPHA_WIDTH} /Height ${HB_PDF_LOGO_ALPHA_HEIGHT} /ColorSpace /DeviceGray /BitsPerComponent 8 /Filter [/ASCIIHexDecode /FlateDecode] /Length ${logoAlphaHex.length + 1} >>
stream
${logoAlphaHex}>
endstream`);
  const logoId = addObj(`<< /Type /XObject /Subtype /Image /Width ${HB_PDF_LOGO_ALPHA_WIDTH} /Height ${HB_PDF_LOGO_ALPHA_HEIGHT} /ColorSpace /DeviceRGB /BitsPerComponent 8 /SMask ${logoMaskObj} 0 R /Filter [/ASCIIHexDecode /FlateDecode] /Length ${logoRgbHex.length + 1} >>
stream
${logoRgbHex}>
endstream`);
  const contentIds=[], pageIds=[];
  for (const content of pages) {
    const b = new TextEncoder().encode(content);
    contentIds.push(addObj(`<< /Length ${b.length} >>\nstream\n${content}\nendstream`));
    pageIds.push(null);
  }
  const parent = "PAGES_PARENT";
  for (let i=0;i<pages.length;i++) pageIds[i]=addObj(`<< /Type /Page /Parent ${parent} 0 R /MediaBox [0 0 612 792] /Resources << /Font << /F1 ${font1} 0 R /F2 ${font2} 0 R >> /XObject << /Logo ${logoId} 0 R >> >> /Contents ${contentIds[i]} 0 R >>`);
  const pagesId = addObj(`<< /Type /Pages /Kids [${pageIds.map(id=>id+" 0 R").join(" ")}] /Count ${pageIds.length} >>`);
  const catalogId = addObj(`<< /Type /Catalog /Pages ${pagesId} 0 R >>`);
  for (let i=0;i<objects.length;i++) objects[i]=objects[i].replaceAll(parent, String(pagesId));
  let pdf="%PDF-1.4\n%\xE2\xE3\xCF\xD3\n"; const offsets=[0];
  for (let i=0;i<objects.length;i++){offsets.push(new TextEncoder().encode(pdf).length);pdf+=`${i+1} 0 obj\n${objects[i]}\nendobj\n`;}
  const xref=new TextEncoder().encode(pdf).length; pdf+=`xref\n0 ${objects.length+1}\n0000000000 65535 f \n`;
  for(let i=1;i<offsets.length;i++) pdf+=`${String(offsets[i]).padStart(10,"0")} 00000 n \n`;
  pdf+=`trailer\n<< /Size ${objects.length+1} /Root ${catalogId} 0 R >>\nstartxref\n${xref}\n%%EOF`;
  return new TextEncoder().encode(pdf);
}

function reportChartHtml(report, metric = "subtotal", label = "Sales") {
  const values = report.monthly || [];
  const max = Math.max(1, ...values.map(m => Math.abs(Number(m[metric] || 0))));
  return `<div class="report-chart"><div class="chart-head"><h3>${escapeHtml(label)} by Month — ${escapeHtml(report.year || "")}</h3><span>${escapeHtml(report.mode === "year" ? "Year View" : "Month View")}</span></div><div class="chart-bars">${values.map(m => {
    const v = Number(m[metric] || 0);
    const h = Math.max(8, Math.round(Math.abs(v) / max * 128));
    const active = report.mode === "month" && m.month === report.month ? "active" : "";
    return `<div class="chart-bar-wrap ${active}"><div class="chart-bar" style="height:${h}px"><em>${money(v)}</em></div><small>${escapeHtml(m.label)}</small></div>`;
  }).join("")}</div></div>`;
}

async function reportFromRequest(env, url, kind = "sales") {
  const currentMonth = new Date().toISOString().slice(0, 7);
  const currentYear = new Date().getFullYear();
  const mode = url.searchParams.get("mode") === "year" ? "year" : "month";
  const savedFederal = await getSetting(env, "federal_estimate_rate", "0");
  const federalRate = kind === "pnl" ? Number(url.searchParams.get("federal_rate") || savedFederal || 0) : 0;
  const year = String(url.searchParams.get("year") || currentYear).slice(0,4);
  const month = url.searchParams.get("month") || currentMonth;
  const showBreakdown = mode === "year" && url.searchParams.get("show_breakdown") === "1";
  const report = mode === "year" ? await buildYearlyReport(env, year, federalRate) : await buildMonthlyReport(env, month, federalRate);
  report.showBreakdown = showBreakdown;
  report.reportKind = kind === "pnl" ? "pnl" : "sales";
  if (report.reportKind === "sales") report.rows = sortReportRowsByState(report.rows);
  return report;
}

async function adminReportsPageBase(request, env, kind = "sales", message = "") {
  const user = await requireAuth(request, env);
  if (!user) return redirect("/admin/login");
  const url = new URL(request.url);
  const currentMonth = new Date().toISOString().slice(0, 7);
  const currentYear = new Date().getFullYear();
  const mode = url.searchParams.get("mode") === "year" ? "year" : "month";
  const month = url.searchParams.get("month") || currentMonth;
  const year = String(url.searchParams.get("year") || month.slice(0,4) || currentYear).slice(0, 4);
  const showBreakdown = mode === "year" && url.searchParams.get("show_breakdown") === "1";
  const savedEmail = await getSetting(env, kind === "pnl" ? "pnl_report_email" : "accountant_email", "");
  const savedFederal = await getSetting(env, "federal_estimate_rate", "0");
  const federalRate = kind === "pnl" ? Number(url.searchParams.get("federal_rate") || savedFederal || 0) : 0;
  const report = await reportFromRequest(env, url, kind);
  const base = reportBasePath(kind);
  const breakdownQuery = showBreakdown ? "&show_breakdown=1" : "";
  const query = `mode=${encodeURIComponent(mode)}&month=${encodeURIComponent(month)}&year=${encodeURIComponent(year)}&federal_rate=${encodeURIComponent(federalRate)}${breakdownQuery}`;
  const title = reportTitle(report);
  const switchButtons = `<a class="btn ${kind === "sales" ? "orange" : ""}" href="/admin/reports?mode=${encodeURIComponent(mode)}&month=${encodeURIComponent(month)}&year=${encodeURIComponent(year)}">Sales Reports</a><a class="btn ${kind === "pnl" ? "orange" : ""}" href="/admin/pnl-reports?mode=${encodeURIComponent(mode)}&month=${encodeURIComponent(month)}&year=${encodeURIComponent(year)}&federal_rate=${encodeURIComponent(federalRate)}">P&amp;L Reports</a>`;
  const summaryCards = reportSummaryRows(report).slice(0, kind === "pnl" ? 6 : 6).map(([label, value]) => `<div class="report-card ${label.toLowerCase().includes("profit") ? "profit" : ""}"><span>${escapeHtml(label)}</span><strong>${escapeHtml(value)}</strong></div>`).join("");
  const rowHtml = report.rows.map(r => kind === "pnl"
    ? `<tr><td>${escapeHtml(r.date)}</td><td>${escapeHtml(r.number)}</td><td>${escapeHtml(r.customer)}</td><td>${money(r.subtotal)}</td><td>${money(r.cost)}</td><td><strong>${money(r.profit)}</strong></td><td>${money(r.tax)}</td><td>${money(r.total)}</td><td>${escapeHtml(r.method)}</td></tr>`
    : `<tr><td><strong>${escapeHtml(reportStateLabel(r.state))}</strong></td><td>${escapeHtml(r.date)}</td><td>${escapeHtml(r.number)}</td><td>${escapeHtml(r.customer)}</td><td>${money(r.subtotal)}</td><td>${money(r.taxable)}</td><td>${money(r.nonTaxable)}</td><td>${money(r.tax)}</td><td>${money(r.total)}</td><td>${escapeHtml(r.method)}</td></tr>`
  ).join("") || `<tr><td colspan="${kind === "pnl" ? 9 : 10}">No paid invoices found for this period.</td></tr>`;
  const monthlyRows = (report.monthly || []).map(m => kind === "pnl"
    ? `<tr><td>${escapeHtml(m.month)}</td><td>${m.count}</td><td>${money(m.subtotal)}</td><td>${money(m.cost)}</td><td><strong>${money(m.profit)}</strong></td><td>${money(m.tax)}</td><td>${money(m.total)}</td></tr>`
    : `<tr><td>${escapeHtml(m.month)}</td><td>${m.count}</td><td>${money(m.subtotal)}</td><td>${money(m.taxable)}</td><td>${money(m.nonTaxable)}</td><td>${money(m.tax)}</td><td>${money(m.total)}</td></tr>`
  ).join("");
  const monthlyBreakdownHtml = (mode === "year" && showBreakdown)
    ? (kind === "pnl"
      ? `<div class="table-panel"><div class="section-title"><h2>${escapeHtml(report.year)} Monthly P&amp;L Breakdown</h2><p>Sales, internal cost, gross profit, tax collected, and total collected by month.</p></div><div class="table-wrap"><table><thead><tr><th>Month</th><th>Invoices</th><th>Sales Before Tax</th><th>Internal Cost</th><th>Gross Profit</th><th>Tax Collected</th><th>Total Collected</th></tr></thead><tbody>${monthlyRows}</tbody></table></div></div>`
      : `<div class="table-panel"><div class="section-title"><h2>${escapeHtml(report.year)} Monthly Sales Breakdown</h2><p>Total taxable sales, non-taxable sales, tax collected, and paid invoice totals by month.</p></div><div class="table-wrap"><table><thead><tr><th>Month</th><th>Invoices</th><th>Sales Before Tax</th><th>Taxable Sales</th><th>Non-Taxable Sales</th><th>Tax Collected</th><th>Total Collected</th></tr></thead><tbody>${monthlyRows}</tbody></table></div></div>`)
    : "";
  const federalField = kind === "pnl" ? `<div class="field report-federal-field"><label>Federal Estimate Rate (%)</label><input type="number" step="0.001" name="federal_rate" value="${escapeHtml(federalRate)}"></div>` : "";
  const charts = kind === "pnl" ? `<div class="report-chart-grid report-chart-grid-two">${reportChartHtml(report, "subtotal", "Sales")}${reportChartHtml(report, "profit", "Gross Profit")}</div>` : `<div class="report-chart-grid report-chart-grid-full">${reportChartHtml(report, "subtotal", "Sales")}</div>`;
  const detailHead = kind === "pnl"
    ? `<tr><th>Date</th><th>Invoice</th><th>Customer</th><th>Sales Before Tax</th><th>Internal Cost</th><th>Gross Profit</th><th>Tax</th><th>Total</th><th>Payment</th></tr>`
    : `<tr><th>State</th><th>Date</th><th>Invoice</th><th>Customer</th><th>Sales Before Tax</th><th>Taxable</th><th>Non-Taxable</th><th>Tax</th><th>Total</th><th>Payment</th></tr>`;
  const note = kind === "pnl"
    ? `P&amp;L Reports include internal cost and gross profit for owner/internal financial review.`
    : `Sales Reports are based on <strong>paid invoices only</strong>, sorted by destination state, and intentionally exclude internal cost and gross profit so they can be shared with your accountant.`;
  const emailLabel = kind === "pnl" ? "Email P&L Report" : "Email Sales Report to Accountant";
  const body = `<main class="section admin-dashboard reports-dashboard"><div class="container">
    <div class="section-title"><h2>${escapeHtml(title)}</h2><div class="btn-row">${switchButtons}<a class="btn" href="/admin/dashboard">Back to Dashboard</a></div></div>
    ${message}
    <div class="notice">${note} Sales tax collected uses the fixed 10% tax configuration. PDF and Excel exports include the HB Commerce logo at the top center and do not include graph images.</div>
    <form class="form-section reports-filter-form" method="get" action="${base}">
      <div class="grid-4">
        <div class="field"><label>Report Type</label><select name="mode" id="reportMode" onchange="toggleReportFields()"><option value="month" ${mode==="month"?"selected":""}>Monthly Report</option><option value="year" ${mode==="year"?"selected":""}>Yearly Report</option></select></div>
        <div class="field report-month-field"><label>Month</label><input type="month" name="month" value="${escapeHtml(month)}"></div>
        <div class="field report-year-field"><label>Year</label><input type="number" min="2020" max="2100" name="year" value="${escapeHtml(year)}"></div>
        ${federalField}
        <div class="field report-breakdown-field"><label>Yearly Table Option</label><label class="hb-report-check"><input type="checkbox" name="show_breakdown" value="1" ${showBreakdown ? "checked" : ""}> Show Monthly Breakdown Table</label></div>
      </div>
      <div class="btn-row"><button class="primary">View Report</button><a class="btn orange" href="${base}.xls?${query}">Export Excel</a><a class="btn" href="${base}.csv?${query}">Raw CSV</a><a class="btn primary hb-report-pdf-download" href="${base}.pdf?${query}" download="${reportFilePrefix(report)}-${reportSafeLabel(report)}.pdf" data-download-name="${reportFilePrefix(report)}-${reportSafeLabel(report)}.pdf">Export PDF</a></div>
    </form>

    <div class="report-summary-cards">${summaryCards}</div>
    ${charts}
    ${monthlyBreakdownHtml}

    <div class="table-panel"><div class="section-title"><h2>${escapeHtml(report.periodLabel)} ${kind === "pnl" ? "P&L" : "Sales"} Detail</h2><p>${kind === "pnl" ? "Internal cost and gross profit are shown per paid invoice." : "Paid invoices are sorted by destination state, then date, customer, and invoice number. Internal cost and gross profit are not shown in Sales Reports."}</p></div><div class="table-wrap"><table><thead>${detailHead}</thead><tbody>${rowHtml}</tbody></table></div></div>

    <form class="form-section" method="post" action="${base}/email"><div class="form-title">${escapeHtml(emailLabel)}</div><input type="hidden" name="mode" value="${escapeHtml(mode)}"><input type="hidden" name="month" value="${escapeHtml(month)}"><input type="hidden" name="year" value="${escapeHtml(year)}"><input type="hidden" name="federal_rate" value="${escapeHtml(federalRate)}"><input type="hidden" name="show_breakdown" value="${showBreakdown ? "1" : "0"}"><div class="grid-2"><div class="field"><label>${kind === "pnl" ? "Recipient Email" : "Accountant Email"}</label><input type="email" name="accountant_email" value="${escapeHtml(savedEmail)}" required></div><div class="field"><label>&nbsp;</label><button class="green">Save Email and Send Report</button></div></div></form>
    <script>
      function toggleReportFields(){
        const mode=document.getElementById('reportMode').value;
        document.querySelectorAll('.report-month-field').forEach(el=>el.style.display=mode==='year'?'none':'grid');
        document.querySelectorAll('.report-year-field,.report-breakdown-field').forEach(el=>el.style.display=mode==='year'?'grid':'none');
      }
      toggleReportFields();
      document.querySelectorAll('.hb-report-pdf-download').forEach(function(link){
        link.addEventListener('click', async function(ev){
          ev.preventDefault();
          const originalText = link.textContent;
          link.textContent = 'Preparing PDF...';
          link.setAttribute('aria-busy','true');
          try {
            const res = await fetch(link.href, { credentials: 'same-origin', cache: 'no-store' });
            if (!res.ok) throw new Error('PDF download failed');
            const blob = await res.blob();
            const url = URL.createObjectURL(blob);
            const a = document.createElement('a');
            a.href = url;
            a.download = link.dataset.downloadName || link.getAttribute('download') || 'HB-Commerce-Report.pdf';
            document.body.appendChild(a);
            a.click();
            setTimeout(function(){ URL.revokeObjectURL(url); a.remove(); }, 1500);
          } catch (err) {
            window.location.href = link.href;
          } finally {
            link.textContent = originalText;
            link.removeAttribute('aria-busy');
          }
        });
      });
    </script>
  </div></main>`;
  return htmlPage(`${title} | HB Commerce Solutions`, layout(env, "Dashboard", body));
}

async function adminReportsPage(request, env, message = "") {
  return adminReportsPageBase(request, env, "sales", message);
}

async function adminPnlReportsPage(request, env, message = "") {
  return adminReportsPageBase(request, env, "pnl", message);
}

async function adminReportsCsv(request, env) {
  const user = await requireAuth(request, env);
  if (!user) return redirect("/admin/login");
  const report = await reportFromRequest(env, new URL(request.url), "sales");
  const label = reportSafeLabel(report);
  return new Response(reportCsv(report), { headers: { "content-type": "text/csv; charset=utf-8", "content-disposition": `attachment; filename="${reportFilePrefix(report)}-${label}.csv"` } });
}

