async function adminCloneDocument(request, env) {
  const user = await requireAuth(request, env);
  if (!user) return redirect("/admin/login");
  const id = new URL(request.url).searchParams.get("id") || "";
  const source = id ? await getDoc(env, id) : null;
  if (!source || !["Quote","Invoice"].includes(source.type)) return redirect("/admin/dashboard");
  const doc = { ...source };
  doc.id = "";
  doc.token = "";
  doc.created_at = "";
  doc.updated_at = "";
  doc.number = nextDocNumber(source.type);
  doc.doc_date = today();
  doc.valid_until = source.type === "Invoice" ? plusDays(14) : plusDays(30);
  doc.status = source.type === "Invoice" ? "Open" : "Draft";
  doc.paid = 0;
  doc.paid_at = "";
  doc.payment_method = "";
  doc.check_number = "";
  doc.check_image_name = "";
  doc.check_image_type = "";
  doc.check_image_data = "";
  doc.customer_name = "";
  doc.billing_street = "";
  doc.billing_city = "";
  doc.billing_state = "IL";
  doc.billing_zip = "";
  doc.shipping_same_as_billing = 0;
  doc.shipping_street = "";
  doc.shipping_city = "";
  doc.shipping_state = "IL";
  doc.shipping_zip = "";
  doc.street = "";
  doc.city = "";
  doc.state = "IL";
  doc.zip = "";
  doc.shipping_cost = 0;
  doc.shipping_weight_lbs = "";
  doc.shipping_carrier = "manual";
  doc.shipping_service = "";
  doc.shipping_rate_label = "";
  doc.shipping_rate_source = "";
  doc.email = "";
  doc.phone = "";
  doc.approved_by = "";
  doc.approved_at = "";
  doc.approved_signature = "";
  doc.declined_by = "";
  doc.declined_at = "";
  doc.converted_to_invoice_id = "";
  doc.converted_to_invoice_number = "";
  return adminDocumentPage(request, env, `<div class="notice success">Cloned ${escapeHtml(source.type)} ${escapeHtml(source.number || "")}. A new ${escapeHtml(source.type.toLowerCase())} number was generated. Enter the new customer information before saving.</div>`, doc);
}

function posSupportMonthlyFee(registers) {
  const n = Math.max(1, parseInt(registers || 1, 10) || 1);
  if (n === 1) return 40;
  if (n === 2) return 55;
  return 55 + (n - 2) * 15;
}

async function posSupportCustomers(env) {
  try {
    const raw = await getSetting(env, "pos_support_customers_json", "");
    const arr = raw ? JSON.parse(raw) : [];
    return Array.isArray(arr) ? arr : [];
  } catch { return []; }
}

async function savePosSupportCustomers(env, rows) {
  await setSetting(env, "pos_support_customers_json", JSON.stringify(Array.isArray(rows) ? rows : []));
}

