function absoluteReviewUrl(env, doc) {
  const base = (env.PUBLIC_BASE_URL || env.WEBSITE_URL || "https://www.hbcommercesolution.com").replace(/\/$/,"");
  return `${base}/review/${encodeURIComponent(doc.id)}/${encodeURIComponent(doc.token)}`;
}

function dateOnlyMs(s) {
  if (!s) return NaN;
  const d = new Date(String(s).slice(0,10) + "T00:00:00Z");
  return d.getTime();
}

function dayDiff(fromDate, toDate) {
  const a = dateOnlyMs(fromDate), b = dateOnlyMs(toDate);
  if (!Number.isFinite(a) || !Number.isFinite(b)) return NaN;
  return Math.round((b - a) / 86400000);
}

function reminderLog(doc) {
  const r = doc.reminder_log && typeof doc.reminder_log === "object" ? doc.reminder_log : {};
  doc.reminder_log = r;
  return r;
}


async function reminderEmailLogs(env) {
  try {
    const raw = await getSetting(env, "reminder_email_log_json", "[]");
    const arr = raw ? JSON.parse(raw) : [];
    return Array.isArray(arr) ? arr : [];
  } catch { return []; }
}

async function addReminderEmailLog(env, entry) {
  const logs = await reminderEmailLogs(env);
  logs.unshift({
    id: crypto.randomUUID(),
    sent_at: now(),
    kind: String(entry.kind || ""),
    doc_type: String(entry.doc_type || ""),
    doc_id: String(entry.doc_id || ""),
    number: String(entry.number || ""),
    customer_name: String(entry.customer_name || ""),
    email: String(entry.email || ""),
    subject: String(entry.subject || ""),
    amount: Number(entry.amount || 0),
    days: entry.days === undefined ? "" : String(entry.days),
    status: String(entry.status || "Sent")
  });
  await setSetting(env, "reminder_email_log_json", JSON.stringify(logs.slice(0, 300)));
}

function reminderKindLabel(kind) {
  return {
    quote_due: "Quote Expiry Reminder",
    quote_expired: "Quote Expired",
    invoice_due: "Invoice Due Reminder",
    invoice_overdue: "Invoice Overdue",
    payment_link: "Card Payment Link"
  }[kind] || kind || "Reminder";
}

async function sendReminderEmail(env, doc, kind, days = 0) {
  if (!env.RESEND_API_KEY || !doc.email) return false;
  const totals = calcTotals(doc);
  const link = absoluteReviewUrl(env, doc);
  let subject = "", html = "";
  if (kind === "quote_due") {
    const when = days === 0 ? "today" : `in ${days} day${days === 1 ? "" : "s"}`;
    subject = `Reminder: Quote ${doc.number || ""} expires ${when}`;
    html = `<p>Hello ${escapeHtml(doc.customer_name || "Customer")},</p><p>This is a reminder that your HB Commerce Solutions quote <strong>${escapeHtml(doc.number || "")}</strong> expires ${escapeHtml(when)}.</p><p><strong>Quote Total:</strong> ${money(totals.total)}</p><p><a href="${link}#approve">Approve Quote</a> &nbsp; | &nbsp; <a href="${link}?action=decline#decline">Decline Quote</a></p><p>Thank you,<br>HB Commerce Solutions</p>`;
  } else if (kind === "quote_expired") {
    subject = `Quote ${doc.number || ""} has expired`;
    html = `<p>Hello ${escapeHtml(doc.customer_name || "Customer")},</p><p>Your HB Commerce Solutions quote <strong>${escapeHtml(doc.number || "")}</strong> has expired and is no longer valid.</p><p>Please contact us if you would like an updated quote.</p><p>Thank you,<br>HB Commerce Solutions</p>`;
  } else if (kind === "invoice_due") {
    const when = days === 0 ? "today" : `in ${days} day${days === 1 ? "" : "s"}`;
    subject = `Payment reminder: Invoice ${doc.number || ""} is due ${when}`;
    const pay = doc.payment_link ? `<p><a href="${escapeHtml(doc.payment_link)}">Pay securely online by card</a></p>` : "";
    html = `<p>Hello ${escapeHtml(doc.customer_name || "Customer")},</p><p>This is a friendly reminder that invoice <strong>${escapeHtml(doc.number || "")}</strong> is due ${escapeHtml(when)}.</p><p><strong>Amount Due:</strong> ${money(totals.total)}</p>${pay}<p>You can also view your invoice here: <a href="${link}">${link}</a></p><p>Thank you,<br>HB Commerce Solutions</p>`;
  } else if (kind === "invoice_overdue") {
    subject = `Past due invoice ${doc.number || ""} - ${days} day${days === 1 ? "" : "s"} overdue`;
    const pay = doc.payment_link ? `<p><a href="${escapeHtml(doc.payment_link)}">Pay securely online by card</a></p>` : "";
    html = `<p>Hello ${escapeHtml(doc.customer_name || "Customer")},</p><p>Invoice <strong>${escapeHtml(doc.number || "")}</strong> is past due by <strong>${days} day${days === 1 ? "" : "s"}</strong>.</p><p><strong>Amount Due:</strong> ${money(totals.total)}</p>${pay}<p>Please make payment as soon as possible or contact us if you have any questions.</p><p>Invoice link: <a href="${link}">${link}</a></p><p>Thank you,<br>HB Commerce Solutions</p>`;
  }
  html = `<div style="margin:0;padding:0;background:#eef4fb;font-family:Arial,Helvetica,sans-serif;color:#10233d"><div style="max-width:720px;margin:0 auto;padding:22px"><div style="background:#ffffff;border:1px solid #d9e2ef;border-radius:24px;overflow:hidden"><div style="background:#06101f;color:#ffffff;padding:24px 28px;border-bottom:6px solid #ff6a00"><div style="font-size:12px;letter-spacing:.16em;text-transform:uppercase;color:#9df0b3;font-weight:900">HB Commerce Solutions</div><h1 style="margin:8px 0 0;color:#ffffff;font-size:26px;line-height:1.15">${escapeHtml(subject)}</h1></div><div style="padding:24px 28px;color:#10233d;font-size:15px;line-height:1.6">${html}<div style="margin-top:18px;padding:14px;border-radius:16px;background:#06101f;color:#ffffff;border-left:6px solid #ff6a00"><strong style="color:#ffffff">Online document:</strong> <span style="color:#eaf2ff">Use the secure link above to open the latest responsive copy.</span></div></div></div></div></div>`;
  const attachments = documentEmailAttachments(doc, env);
  const ok = await sendEmail(env, { to: doc.email, subject, html, attachments });
  if (ok) await addReminderEmailLog(env, { kind, doc_type: doc.type, doc_id: doc.id, number: doc.number, customer_name: doc.customer_name, email: doc.email, subject, amount: totals.total, days });
  return ok;
}

async function runScheduledAdminReminders(env) {
  const todayIso = today();
  const res = await env.DB.prepare("SELECT id,type,status,paid,email,data_json FROM documents WHERE type IN ('Quote','Invoice') ORDER BY updated_at DESC LIMIT 1000").all();
  let sent = 0, checked = 0;
  for (const row of (res.results || [])) {
    let doc = {};
    try { doc = JSON.parse(row.data_json || "{}"); } catch { continue; }
    doc.status = row.status || doc.status;
    doc.paid = row.paid || doc.paid;
    if (!doc.email || doc.canceled_at || doc.deleted_at || ["Canceled","Deleted","Declined"].includes(doc.status)) continue;
    checked++;
    const log = reminderLog(doc);
    if (doc.type === "Quote") {
      if (["Approved","Converted","Expired"].includes(doc.status)) continue;
      const diff = dayDiff(todayIso, doc.valid_until);
      if (!Number.isFinite(diff)) continue;
      if (diff >= 0 && diff <= 3) {
        const key = `quote_due_${todayIso}`;
        if (!log[key] && await sendReminderEmail(env, doc, "quote_due", diff)) { log[key] = now(); sent++; await saveDoc(env, doc); }
      } else if (diff < 0 && !doc.quote_expired_email_sent_at) {
        if (await sendReminderEmail(env, doc, "quote_expired", -diff)) { doc.quote_expired_email_sent_at = now(); doc.status = "Expired"; sent++; await saveDoc(env, doc); }
      }
    } else if (doc.type === "Invoice") {
      if (doc.paid || ["Paid","Canceled","Deleted"].includes(doc.status)) continue;
      const diff = dayDiff(todayIso, doc.valid_until);
      if (!Number.isFinite(diff)) continue;
      if (diff >= 0 && diff <= 2) {
        const key = `invoice_due_${todayIso}`;
        if (!log[key] && await sendReminderEmail(env, doc, "invoice_due", diff)) { log[key] = now(); sent++; await saveDoc(env, doc); }
      } else if (diff < 0) {
        const key = `invoice_overdue_${todayIso}`;
        if (!log[key] && await sendReminderEmail(env, doc, "invoice_overdue", -diff)) { log[key] = now(); sent++; await saveDoc(env, doc); }
      }
    }
  }
  return { checked, sent };
}

async function adminRunReminders(request, env) {
  const user = await requireAuth(request, env);
  if (!user) return redirect("/admin/login");
  const result = await runScheduledAdminReminders(env);
  const body = `<main class="section admin-dashboard"><div class="container"><div class="form-section"><div class="form-title">Reminder Emails Run</div><div class="notice success">Checked ${result.checked} record(s). Sent ${result.sent} reminder email(s).</div><div class="btn-row"><a class="btn orange" href="/admin/dashboard?app=1">Dashboard</a><a class="btn" href="/admin/dashboard?view=invoices">Open Invoices</a></div></div></div></main>`;
  return htmlPage("Reminder Emails Run | HB Commerce", layout(env, "Dashboard", body));
}



function absoluteInvoicePayUrl(env, doc) {
  const base = (env.PUBLIC_BASE_URL || env.WEBSITE_URL || "https://www.hbcommercesolution.com").replace(/\/$/,"");
  return `${base}/pay/invoice/${encodeURIComponent(doc.id)}/${encodeURIComponent(doc.token)}`;
}

function authNetMode(env) {
  const r = String(env.AUTHORIZE_NET_ENV || "").trim().toLowerCase();
  return ["sandbox","test","testing","apitest"].includes(r) ? "sandbox" : "production";
}

function authNetConfig(env) {
  const mode = authNetMode(env);
  const pub = String(env.AUTHORIZE_NET_PUBLIC_CLIENT_KEY || "").trim();
  return {
    login: String(env.AUTHORIZE_NET_API_LOGIN_ID || "").trim(),
    key: String(env.AUTHORIZE_NET_TRANSACTION_KEY || "").trim(),
    publicKey: pub,
    api: mode === "sandbox" ? "https://apitest.authorize.net/xml/v1/request.api" : "https://api.authorize.net/xml/v1/request.api",
    acceptJs: mode === "sandbox" ? "https://jstest.authorize.net/v3/AcceptUI.js" : "https://js.authorize.net/v3/AcceptUI.js",
    mode
  };
}

function authNetReady(env) {
  const c = authNetConfig(env);
  return !!(c.login && c.key && c.publicKey);
}

function firstLastName(full) {
  const parts = String(full || "").trim().split(/\s+/).filter(Boolean);
  if (!parts.length) return { firstName: "", lastName: "" };
  if (parts.length === 1) return { firstName: parts[0], lastName: "" };
  return { firstName: parts[0], lastName: parts.slice(1).join(" ") };
}

async function authNetChargeOpaque(request, env, doc, descriptor, value) {
  const cfg = authNetConfig(env);
  if (!cfg.login || !cfg.key) throw new Error("Authorize.Net API credentials are not configured.");
  if (!descriptor || !value) throw new Error("Authorize.Net payment token was not received.");
  const totals = calcTotals(doc);
  const amount = Number(doc.payment_amount_override || doc.customer_balance_total || totals.total || 0).toFixed(2);
  const n = firstLastName(doc.customer_name);
  const payload = { createTransactionRequest: { merchantAuthentication: { name: cfg.login, transactionKey: cfg.key }, transactionRequest: {
    transactionType: "authCaptureTransaction",
    amount,
    payment: { opaqueData: { dataDescriptor: descriptor, dataValue: value } },
    order: { invoiceNumber: String(doc.number || "").slice(0, 20), description: `HB Commerce ${doc.type === 'OnlineOrder' ? 'order' : 'invoice'} ${doc.number || ""}`.slice(0, 255) },
    customer: { email: doc.email || "" },
    billTo: { firstName: n.firstName, lastName: n.lastName, company: doc.customer_name || "", address: docBillingAddress(doc).street || "", city: docBillingAddress(doc).city || "", state: docBillingAddress(doc).state || "", zip: docBillingAddress(doc).zip || "", country: "US" }
  } } };
  const res = await fetch(cfg.api, { method:"POST", headers:{ "content-type":"application/json", "accept":"application/json" }, body: JSON.stringify(payload) });
  const raw = (await res.text()).replace(/^\uFEFF/, "");
  let data = {};
  try { data = JSON.parse(raw); } catch { throw new Error("Authorize.Net returned a non-JSON response."); }
  const tr = data?.transactionResponse || {};
  if (data?.messages?.resultCode !== "Ok" || tr.responseCode !== "1") {
    const e = (tr.errors && tr.errors[0]) || (data?.messages?.message && data.messages.message[0]) || {};
    throw new Error(`Authorize.Net payment failed: ${e.errorCode || e.code || ""} ${e.errorText || e.text || "Transaction was not approved."}`.trim());
  }
  return { transId: tr.transId || "", authCode: tr.authCode || "", amount };
}

