  if (doc.paid) return htmlPage("Payment Complete", layout(env, "Payment", `<section class="section"><div class="container"><div class="form-section hb-pay-card"><div class="hb-pay-logo"><img src="${HB_DOC_TEMPLATE_LOGO_SRC}" alt="HB Commerce Solutions"></div><div class="form-title">Invoice Already Paid</div><div class="notice success">Invoice ${escapeHtml(doc.number || "")} is already marked paid. Thank you.</div><a class="btn green" href="${escapeHtml(absoluteReviewUrl(env, doc))}">View Paid Invoice</a></div></div></section>`));
